'use client';

import { Children, isValidElement, type ReactNode } from 'react';
import { cn } from '../../utils/cn';
import { useWizardContext } from './WizardContext';
import type { WizardContentProps, WizardPanelProps } from './types';

/**
 * Container for wizard step panels
 *
 * Automatically renders only the panel matching the current step
 *
 * @example
 * ```tsx
 * <Wizard.Content>
 *   <Wizard.Panel name="step1">Step 1 content</Wizard.Panel>
 *   <Wizard.Panel name="step2">Step 2 content</Wizard.Panel>
 * </Wizard.Content>
 * ```
 */
export function WizardContent({ children, className }: WizardContentProps) {
  const { currentStepConfig } = useWizardContext();

  // Find the panel that matches the current step
  let activePanel: ReactNode = null;

  Children.forEach(children, (child) => {
    if (!isValidElement(child)) return;

    // Check if this is a WizardPanel with matching name
    const panelProps = child.props as WizardPanelProps;
    if (panelProps.name === currentStepConfig?.name || panelProps.name === currentStepConfig?.id) {
      activePanel = child;
    }
  });

  return (
    <div
      className={cn('flex-1', className)}
      role="tabpanel"
      aria-label={currentStepConfig?.label || currentStepConfig?.name}
    >
      {activePanel}
    </div>
  );
}
