import * as React from 'react'
import { cn } from '../../utils/cn'
import type { DataTableTabsProps } from './types'

// ============================================================================
// TABS COMPONENT - Tabs de filtro rápido acima da tabela
// ============================================================================
//
// Uso:
// <DataTable data={filteredData} columns={columns}>
//   <DataTable.Tabs
//     tabs={[
//       { value: 'all', label: 'Todas', count: 85 },
//       { value: 'active', label: 'Ativas', count: 24 },
//       { value: 'inactive', label: 'Inativas', count: 12 },
//     ]}
//     value={activeTab}
//     onValueChange={setActiveTab}
//   />
//   <DataTable.Toolbar>...</DataTable.Toolbar>
//   <DataTable.Content />
// </DataTable>
//
// Nota: O DataTable.Tabs NÃO filtra os dados automaticamente.
// Você deve filtrar os dados externamente e passar para o DataTable.
// Isso permite flexibilidade para server-side filtering.
//
// ============================================================================

export function DataTableTabs({
  tabs,
  value,
  defaultValue,
  onValueChange,
  className,
}: DataTableTabsProps) {
  // Estado interno para modo uncontrolled
  const [internalValue, setInternalValue] = React.useState(defaultValue ?? tabs[0]?.value)

  // Usa valor controlado se fornecido, senão usa interno
  const activeValue = value ?? internalValue

  const handleTabClick = (tabValue: string) => {
    if (value === undefined) {
      // Modo uncontrolled
      setInternalValue(tabValue)
    }
    onValueChange?.(tabValue)
  }

  return (
    <div
      className={cn('flex items-center gap-1', className)}
      role="tablist"
      aria-label="Filtros"
    >
      {tabs.map((tab) => {
        const isActive = activeValue === tab.value

        return (
          <button
            key={tab.value}
            role="tab"
            aria-selected={isActive}
            aria-controls={`tabpanel-${tab.value}`}
            className={cn(
              'relative px-4 py-2.5 text-sm font-medium transition-colors',
              'hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring',
              isActive
                ? 'text-primary'
                : 'text-muted-foreground hover:text-foreground/80'
            )}
            onClick={() => handleTabClick(tab.value)}
          >
            <span className="flex items-center gap-2">
              {tab.label}
              {tab.count !== undefined && (
                <span
                  className={cn(
                    'inline-flex items-center justify-center min-w-[1.25rem] h-5 px-1.5 rounded text-xs font-medium',
                    isActive
                      ? 'bg-primary/10 text-primary'
                      : 'bg-muted text-muted-foreground'
                  )}
                >
                  {tab.count}
                </span>
              )}
            </span>

            {/* Indicador ativo */}
            {isActive && (
              <span
                className="absolute bottom-0 left-0 right-0 h-0.5 bg-primary"
                aria-hidden="true"
              />
            )}
          </button>
        )
      })}
    </div>
  )
}

DataTableTabs.displayName = 'DataTable.Tabs'
