import * as React from 'react'
import { cn } from '../../utils/cn'
import { flexRender } from '@tanstack/react-table'
import {
  useDataTable,
  useDataTableMeta,
  useDataTableDensity,
  useDataTableEmptyStateConfig,
  useDataTableLoadingState,
  useDataTablePagination,
} from './DataTableContext'
import type { DataTableContentProps } from './types'
import { DENSITY_CONFIG } from './types'
import { useAvailableHeight } from '../../hooks'

import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from './Table'

import { EmptyState } from '../EmptyState'

// ============================================================================
// CONTENT COMPONENT - Tabela principal com density + auto page size
// ============================================================================

export const DataTableContent = React.memo(function DataTableContent({
  stickyHeader = false,
  stripedRows = false,
  highlightOnHover = true,
  onRowClick,
  scrollable = false,
  scrollBottomOffset = 68,
  autoPageSize = false,
  className,
}: DataTableContentProps) {
  const table = useDataTable()
  const { isEmpty } = useDataTableMeta()
  const { density } = useDataTableDensity()
  const { config: emptyStateConfig } = useDataTableEmptyStateConfig()
  const { isLoading, skeletonRows } = useDataTableLoadingState()
  const { setPageSize } = useDataTablePagination()

  const tbodyRef = React.useRef<HTMLTableSectionElement>(null)

  const { ref: scrollRef, style: scrollStyle } = useAvailableHeight<HTMLDivElement>({
    bottomOffset: scrollBottomOffset,
    enabled: scrollable,
  })

  const densityStyles = DENSITY_CONFIG[density]
  const rowHeight = densityStyles.rowHeight + 1 // +1 for border
  const cellClasses = cn(densityStyles.padding, densityStyles.fontSize)
  const columnCount = table.getVisibleLeafColumns().length
  const hasRows = table.getRowModel().rows?.length > 0
  const effectiveStickyHeader = stickyHeader || scrollable

  // Auto page size: measure tbody position and calculate how many rows fit
  React.useEffect(() => {
    if (!autoPageSize) return

    const calculate = () => {
      const tbody = tbodyRef.current
      if (!tbody) return

      const rect = tbody.getBoundingClientRect()
      // Available = viewport bottom - tbody top - pagination (~52px) - margin (~16px)
      const available = window.innerHeight - rect.top - 68
      const rows = Math.floor(available / rowHeight)
      const clamped = Math.max(3, Math.min(50, rows))

      setPageSize(clamped)
    }

    // Wait for layout to settle
    const frame = requestAnimationFrame(calculate)
    window.addEventListener('resize', calculate)
    return () => {
      cancelAnimationFrame(frame)
      window.removeEventListener('resize', calculate)
    }
  }, [autoPageSize, rowHeight, setPageSize])

  // Empty state
  if (!hasRows && isEmpty && !isLoading) {
    return (
      <EmptyState
        message={emptyStateConfig.title}
        description={emptyStateConfig.description}
        icon={emptyStateConfig.icon as React.ComponentType<any>}
        animated={false}
      />
    )
  }

  return (
    <div
      ref={scrollRef}
      className={cn('rounded-md overflow-auto bg-card', className)}
      style={scrollStyle}
    >
      <Table>
        <TableHeader
          className={cn(
            effectiveStickyHeader && 'sticky top-0 z-10 bg-background shadow-[0_1px_0_0_hsl(var(--border))]'
          )}
        >
          {table.getHeaderGroups().map((headerGroup) => (
            <TableRow key={headerGroup.id}>
              {headerGroup.headers.map((header) => (
                <TableHead
                  key={header.id}
                  className={cn(cellClasses, 'font-medium')}
                  style={{ width: header.getSize() !== 150 ? header.getSize() : undefined }}
                >
                  {header.isPlaceholder
                    ? null
                    : flexRender(
                        header.column.columnDef.header,
                        header.getContext()
                      )}
                </TableHead>
              ))}
            </TableRow>
          ))}
        </TableHeader>
        <TableBody ref={tbodyRef}>
          {isLoading
            ? Array.from({ length: skeletonRows }).map((_, index) => (
                <TableRow key={`skeleton-${index}`} className="animate-pulse">
                  {Array.from({ length: columnCount || 4 }).map((_, colIndex) => (
                    <TableCell key={colIndex} className={cellClasses}>
                      <div className="h-4 bg-muted rounded w-3/4" />
                    </TableCell>
                  ))}
                </TableRow>
              ))
            : table.getRowModel().rows.map((row, index) => (
                <TableRow
                  key={row.id}
                  data-state={row.getIsSelected() && 'selected'}
                  className={cn(
                    highlightOnHover && 'hover:bg-muted/50',
                    stripedRows && index % 2 === 1 && 'bg-muted/30',
                    onRowClick && 'cursor-pointer'
                  )}
                  onClick={onRowClick ? () => onRowClick(row) : undefined}
                >
                  {row.getVisibleCells().map((cell) => (
                    <TableCell key={cell.id} className={cellClasses}>
                      {flexRender(cell.column.columnDef.cell, cell.getContext())}
                    </TableCell>
                  ))}
                </TableRow>
              ))}
        </TableBody>
      </Table>
    </div>
  )
})

DataTableContent.displayName = 'DataTable.Content'
