import * as React from 'react'
import { Search, Star, ArrowRight, Building2 } from 'lucide-react'
import { cn } from '../../../utils/cn'
import type {
  SelectionLayoutProps,
  SelectionLayoutSidebarProps,
  SelectionLayoutLogoProps,
  SelectionLayoutHeadlineProps,
  SelectionLayoutStatsProps,
  SelectionLayoutMainProps,
  SelectionLayoutHeaderProps,
  SelectionLayoutSearchProps,
  SelectionLayoutTabsProps,
  SelectionLayoutTabProps,
  SelectionLayoutListProps,
  SelectionLayoutCardProps,
  SelectionLayoutEmptyProps,
} from './types'

// Context para tabs
interface TabsContextValue {
  value: string
  onValueChange: (value: string) => void
}

const TabsContext = React.createContext<TabsContextValue | null>(null)

// ============================================================================
// SelectionLayout Root
// ============================================================================
function SelectionLayoutRoot({ children, className }: SelectionLayoutProps) {
  return (
    <div className={cn('min-h-screen bg-muted/30 flex flex-col lg:flex-row', className)}>
      {children}
    </div>
  )
}

// ============================================================================
// SelectionLayout.Sidebar
// ============================================================================
function SelectionLayoutSidebar({ children, className }: SelectionLayoutSidebarProps) {
  return (
    <div
      className={cn(
        'lg:w-2/5 bg-gradient-to-br from-primary/90 to-primary p-6 lg:p-12',
        'flex flex-col justify-between text-white relative overflow-hidden',
        'min-h-[50vh] lg:min-h-screen',
        className
      )}
    >
      {children}
    </div>
  )
}

// ============================================================================
// SelectionLayout.Logo
// ============================================================================
function SelectionLayoutLogo({ children, className }: SelectionLayoutLogoProps) {
  return (
    <div className={cn('flex items-center gap-3 mb-8 lg:mb-16', className)}>
      {children}
    </div>
  )
}

// ============================================================================
// SelectionLayout.Headline
// ============================================================================
function SelectionLayoutHeadline({
  title,
  bullets,
  className,
}: SelectionLayoutHeadlineProps) {
  return (
    <div className={cn('space-y-4 lg:space-y-6 flex-1', className)}>
      <h1 className="text-3xl lg:text-5xl font-bold leading-tight">{title}</h1>
      {bullets && bullets.length > 0 && (
        <div className="space-y-2 text-white/80">
          {bullets.map((bullet, index) => (
            <p key={index} className="text-base lg:text-lg">
              {bullet}
            </p>
          ))}
        </div>
      )}
    </div>
  )
}

// ============================================================================
// SelectionLayout.Stats
// ============================================================================
function SelectionLayoutStats({ label, value, className }: SelectionLayoutStatsProps) {
  return (
    <div className={cn('bg-white/10 rounded-lg p-4 backdrop-blur-sm', className)}>
      <div className="flex items-center justify-between text-sm lg:text-base">
        <span>{label}</span>
        <span className="font-bold">{value}</span>
      </div>
    </div>
  )
}

// ============================================================================
// SelectionLayout.Main
// ============================================================================
function SelectionLayoutMain({ children, className }: SelectionLayoutMainProps) {
  return (
    <div
      className={cn(
        'lg:w-3/5 bg-background flex flex-col min-h-[50vh] lg:min-h-screen',
        className
      )}
    >
      {children}
    </div>
  )
}

// ============================================================================
// SelectionLayout.Header
// ============================================================================
function SelectionLayoutHeader({
  title,
  subtitle,
  action,
  className,
}: SelectionLayoutHeaderProps) {
  return (
    <div
      className={cn(
        'flex justify-between items-center p-6 lg:p-8 border-b border-border',
        className
      )}
    >
      <div>
        <h2 className="text-xl lg:text-2xl font-bold">{title}</h2>
        {subtitle && <p className="text-sm text-muted-foreground mt-1">{subtitle}</p>}
      </div>
      {action && <div>{action}</div>}
    </div>
  )
}

// ============================================================================
// SelectionLayout.Search
// ============================================================================
function SelectionLayoutSearch({
  value,
  onChange,
  placeholder = 'Buscar...',
  className,
}: SelectionLayoutSearchProps) {
  return (
    <div className={cn('p-6 lg:p-8 pb-4 lg:pb-6', className)}>
      <div className="relative">
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground w-4 h-4" />
        <input
          type="text"
          placeholder={placeholder}
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className={cn(
            'w-full pl-10 h-11 rounded-md border border-input bg-muted/50',
            'focus:bg-background focus:outline-none focus:ring-2 focus:ring-ring',
            'text-sm placeholder:text-muted-foreground'
          )}
        />
      </div>
    </div>
  )
}

// ============================================================================
// SelectionLayout.Tabs
// ============================================================================
function SelectionLayoutTabs({
  children,
  value,
  onValueChange,
  className,
}: SelectionLayoutTabsProps) {
  return (
    <TabsContext.Provider value={{ value, onValueChange }}>
      <div className={cn('px-6 lg:px-8', className)}>
        <div className="flex space-x-1 bg-muted p-1 rounded-lg">{children}</div>
      </div>
    </TabsContext.Provider>
  )
}

// ============================================================================
// SelectionLayout.Tab
// ============================================================================
function SelectionLayoutTab({
  value,
  label,
  icon: Icon,
  badge,
  className,
}: SelectionLayoutTabProps) {
  const context = React.useContext(TabsContext)
  if (!context) {
    throw new Error('SelectionLayout.Tab must be used within SelectionLayout.Tabs')
  }

  const isActive = context.value === value

  return (
    <button
      onClick={() => context.onValueChange(value)}
      className={cn(
        'flex-1 flex items-center justify-center gap-2 px-3 py-2 rounded-md text-sm font-medium transition-all',
        isActive
          ? 'bg-background text-foreground shadow-sm'
          : 'text-muted-foreground hover:text-foreground',
        className
      )}
    >
      {Icon && <Icon className="w-4 h-4" />}
      <span className="hidden sm:inline">{label}</span>
      {badge !== undefined && (
        <span
          className={cn(
            'text-xs px-2 py-0.5 rounded-full',
            isActive ? 'bg-primary/10 text-primary' : 'bg-muted-foreground/20'
          )}
        >
          {badge}
        </span>
      )}
    </button>
  )
}

// ============================================================================
// SelectionLayout.List
// ============================================================================
function SelectionLayoutList({ children, className }: SelectionLayoutListProps) {
  return (
    <div className={cn('flex-1 p-6 lg:p-8 pt-6', className)}>
      <div
        className={cn(
          'space-y-3 max-h-[50vh] lg:max-h-[55vh] overflow-y-auto pr-2',
          'scrollbar-thin scrollbar-thumb-muted-foreground/20 scrollbar-track-transparent'
        )}
      >
        {children}
      </div>
    </div>
  )
}

// ============================================================================
// SelectionLayout.Card
// ============================================================================
function SelectionLayoutCard({
  children,
  className,
  onClick,
  icon,
  title,
  description,
  badge,
  favorite,
  onFavoriteClick,
}: SelectionLayoutCardProps) {
  // Check if icon is a React component (function or forwardRef object)
  const isIconComponent =
    typeof icon === 'function' ||
    (icon && typeof icon === 'object' && '$$typeof' in icon)

  const IconComponent = isIconComponent
    ? (icon as React.ComponentType<{ className?: string }>)
    : null

  return (
    <div
      onClick={onClick}
      className={cn(
        'cursor-pointer transition-all duration-200 rounded-lg border-2 bg-card',
        'hover:shadow-lg hover:border-primary/20 active:scale-[0.98] group',
        className
      )}
    >
      <div className="p-4 lg:p-5">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3 lg:gap-4 flex-1 min-w-0">
            {/* Icon */}
            {icon && (
              <div className="w-10 h-10 lg:w-12 lg:h-12 bg-primary/10 rounded-lg flex items-center justify-center flex-shrink-0">
                {IconComponent ? (
                  <IconComponent className="w-5 h-5 lg:w-6 lg:h-6 text-primary" />
                ) : (
                  icon as React.ReactNode
                )}
              </div>
            )}

            {/* Content */}
            <div className="min-w-0 flex-1">
              <div className="flex items-center gap-2">
                <h3 className="font-semibold text-sm lg:text-base truncate">{title}</h3>
                {favorite && (
                  <Star className="w-4 h-4 text-yellow-500 fill-current flex-shrink-0" />
                )}
                {badge}
              </div>
              {description && (
                <p className="text-muted-foreground text-xs lg:text-sm truncate">
                  {description}
                </p>
              )}
              {children}
            </div>
          </div>

          {/* Actions */}
          <div className="flex items-center gap-2 flex-shrink-0 ml-2">
            {onFavoriteClick && (
              <button
                onClick={(e) => {
                  e.stopPropagation()
                  onFavoriteClick()
                }}
                className="p-2 hover:bg-muted rounded-md transition-colors"
              >
                <Star
                  className={cn(
                    'w-4 h-4',
                    favorite ? 'text-yellow-500 fill-current' : 'text-muted-foreground'
                  )}
                />
              </button>
            )}
            <ArrowRight className="w-5 h-5 text-muted-foreground group-hover:text-foreground transition-colors" />
          </div>
        </div>
      </div>
    </div>
  )
}

// ============================================================================
// SelectionLayout.Empty
// ============================================================================
function SelectionLayoutEmpty({
  icon: Icon = Building2,
  title,
  description,
  action,
  className,
}: SelectionLayoutEmptyProps) {
  return (
    <div className={cn('text-center py-12', className)}>
      <Icon className="w-12 h-12 text-muted-foreground/50 mx-auto mb-4" />
      <h3 className="text-lg font-medium mb-2">{title}</h3>
      {description && <p className="text-muted-foreground mb-4">{description}</p>}
      {action}
    </div>
  )
}

// ============================================================================
// Compound Component Export
// ============================================================================
SelectionLayoutRoot.displayName = 'SelectionLayout'
SelectionLayoutSidebar.displayName = 'SelectionLayout.Sidebar'
SelectionLayoutLogo.displayName = 'SelectionLayout.Logo'
SelectionLayoutHeadline.displayName = 'SelectionLayout.Headline'
SelectionLayoutStats.displayName = 'SelectionLayout.Stats'
SelectionLayoutMain.displayName = 'SelectionLayout.Main'
SelectionLayoutHeader.displayName = 'SelectionLayout.Header'
SelectionLayoutSearch.displayName = 'SelectionLayout.Search'
SelectionLayoutTabs.displayName = 'SelectionLayout.Tabs'
SelectionLayoutTab.displayName = 'SelectionLayout.Tab'
SelectionLayoutList.displayName = 'SelectionLayout.List'
SelectionLayoutCard.displayName = 'SelectionLayout.Card'
SelectionLayoutEmpty.displayName = 'SelectionLayout.Empty'

export const SelectionLayout = Object.assign(SelectionLayoutRoot, {
  Sidebar: SelectionLayoutSidebar,
  Logo: SelectionLayoutLogo,
  Headline: SelectionLayoutHeadline,
  Stats: SelectionLayoutStats,
  Main: SelectionLayoutMain,
  Header: SelectionLayoutHeader,
  Search: SelectionLayoutSearch,
  Tabs: SelectionLayoutTabs,
  Tab: SelectionLayoutTab,
  List: SelectionLayoutList,
  Card: SelectionLayoutCard,
  Empty: SelectionLayoutEmpty,
})
