import * as React from 'react'
import {
  type ColumnDef,
  type ColumnFiltersState,
  type SortingState,
  type VisibilityState,
  type PaginationState,
  type RowSelectionState,
  type Table,
  flexRender,
  getCoreRowModel,
  getFilteredRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  useReactTable,
} from '@tanstack/react-table'
import type { DataTableMeta, DataTableDensity, UseDataTableConfig } from '../types'

// ============================================================================
// HOOK INTERNO - Usado pelo DataTable root
// ============================================================================
//
// Este hook gerencia todo o estado interno da tabela.
// Consumidores não devem usar diretamente - use os hooks do Context:
//
// - useDataTable() - instância da tabela
// - useDataTableMeta() - estado meta (loading, empty, selection)
// - useDataTableDensity() - densidade (compact, default, comfortable)
// - useDataTablePagination() - helpers de paginação
// - useDataTableSorting() - helpers de sorting
// - useDataTableSelection() - rows selecionadas
//
// ============================================================================

interface UseDataTableInternalConfig<TData extends object> {
  data: TData[]
  columns: ColumnDef<TData, unknown>[]
  getRowId?: (row: TData) => string
  /** Server-side pagination: disables local pagination */
  manualPagination?: boolean
  /** Total page count for server-side pagination */
  pageCount?: number
  /** Initial page size (default: 10) */
  initialPageSize?: number
  /** Callback when pagination changes (server-side) */
  onPaginationChange?: (pagination: { pageIndex: number; pageSize: number }) => void
}

interface UseDataTableInternalReturn<TData extends object> {
  table: Table<TData>
  meta: DataTableMeta
  density: DataTableDensity
  setDensity: (density: DataTableDensity) => void
  pageIndex: number
  pageSize: number
}

export function useDataTableInternal<TData extends object>({
  data,
  columns,
  getRowId,
  manualPagination = false,
  pageCount: externalPageCount,
  initialPageSize = 10,
  onPaginationChange: onPaginationChangeProp,
}: UseDataTableInternalConfig<TData>): UseDataTableInternalReturn<TData> {
  // ============================================================================
  // STATE
  // ============================================================================

  const [rowSelection, setRowSelection] = React.useState<RowSelectionState>({})
  const [columnVisibility, setColumnVisibility] = React.useState<VisibilityState>({})
  const [columnFilters, setColumnFilters] = React.useState<ColumnFiltersState>([])
  const [sorting, setSorting] = React.useState<SortingState>([])
  const [globalFilter, setGlobalFilter] = React.useState<string>('')
  const [density, setDensity] = React.useState<DataTableDensity>('default')

  const [pagination, setPagination] = React.useState<PaginationState>({
    pageIndex: 0,
    pageSize: initialPageSize,
  })

  // ============================================================================
  // TABLE INSTANCE
  // ============================================================================

  const table = useReactTable({
    data,
    columns,
    getRowId,
    state: {
      sorting,
      columnVisibility,
      rowSelection,
      columnFilters,
      pagination,
      globalFilter,
    },
    // Features
    enableRowSelection: true,
    enableSorting: true,
    enableFilters: true,
    enableGlobalFilter: true,

    // Server-side pagination support
    manualPagination,
    pageCount: manualPagination ? externalPageCount : undefined,

    // Handlers
    onRowSelectionChange: setRowSelection,
    onSortingChange: setSorting,
    onColumnFiltersChange: setColumnFilters,
    onColumnVisibilityChange: setColumnVisibility,
    onPaginationChange: setPagination,
    onGlobalFilterChange: setGlobalFilter,

    // Row Models
    getCoreRowModel: getCoreRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    getSortedRowModel: getSortedRowModel(),
  })

  // ============================================================================
  // SERVER-SIDE PAGINATION CALLBACK
  // ============================================================================

  React.useEffect(() => {
    if (onPaginationChangeProp) {
      onPaginationChangeProp({
        pageIndex: pagination.pageIndex,
        pageSize: pagination.pageSize,
      })
    }
  }, [pagination.pageIndex, pagination.pageSize, onPaginationChangeProp])

  // ============================================================================
  // META STATE (Derivado)
  // ============================================================================

  const meta: DataTableMeta = React.useMemo(
    () => ({
      isLoading: false, // Loading é controlado externamente via DataTable.Loading
      isEmpty: data.length === 0,
      selectedRowCount: Object.keys(rowSelection).length,
      totalRows: data.length,
      density,
    }),
    [data.length, rowSelection, density]
  )

  return {
    table: table as Table<TData>,
    meta,
    density,
    setDensity,
    pageIndex: pagination.pageIndex,
    pageSize: pagination.pageSize,
  }
}

// ============================================================================
// EXPORTS PÚBLICOS
// ============================================================================

// Re-export flexRender para uso em componentes de cell
export { flexRender }

// Re-export tipos úteis
export type { UseDataTableConfig }
