import * as React from 'react'
import { Bell } from 'lucide-react'
import { Button } from '../Button'
import { Popover, PopoverContent, PopoverTrigger } from '../Popover'
import {
  Card,
  CardContent,
  CardFooter,
  CardHeader,
  CardTitle,
} from '../Card'

export interface NotificationItem {
  id: string
  icon?: React.ReactNode
  title: string
  description: string
  time: string
  isHighlighted?: boolean
}

export interface NavbarNotificationProps {
  notifications?: NotificationItem[]
  onMarkAllAsRead?: () => void
  onViewAll?: () => void
}

export function NavbarNotification({
  notifications = [],
  onMarkAllAsRead,
  onViewAll,
}: NavbarNotificationProps) {
  const hasNotifications = notifications.length > 0

  return (
    <Popover>
      <PopoverTrigger asChild>
        <Button variant="ghost" size="icon" className="rounded-full relative">
          <Bell className="h-5 w-5 text-muted-foreground" />
          {hasNotifications && (
            <span className="absolute top-0 right-0 h-2 w-2 rounded-full bg-red-500" />
          )}
          <span className="sr-only">Abrir notificações</span>
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-[400px] p-0" align="end">
        <Card className="border-0 shadow-none">
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-xl font-bold">Notificações</CardTitle>
            {onMarkAllAsRead && (
              <Button
                variant="link"
                className="text-primary hover:text-primary/80"
                onClick={onMarkAllAsRead}
              >
                Marcar todas como lidas
              </Button>
            )}
          </CardHeader>
          <CardContent className="px-0">
            {notifications.length === 0 ? (
              <div className="py-8 text-center text-muted-foreground">
                Nenhuma notificação
              </div>
            ) : (
              <>
                <div className="bg-background/30 px-6 py-2 text-sm font-medium text-gray-500">
                  Hoje
                </div>
                <div className="space-y-4 px-6 py-3">
                  {notifications.map((notification) => (
                    <div
                      key={notification.id}
                      className={`flex items-start space-x-4 ${
                        notification.isHighlighted
                          ? 'rounded-lg bg-primary/5 p-3'
                          : ''
                      }`}
                    >
                      {notification.icon && (
                        <div
                          className={`mt-1 rounded-full p-2 ${
                            notification.isHighlighted
                              ? 'bg-primary/25'
                              : 'bg-gray-500/20'
                          }`}
                        >
                          {notification.icon}
                        </div>
                      )}
                      <div className="flex-1">
                        <p className="text-sm font-medium">
                          {notification.title}
                        </p>
                        <p className="text-sm text-gray-500">
                          {notification.description}
                        </p>
                        <p className="mt-1 text-xs text-gray-400">
                          {notification.time}
                        </p>
                      </div>
                    </div>
                  ))}
                </div>
              </>
            )}
          </CardContent>
          {onViewAll && (
            <CardFooter className="justify-center">
              <Button
                variant="link"
                className="text-primary hover:text-primary/80"
                onClick={onViewAll}
              >
                Ver todas notificações
              </Button>
            </CardFooter>
          )}
        </Card>
      </PopoverContent>
    </Popover>
  )
}

NavbarNotification.displayName = 'NavbarNotification'
