import * as React from 'react'
import * as TooltipPrimitive from '@radix-ui/react-tooltip'
import { cva, type VariantProps } from 'class-variance-authority'
import { X } from 'lucide-react'
import { cn } from '../../utils/cn'

// ============================================================================
// Provider
// ============================================================================

const TooltipProvider = TooltipPrimitive.Provider

// ============================================================================
// Root
// ============================================================================

const TooltipRoot = TooltipPrimitive.Root

// ============================================================================
// Trigger
// ============================================================================

const TooltipTrigger = TooltipPrimitive.Trigger

// ============================================================================
// Portal
// ============================================================================

const TooltipPortal = TooltipPrimitive.Portal

// ============================================================================
// Arrow
// ============================================================================

const TooltipArrow = React.forwardRef<
  React.ElementRef<typeof TooltipPrimitive.Arrow>,
  React.ComponentPropsWithoutRef<typeof TooltipPrimitive.Arrow> & {
    variant?: 'light' | 'dark'
  }
>(({ className, variant = 'light', ...props }, ref) => (
  <TooltipPrimitive.Arrow
    ref={ref}
    className={cn(
      'z-50',
      variant === 'dark' ? 'fill-popover' : 'fill-background',
      className
    )}
    {...props}
  />
))
TooltipArrow.displayName = 'TooltipArrow'

// ============================================================================
// Content Variants
// ============================================================================

const tooltipContentVariants = cva(
  'z-50 overflow-hidden rounded-lg shadow-lg outline-none animate-in fade-in-0 zoom-in-95 data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=closed]:zoom-out-95 data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2',
  {
    variants: {
      variant: {
        light: 'bg-background text-foreground border border-border',
        dark: 'bg-popover text-popover-foreground border border-border',
      },
      size: {
        sm: 'max-w-[200px] p-2',
        md: 'max-w-[280px] p-3',
        lg: 'max-w-[360px] p-4',
      },
    },
    defaultVariants: {
      variant: 'light',
      size: 'md',
    },
  }
)

// ============================================================================
// Content
// ============================================================================

export interface TooltipContentProps
  extends React.ComponentPropsWithoutRef<typeof TooltipPrimitive.Content>,
    VariantProps<typeof tooltipContentVariants> {
  showArrow?: boolean
  onDismiss?: () => void
}

const TooltipContent = React.forwardRef<
  React.ElementRef<typeof TooltipPrimitive.Content>,
  TooltipContentProps
>(
  (
    {
      className,
      variant = 'light',
      size = 'md',
      sideOffset = 8,
      showArrow = true,
      onDismiss,
      children,
      ...props
    },
    ref
  ) => (
    <TooltipPrimitive.Portal>
      <TooltipPrimitive.Content
        ref={ref}
        sideOffset={sideOffset}
        className={cn(tooltipContentVariants({ variant, size }), className)}
        {...props}
      >
        {onDismiss && (
          <button
            onClick={onDismiss}
            className="absolute top-2 right-2 p-1 rounded-full transition-colors hover:bg-muted text-muted-foreground hover:text-foreground"
            aria-label="Fechar"
          >
            <X className="h-3.5 w-3.5" />
          </button>
        )}
        {children}
        {showArrow && <TooltipArrow variant={variant ?? 'light'} width={12} height={6} />}
      </TooltipPrimitive.Content>
    </TooltipPrimitive.Portal>
  )
)
TooltipContent.displayName = TooltipPrimitive.Content.displayName

// ============================================================================
// Header
// ============================================================================

export interface TooltipHeaderProps extends React.HTMLAttributes<HTMLDivElement> {}

const TooltipHeader = React.forwardRef<HTMLDivElement, TooltipHeaderProps>(
  ({ className, ...props }, ref) => (
    <div ref={ref} className={cn('flex flex-col gap-1', className)} {...props} />
  )
)
TooltipHeader.displayName = 'TooltipHeader'

// ============================================================================
// Title
// ============================================================================

export interface TooltipTitleProps extends React.HTMLAttributes<HTMLHeadingElement> {}

const TooltipTitle = React.forwardRef<HTMLHeadingElement, TooltipTitleProps>(
  ({ className, ...props }, ref) => (
    <h4
      ref={ref}
      className={cn('text-sm font-semibold leading-tight', className)}
      {...props}
    />
  )
)
TooltipTitle.displayName = 'TooltipTitle'

// ============================================================================
// Description
// ============================================================================

export interface TooltipDescriptionProps
  extends React.HTMLAttributes<HTMLParagraphElement> {}

const TooltipDescription = React.forwardRef<
  HTMLParagraphElement,
  TooltipDescriptionProps
>(({ className, ...props }, ref) => (
  <p
    ref={ref}
    className={cn('text-xs leading-relaxed text-muted-foreground', className)}
    {...props}
  />
))
TooltipDescription.displayName = 'TooltipDescription'

// ============================================================================
// Actions
// ============================================================================

export interface TooltipActionsProps extends React.HTMLAttributes<HTMLDivElement> {}

const TooltipActions = React.forwardRef<HTMLDivElement, TooltipActionsProps>(
  ({ className, ...props }, ref) => (
    <div
      ref={ref}
      className={cn('flex items-center gap-2 mt-3', className)}
      {...props}
    />
  )
)
TooltipActions.displayName = 'TooltipActions'

// ============================================================================
// Action Button
// ============================================================================

const tooltipActionVariants = cva(
  'inline-flex items-center justify-center text-xs font-medium rounded-md transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50',
  {
    variants: {
      variant: {
        primary: 'bg-primary text-primary-foreground hover:bg-primary/90 px-3 py-1.5',
        secondary:
          'bg-transparent text-muted-foreground hover:text-foreground hover:underline px-2 py-1.5',
        outline:
          'border border-border bg-background text-foreground hover:bg-muted px-3 py-1.5',
      },
    },
    defaultVariants: {
      variant: 'primary',
    },
  }
)

export interface TooltipActionProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof tooltipActionVariants> {}

const TooltipAction = React.forwardRef<HTMLButtonElement, TooltipActionProps>(
  ({ className, variant = 'primary', ...props }, ref) => (
    <button
      ref={ref}
      className={cn(tooltipActionVariants({ variant }), className)}
      {...props}
    />
  )
)
TooltipAction.displayName = 'TooltipAction'

// ============================================================================
// Icon Container
// ============================================================================

export interface TooltipIconProps extends React.HTMLAttributes<HTMLDivElement> {}

const TooltipIcon = React.forwardRef<HTMLDivElement, TooltipIconProps>(
  ({ className, children, ...props }, ref) => (
    <div
      ref={ref}
      className={cn(
        'flex items-center justify-center w-10 h-10 rounded-full mb-3 bg-muted',
        className
      )}
      {...props}
    >
      {children}
    </div>
  )
)
TooltipIcon.displayName = 'TooltipIcon'

// ============================================================================
// Simple Tooltip (shorthand for common use case)
// ============================================================================

export interface SimpleTooltipProps {
  children: React.ReactNode
  content: React.ReactNode
  variant?: 'light' | 'dark'
  side?: 'top' | 'right' | 'bottom' | 'left'
  align?: 'start' | 'center' | 'end'
  delayDuration?: number
  open?: boolean
  defaultOpen?: boolean
  onOpenChange?: (open: boolean) => void
}

const SimpleTooltip = ({
  children,
  content,
  variant = 'light',
  side = 'top',
  align = 'center',
  delayDuration = 200,
  open,
  defaultOpen,
  onOpenChange,
}: SimpleTooltipProps) => (
  <TooltipRoot
    open={open}
    defaultOpen={defaultOpen}
    onOpenChange={onOpenChange}
    delayDuration={delayDuration}
  >
    <TooltipTrigger asChild>{children}</TooltipTrigger>
    <TooltipContent variant={variant} side={side} align={align} size="sm">
      <span className="text-xs">{content}</span>
    </TooltipContent>
  </TooltipRoot>
)
SimpleTooltip.displayName = 'SimpleTooltip'

// ============================================================================
// Compound Component
// ============================================================================

const Tooltip = Object.assign(TooltipRoot, {
  Provider: TooltipProvider,
  Trigger: TooltipTrigger,
  Portal: TooltipPortal,
  Content: TooltipContent,
  Arrow: TooltipArrow,
  Header: TooltipHeader,
  Title: TooltipTitle,
  Description: TooltipDescription,
  Actions: TooltipActions,
  Action: TooltipAction,
  Icon: TooltipIcon,
  Simple: SimpleTooltip,
})

export {
  Tooltip,
  TooltipProvider,
  TooltipRoot,
  TooltipTrigger,
  TooltipPortal,
  TooltipContent,
  TooltipArrow,
  TooltipHeader,
  TooltipTitle,
  TooltipDescription,
  TooltipActions,
  TooltipAction,
  TooltipIcon,
  SimpleTooltip,
  tooltipContentVariants,
  tooltipActionVariants,
}
