import * as React from 'react'
import { cn } from '../../utils/cn'

export interface RippleEffectProps {
  size?: 'sm' | 'md' | 'lg' | 'xl' | 'xxl'
  color?: 'primary' | 'secondary' | 'accent' | 'muted'
  intensity?: 'light' | 'medium' | 'strong'
  rings?: number
  position?:
    | 'center'
    | 'top-left'
    | 'top-right'
    | 'bottom-left'
    | 'bottom-right'
    | 'top-center'
    | 'bottom-center'
  className?: string
}

// Configurações memoizadas
const SIZE_CONFIG = {
  sm: { base: 8, increment: 2 },
  md: { base: 12, increment: 4 },
  lg: { base: 16, increment: 6 },
  xl: { base: 28, increment: 14 },
  xxl: { base: 36, increment: 16 },
} as const

const INTENSITY_CONFIG = {
  light: [4, 6, 8, 10, 12],
  medium: [6, 8, 10, 12, 16],
  strong: [8, 12, 16, 20, 25],
} as const

const POSITION_CONFIG = {
  center: 'items-center justify-center',
  'top-left': 'items-start justify-start',
  'top-right': 'items-start justify-end',
  'bottom-left': 'items-end justify-start',
  'bottom-right': 'items-end justify-end',
  'top-center': 'items-start justify-center',
  'bottom-center': 'items-end justify-center',
} as const

// Mapa de cores para classes Tailwind
const COLOR_MAP = {
  primary: 'border-primary',
  secondary: 'border-secondary',
  accent: 'border-accent',
  muted: 'border-muted',
} as const

// Componente interno memoizado para cada anel
const RippleRing = React.memo<{
  size: number
  color: string
  opacity: number
}>(({ size, color, opacity }) => {
  const borderColorClass = COLOR_MAP[color as keyof typeof COLOR_MAP] || COLOR_MAP.primary

  return (
    <div
      className={cn('absolute rounded-full', borderColorClass)}
      style={{
        width: `${size * 4}px`,
        height: `${size * 4}px`,
        borderWidth: '1px',
        opacity: opacity / 100,
        top: '50%',
        left: '50%',
        transform: 'translate(-50%, -50%)',
      }}
    />
  )
})
RippleRing.displayName = 'RippleRing'

export const RippleEffect = React.memo<RippleEffectProps>(
  ({
    size = 'md',
    color = 'primary',
    intensity = 'medium',
    rings = 5,
    position = 'center',
    className,
  }) => {
    const { base, increment } = SIZE_CONFIG[size]
    const opacities = INTENSITY_CONFIG[intensity]
    const positionClasses = POSITION_CONFIG[position]

    // Memoizar os anéis para evitar recriação
    const rippleRings = React.useMemo(
      () =>
        Array.from({ length: rings }).map((_, index) => {
          const ringSize = base + increment * (rings - index - 1)
          const opacity = opacities[index] || opacities[opacities.length - 1]

          return (
            <RippleRing
              key={index}
              size={ringSize}
              color={color}
              opacity={opacity}
            />
          )
        }),
      [base, increment, rings, opacities, color]
    )

    return (
      <div
        className={cn(
          'absolute inset-0 flex pointer-events-none',
          positionClasses,
          className
        )}
      >
        <div className="relative">{rippleRings}</div>
      </div>
    )
  }
)
RippleEffect.displayName = 'RippleEffect'

export interface RippleWrapperProps {
  children: React.ReactNode
  rippleProps?: RippleEffectProps
  className?: string
}

export const RippleWrapper = React.memo<RippleWrapperProps>(
  ({ children, rippleProps, className }) => {
    return (
      <div className={cn('relative', className)}>
        {rippleProps && <RippleEffect {...rippleProps} />}
        <div className="relative z-10">{children}</div>
      </div>
    )
  }
)
RippleWrapper.displayName = 'RippleWrapper'

export interface RippleBackgroundProps extends RippleEffectProps {
  containerClassName?: string
}

export const RippleBackground = React.memo<RippleBackgroundProps>(
  ({ containerClassName, ...rippleProps }) => {
    return (
      <div
        className={cn(
          'absolute inset-0 overflow-hidden pointer-events-none',
          containerClassName
        )}
      >
        <RippleEffect {...rippleProps} />
      </div>
    )
  }
)
RippleBackground.displayName = 'RippleBackground'
