import * as React from 'react'
import { cn } from '../../utils/cn'
import { useDataTableInstance } from './DataTableContext'
import { useDebounce } from './hooks/useDebounce'
import type { DataTableSearchProps } from './types'
import { Input } from '../Input'
import { Search } from 'lucide-react'

// ============================================================================
// SEARCH COMPONENT - Busca com debounce (client-side e server-side)
// ============================================================================

export const DataTableSearch = React.memo(function DataTableSearch({
  column,
  placeholder = 'Buscar...',
  debounce = 300,
  onSearch,
  className,
}: DataTableSearchProps) {
  const table = useDataTableInstance()
  const columnInstance = column ? table.getColumn(column) : null

  const [value, setValue] = React.useState(
    (columnInstance?.getFilterValue() as string) ?? ''
  )
  const debouncedValue = useDebounce(value, debounce)

  const isServerSide = !!onSearch

  React.useEffect(() => {
    if (isServerSide) {
      onSearch(debouncedValue)
    } else if (columnInstance) {
      columnInstance.setFilterValue(debouncedValue || undefined)
    }
  }, [debouncedValue, columnInstance, onSearch, isServerSide])

  // Sync external filter changes back to input (client-side only)
  React.useEffect(() => {
    if (isServerSide || !columnInstance) return
    const filterValue = (columnInstance.getFilterValue() as string) ?? ''
    if (filterValue !== value) {
      setValue(filterValue)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [columnInstance?.getFilterValue(), isServerSide])

  return (
    <div className={cn('relative w-[150px] lg:w-[250px]', className)}>
      <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground pointer-events-none" />
      <Input
        placeholder={placeholder}
        value={value}
        onChange={(e) => setValue(e.target.value)}
        className="h-9 pl-9"
      />
    </div>
  )
})
