import * as React from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { ChevronDown } from 'lucide-react'
import { cn } from '../../utils/cn'
import { useSidebar } from './SidebarContext'
import type { SidebarFooterProps } from './types'

// Helper to check if icon is a Lucide icon
function isLucideIcon(icon: unknown): icon is React.ComponentType<{ className?: string }> {
  return typeof icon === 'function'
}

// Get initials from name
function getInitials(name: string): string {
  return name
    .split(' ')
    .map((part) => part.charAt(0))
    .slice(0, 2)
    .join('')
    .toUpperCase()
}

export const SidebarFooter = React.memo<SidebarFooterProps>(function SidebarFooter({
  user,
  menuItems,
  children,
  className,
}) {
  const { expanded } = useSidebar()
  const [menuOpen, setMenuOpen] = React.useState(false)

  const handleToggleMenu = React.useCallback(() => {
    setMenuOpen((prev) => !prev)
  }, [])

  // Close menu when clicking outside
  React.useEffect(() => {
    if (!menuOpen) return

    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as HTMLElement
      if (!target.closest('[data-sidebar-footer]')) {
        setMenuOpen(false)
      }
    }

    document.addEventListener('click', handleClickOutside)
    return () => document.removeEventListener('click', handleClickOutside)
  }, [menuOpen])

  // If children provided, render them directly
  if (children) {
    return (
      <div className={cn('border-t border-border p-2', className)}>
        {children}
      </div>
    )
  }

  // Structured footer with user and menu
  if (!user) return null

  return (
    <div
      data-sidebar-footer
      className={cn('group cursor-pointer border-t border-border p-2', className)}
    >
      <div className="relative">
        <button
          onClick={handleToggleMenu}
          className={cn(
            'flex w-full items-center gap-2 rounded-md p-1.5 transition-all',
            'hover:bg-muted',
            menuOpen && 'bg-muted'
          )}
        >
          {/* Avatar */}
          <div className="relative flex-shrink-0">
            {user.avatar ? (
              <img
                src={user.avatar}
                alt={user.name}
                className="h-8 w-8 rounded-full object-cover"
              />
            ) : (
              <div className="flex h-8 w-8 items-center justify-center rounded-full bg-primary/10 text-xs font-medium text-primary">
                {getInitials(user.name)}
              </div>
            )}
          </div>

          {/* User Info - Only when expanded */}
          <AnimatePresence>
            {expanded && (
              <motion.div
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -10 }}
                transition={{ duration: 0.2 }}
                className="flex flex-1 items-center justify-between"
              >
                <div className="flex flex-col items-start">
                  <span className="text-xs font-medium truncate max-w-[120px]">
                    {user.name}
                  </span>
                  {user.email && (
                    <span className="text-[10px] text-muted-foreground truncate max-w-[120px]">
                      {user.email}
                    </span>
                  )}
                </div>
                <ChevronDown
                  className={cn(
                    'h-3 w-3 text-muted-foreground transition-transform',
                    menuOpen && 'rotate-180'
                  )}
                />
              </motion.div>
            )}
          </AnimatePresence>
        </button>

        {/* Dropdown Menu */}
        <AnimatePresence>
          {menuOpen && expanded && menuItems && menuItems.length > 0 && (
            <motion.div
              initial={{ opacity: 0, y: -10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -10 }}
              transition={{ duration: 0.15 }}
              className="absolute bottom-full left-0 right-0 mb-1 overflow-hidden rounded-md border border-border bg-card shadow-lg"
            >
              <div className="py-1">
                {menuItems.map((item, index) => {
                  const IconComponent = item.icon && isLucideIcon(item.icon) ? item.icon : null
                  const isDestructive = item.variant === 'destructive'

                  return (
                    <React.Fragment key={item.label}>
                      {/* Separator before destructive items */}
                      {isDestructive && index > 0 && (
                        <div className="my-1 border-t border-border" />
                      )}
                      <button
                        onClick={() => {
                          item.onClick()
                          setMenuOpen(false)
                        }}
                        className={cn(
                          'flex w-full items-center gap-2 px-3 py-1.5 text-xs transition-colors',
                          isDestructive
                            ? 'text-destructive hover:bg-destructive/10'
                            : 'text-foreground hover:bg-muted'
                        )}
                      >
                        {IconComponent && <IconComponent className="h-3 w-3" />}
                        <span>{item.label}</span>
                      </button>
                    </React.Fragment>
                  )
                })}
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  )
})

SidebarFooter.displayName = 'Sidebar.Footer'
