'use client'

import { Controller } from 'react-hook-form'
import type { FieldValues } from 'react-hook-form'
import { Textarea } from '../Textarea'
import { useFormContext, FormFieldProvider } from './FormContext'
import type { FormTextareaProps } from './types'
import { cn } from '../../utils/cn'

export function FormTextarea<T extends FieldValues = FieldValues>({
  name,
  label,
  description,
  required,
  disabled,
  className,
  hideError = false,
  showCount = false,
  maxLength,
  ...textareaProps
}: FormTextareaProps<T>) {
  const form = useFormContext<T>()
  const fieldState = form.getFieldState(name, form.formState)
  const error = fieldState.error?.message

  return (
    <FormFieldProvider name={name as string}>
      <Controller
        control={form.control}
        name={name}
        render={({ field }) => {
          const charCount = field.value?.length ?? 0

          return (
            <div className={cn('space-y-1', className)}>
              <Textarea
                {...textareaProps}
                ref={field.ref}
                name={field.name}
                value={field.value ?? ''}
                onChange={(e) => field.onChange(e.target.value || undefined)}
                onBlur={field.onBlur}
                disabled={disabled}
                label={label}
                required={required}
                error={!!error}
                maxLength={maxLength}
              />

              <div className="flex justify-between px-1">
                <div>
                  {description && !error && (
                    <p className="text-xs text-muted-foreground">{description}</p>
                  )}

                  {!hideError && error && (
                    <p className="text-xs text-red-500">{error}</p>
                  )}
                </div>

                {showCount && maxLength && (
                  <p
                    className={cn(
                      'text-xs',
                      charCount > maxLength ? 'text-red-500' : 'text-muted-foreground'
                    )}
                  >
                    {charCount}/{maxLength}
                  </p>
                )}
              </div>
            </div>
          )
        }}
      />
    </FormFieldProvider>
  )
}

FormTextarea.displayName = 'Form.Textarea'
