import * as React from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { ChevronRight } from 'lucide-react'
import { cn } from '../../utils/cn'
import { useSidebar } from './SidebarContext'
import type { SidebarNavGroupProps, BadgeVariant } from './types'

// Helper to render icon - handles Lucide icons, forwardRef, memo, and React elements
function renderIcon(icon: unknown, className: string): React.ReactNode {
  if (!icon) return null

  // If it's a valid React element, render it directly
  if (React.isValidElement(icon)) {
    return React.cloneElement(icon as React.ReactElement<{ className?: string }>, { className })
  }

  // If it's a component (function, forwardRef, memo), render it
  if (
    typeof icon === 'function' ||
    (typeof icon === 'object' && icon !== null && '$$typeof' in icon)
  ) {
    const IconComponent = icon as React.ComponentType<{ className?: string }>
    return <IconComponent className={className} />
  }

  return null
}

// Badge variant styles
const badgeVariantStyles: Record<BadgeVariant, string> = {
  default: 'bg-primary/10 text-primary',
  notification: 'bg-destructive/20 text-destructive',
  success: 'bg-green-100 text-green-600',
  warning: 'bg-amber-100 text-amber-600',
}

export const SidebarNavGroup = React.memo<SidebarNavGroupProps>(function SidebarNavGroup({
  icon,
  label,
  children,
  id,
  defaultOpen = false,
  isActive = false,
  badge,
  badgeVariant = 'default',
  className,
}) {
  const { expanded, activeSection, setActiveSection } = useSidebar()
  const [isOpen, setIsOpen] = React.useState(defaultOpen)
  const groupId = id || label.toLowerCase().replace(/\s+/g, '-')

  // Sync with context activeSection
  const isExpanded = expanded && (activeSection === groupId || isOpen)

  const handleClick = React.useCallback(() => {
    if (activeSection === groupId) {
      setActiveSection(null)
      setIsOpen(false)
    } else {
      setActiveSection(groupId)
      setIsOpen(true)
    }
  }, [activeSection, groupId, setActiveSection])

  // Auto-expand when sidebar expands and group is active
  React.useEffect(() => {
    if (expanded && isActive && !isOpen) {
      setIsOpen(true)
      setActiveSection(groupId)
    }
  }, [expanded, isActive, isOpen, setActiveSection, groupId])

  const iconSize = expanded ? 'h-3.5 w-3.5' : 'h-4 w-4'

  return (
    <div className={cn('relative', className)}>
      {/* Group Header Button */}
      <button
        onClick={handleClick}
        className={cn(
          'group relative flex w-full items-center rounded-md px-2 py-1.5 transition-all duration-200',
          isActive
            ? 'bg-primary/10 text-primary'
            : 'hover:bg-primary/5 hover:text-primary'
        )}
      >
        {/* Active indicator - left border */}
        {isActive && (
          <motion.div
            layoutId="sidebarGroupActiveIndicator"
            className="absolute left-0 top-0 bottom-0 w-0.5 rounded-r-full bg-primary"
            transition={{ type: 'spring', stiffness: 300, damping: 30 }}
          />
        )}

        {/* Icon */}
        <div
          className={cn(
            'flex h-6 w-6 items-center justify-center rounded-md transition-all duration-200',
            isActive
              ? 'text-primary bg-primary/10 group-hover:bg-primary/20'
              : 'text-muted-foreground group-hover:text-foreground'
          )}
        >
          {renderIcon(icon, iconSize)}
        </div>

        {/* Label */}
        <AnimatePresence>
          {expanded && (
            <motion.span
              initial={{ opacity: 0, x: -10 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -10 }}
              transition={{ duration: 0.2 }}
              className="ml-2 flex-1 text-left text-xs font-medium truncate"
            >
              {label}
            </motion.span>
          )}
        </AnimatePresence>

        {/* Badge - Full when expanded */}
        <AnimatePresence>
          {badge !== undefined && expanded && (
            <motion.div
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.8 }}
              transition={{ duration: 0.2 }}
              className={cn(
                'ml-1 flex h-4 min-w-[16px] items-center justify-center rounded-full px-1 text-[10px] font-medium',
                badgeVariantStyles[badgeVariant]
              )}
            >
              {badge}
            </motion.div>
          )}
        </AnimatePresence>

        {/* Chevron - Rotates when expanded */}
        {expanded && (
          <motion.div
            animate={{ rotate: isExpanded ? 90 : 0 }}
            transition={{ duration: 0.2 }}
            className="ml-1"
          >
            <ChevronRight className="h-3 w-3 text-muted-foreground" />
          </motion.div>
        )}

        {/* Badge dot - When collapsed */}
        {badge !== undefined && !expanded && (
          <div
            className={cn(
              'absolute top-1 right-1 h-2 w-2 rounded-full',
              badgeVariant === 'notification' && 'bg-destructive',
              badgeVariant === 'success' && 'bg-green-500',
              badgeVariant === 'warning' && 'bg-amber-500',
              badgeVariant === 'default' && 'bg-primary'
            )}
          />
        )}
      </button>

      {/* Submenu Items */}
      <AnimatePresence>
        {isExpanded && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.2, ease: 'easeInOut' }}
            className="overflow-hidden"
          >
            <div className="mt-0.5 space-y-0.5 pl-4 pr-2">
              {children}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  )
})

SidebarNavGroup.displayName = 'Sidebar.NavGroup'
