'use client'

import * as React from 'react'
import { cn } from '../../utils/cn'

// ============================================================================
// Content Container
// ============================================================================

export interface ItemCardContentProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Whether to use muted background */
  muted?: boolean
}

const ItemCardContent = React.forwardRef<HTMLDivElement, ItemCardContentProps>(
  ({ className, muted = true, children, ...props }, ref) => {
    return (
      <div
        ref={ref}
        className={cn(
          'px-6 py-3 space-y-2',
          muted && 'bg-muted/40',
          className
        )}
        {...props}
      >
        {children}
      </div>
    )
  }
)

ItemCardContent.displayName = 'ItemCardContent'

// ============================================================================
// Content Item (row in list)
// ============================================================================

export interface ItemCardContentItemProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Label on the left */
  label?: React.ReactNode
  /** Value on the right */
  value?: React.ReactNode
  /** Secondary value (e.g., price) */
  secondary?: React.ReactNode
}

const ItemCardContentItem = React.forwardRef<HTMLDivElement, ItemCardContentItemProps>(
  ({ className, label, value, secondary, children, ...props }, ref) => {
    // If children are provided, render them directly
    if (children) {
      return (
        <div
          ref={ref}
          className={cn(
            'flex justify-between items-center text-sm text-muted-foreground',
            className
          )}
          {...props}
        >
          {children}
        </div>
      )
    }

    // Otherwise use the label/value/secondary props
    return (
      <div
        ref={ref}
        className={cn(
          'flex justify-between items-center text-sm text-muted-foreground gap-2',
          className
        )}
        {...props}
      >
        <span className="truncate flex-1">{label}</span>
        {value && <span className="font-medium shrink-0">{value}</span>}
        {secondary && <span className="font-medium shrink-0">{secondary}</span>}
      </div>
    )
  }
)

ItemCardContentItem.displayName = 'ItemCardContentItem'

// ============================================================================
// Empty State for Content
// ============================================================================

export interface ItemCardEmptyProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Icon to display */
  icon?: React.ReactNode
  /** Message to display */
  message?: string
}

const ItemCardEmpty = React.forwardRef<HTMLDivElement, ItemCardEmptyProps>(
  ({ className, icon, message = 'Nenhum item', children, ...props }, ref) => {
    return (
      <div
        ref={ref}
        className={cn(
          'flex flex-col items-center justify-center py-6 text-center text-muted-foreground',
          className
        )}
        {...props}
      >
        {icon && <div className="mb-2 opacity-50">{icon}</div>}
        {children || <p className="text-sm">{message}</p>}
      </div>
    )
  }
)

ItemCardEmpty.displayName = 'ItemCardEmpty'

export { ItemCardContent, ItemCardContentItem, ItemCardEmpty }
