import * as React from 'react'
import { cn } from '../../utils/cn'
import { useDataTable, useDataTablePagination, useDataTableMeta } from './DataTableContext'
import type { DataTablePaginationProps } from './types'
import { Button } from '../Button'
import { Select, SelectItem } from '../Select'
import { ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight } from 'lucide-react'

// ============================================================================
// PAGINATION COMPONENT - Client e Server-side pagination
// ============================================================================
//
// Client-side (padrão):
// <DataTable.Pagination />
//
// Server-side:
// <DataTable.Pagination mode="server" pageCount={meta.totalPages} />
//
// ============================================================================

export const DataTablePagination = React.memo(function DataTablePagination({
  mode = 'client',
  pageCount: externalPageCount,
  pageSizes = [10, 20, 30, 50],
  showPageSize = true,
  showPageInfo = true,
  showFirstLast = true,
  className,
}: DataTablePaginationProps) {
  const table = useDataTable()
  const { selectedRowCount, totalRows } = useDataTableMeta()
  const paginationHook = useDataTablePagination()
  const {
    pageIndex,
    pageSize,
    pageCount: internalPageCount,
    canPreviousPage,
    canNextPage,
    setPageIndex,
    setPageSize,
    previousPage,
    nextPage,
    firstPage,
    lastPage,
  } = paginationHook

  // Usa pageCount externo para server-side, interno para client-side
  const pageCount = mode === 'server' && externalPageCount !== undefined
    ? externalPageCount
    : internalPageCount

  // Recalcula navegação para server-side
  const canGoPrevious = pageIndex > 0
  const canGoNext = pageIndex < pageCount - 1

  // Handlers
  const handlePageSizeChange = React.useCallback(
    (value: string) => {
      setPageSize(Number(value))
    },
    [setPageSize]
  )

  return (
    <div
      className={cn(
        'flex flex-col-reverse items-center justify-between gap-4 sm:flex-row',
        className
      )}
    >
      {/* Info Section */}
      {showPageInfo && (
        <div className="flex-1 text-sm text-muted-foreground">
          {selectedRowCount > 0 ? (
            <>
              {selectedRowCount} de {totalRows} linha(s) selecionada(s)
            </>
          ) : (
            <>
              Página {pageIndex + 1} de {pageCount}
            </>
          )}
        </div>
      )}

      <div className="flex items-center gap-6">
        {/* Page Size Selector */}
        {showPageSize && (
          <div className="flex items-center gap-2">
            <p className="text-sm font-medium whitespace-nowrap">Linhas por página</p>
            <Select
              value={`${pageSize}`}
              onValueChange={handlePageSizeChange}
              selectSize="sm"
            >
              {[...new Set([pageSize, ...pageSizes])].sort((a, b) => a - b).map((size) => (
                <SelectItem key={size} value={`${size}`}>
                  {size}
                </SelectItem>
              ))}
            </Select>
          </div>
        )}

        {/* Pagination Controls */}
        <div className="flex items-center gap-1">
          {showFirstLast && (
            <Button
              variant="outline"
              size="icon-sm"
              className="hidden h-8 w-8 p-0 lg:flex"
              onClick={firstPage}
              disabled={!canGoPrevious}
              aria-label="Primeira página"
            >
              <ChevronsLeft className="h-4 w-4" />
            </Button>
          )}
          <Button
            variant="outline"
            size="icon-sm"
            className="h-8 w-8 p-0"
            onClick={previousPage}
            disabled={!canGoPrevious}
            aria-label="Página anterior"
          >
            <ChevronLeft className="h-4 w-4" />
          </Button>

          {/* Page indicator */}
          <span className="flex h-8 min-w-[4rem] items-center justify-center text-sm font-medium">
            {pageIndex + 1} / {pageCount}
          </span>

          <Button
            variant="outline"
            size="icon-sm"
            className="h-8 w-8 p-0"
            onClick={nextPage}
            disabled={!canGoNext}
            aria-label="Próxima página"
          >
            <ChevronRight className="h-4 w-4" />
          </Button>
          {showFirstLast && (
            <Button
              variant="outline"
              size="icon-sm"
              className="hidden h-8 w-8 p-0 lg:flex"
              onClick={lastPage}
              disabled={!canGoNext}
              aria-label="Última página"
            >
              <ChevronsRight className="h-4 w-4" />
            </Button>
          )}
        </div>
      </div>
    </div>
  )
})

DataTablePagination.displayName = 'DataTable.Pagination'
