import { cn } from '../../utils/cn'
import type { DataTableColumnHeaderProps } from './types'
import { Button } from '../Button'
import { ArrowDown, ArrowUp, ChevronsUpDown } from 'lucide-react'

// ============================================================================
// COLUMN HEADER COMPONENT - Header com sorting
// ============================================================================

export function DataTableColumnHeader({
  column,
  title,
  className,
}: DataTableColumnHeaderProps) {
  if (!column.getCanSort()) {
    return <div className={cn(className)}>{title}</div>
  }

  const handleSort = () => {
    const currentSort = column.getIsSorted()
    if (currentSort === 'asc') {
      column.toggleSorting(true) // Sort descending
    } else if (currentSort === 'desc') {
      column.clearSorting() // Clear sort
    } else {
      column.toggleSorting(false) // Sort ascending
    }
  }

  return (
    <div className={cn('flex items-center space-x-2', className)}>
      <Button
        variant="ghost"
        size="sm"
        className="-ml-3 h-8 data-[state=open]:bg-accent"
        onClick={handleSort}
      >
        <span>{title}</span>
        {column.getIsSorted() === 'desc' ? (
          <ArrowDown className="ml-2 h-4 w-4" />
        ) : column.getIsSorted() === 'asc' ? (
          <ArrowUp className="ml-2 h-4 w-4" />
        ) : (
          <ChevronsUpDown className="ml-2 h-4 w-4" />
        )}
      </Button>
    </div>
  )
}
