'use client'

import * as React from 'react'
import { cn } from '../../utils/cn'

// ============================================================================
// Footer Container
// ============================================================================

export interface ItemCardFooterProps extends React.HTMLAttributes<HTMLDivElement> {}

const ItemCardFooter = React.forwardRef<HTMLDivElement, ItemCardFooterProps>(
  ({ className, children, ...props }, ref) => {
    return (
      <div
        ref={ref}
        className={cn(
          'px-6 py-3 flex justify-between items-center gap-4',
          className
        )}
        {...props}
      >
        {children}
      </div>
    )
  }
)

ItemCardFooter.displayName = 'ItemCardFooter'

// ============================================================================
// Footer Item (label + value)
// ============================================================================

export interface ItemCardFooterItemProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Small label text */
  label: string
  /** Main value */
  value: React.ReactNode
  /** Alignment */
  align?: 'left' | 'right'
}

const ItemCardFooterItem = React.forwardRef<HTMLDivElement, ItemCardFooterItemProps>(
  ({ className, label, value, align = 'left', ...props }, ref) => {
    return (
      <div
        ref={ref}
        className={cn(
          'flex flex-col',
          align === 'right' && 'items-end',
          className
        )}
        {...props}
      >
        <span className="text-xs text-muted-foreground">{label}</span>
        <span className="font-semibold text-sm text-foreground">{value}</span>
      </div>
    )
  }
)

ItemCardFooterItem.displayName = 'ItemCardFooterItem'

// ============================================================================
// Footer Divider
// ============================================================================

export interface ItemCardFooterDividerProps extends React.HTMLAttributes<HTMLDivElement> {}

const ItemCardFooterDivider = React.forwardRef<HTMLDivElement, ItemCardFooterDividerProps>(
  ({ className, ...props }, ref) => {
    return (
      <div
        ref={ref}
        className={cn('flex-1', className)}
        {...props}
      />
    )
  }
)

ItemCardFooterDivider.displayName = 'ItemCardFooterDivider'

export { ItemCardFooter, ItemCardFooterItem, ItemCardFooterDivider }
