import * as React from 'react'
import { cva, type VariantProps } from 'class-variance-authority'
import { cn } from '../../utils/cn'

const textareaVariants = cva(
  'w-full px-3 pt-4 pb-2 text-sm bg-background rounded-md border-2 transition-colors focus:outline-none focus:ring-0 disabled:cursor-not-allowed disabled:opacity-50 resize-none',
  {
    variants: {
      variant: {
        default: 'border-border focus:border-primary',
        error: 'border-red-500 focus:border-red-600',
      },
      textareaSize: {
        sm: 'min-h-[80px] pt-3 pb-1',
        default: 'min-h-[100px]',
        lg: 'min-h-[120px] pt-5 pb-2',
      },
    },
    defaultVariants: {
      variant: 'default',
      textareaSize: 'default',
    },
  }
)

export interface TextareaProps
  extends Omit<React.TextareaHTMLAttributes<HTMLTextAreaElement>, 'size'>,
    VariantProps<typeof textareaVariants> {
  label?: string
  error?: boolean
  icon?: React.ComponentType<any>
  containerClassName?: string
  labelClassName?: string
  autoResize?: boolean
}

export const Textarea = React.memo(
  React.forwardRef<HTMLTextAreaElement, TextareaProps>(
    (
      {
        className,
        variant,
        textareaSize,
        error,
        label,
        icon: Icon,
        required,
        containerClassName,
        labelClassName,
        autoResize = false,
        onChange,
        ...props
      },
      ref
    ) => {
      const textareaRef = React.useRef<HTMLTextAreaElement | null>(null)

      React.useImperativeHandle(ref, () => textareaRef.current!, [])

      const focusTextarea = React.useCallback(() => {
        textareaRef.current?.focus()
      }, [])

      // Auto-resize functionality
      const handleChange = React.useCallback(
        (e: React.ChangeEvent<HTMLTextAreaElement>) => {
          if (autoResize && textareaRef.current) {
            textareaRef.current.style.height = 'auto'
            textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`
          }
          onChange?.(e)
        },
        [autoResize, onChange]
      )

      // Set initial height for auto-resize
      React.useEffect(() => {
        if (autoResize && textareaRef.current) {
          textareaRef.current.style.height = 'auto'
          textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`
        }
      }, [autoResize])

      return (
        <div className={cn('relative', containerClassName)}>
          {/* Icon */}
          {Icon && (
            <Icon
              className="absolute left-3 top-4 text-muted-foreground h-4 w-4 cursor-pointer z-10"
              onClick={focusTextarea}
            />
          )}

          {/* Textarea */}
          <textarea
            className={cn(
              textareaVariants({
                variant: error ? 'error' : variant,
                textareaSize,
              }),
              Icon && 'pl-10',
              className
            )}
            ref={textareaRef}
            onChange={handleChange}
            {...props}
          />

          {/* Floating Label */}
          {label && (
            <label
              className={cn(
                'absolute left-3 top-[-6px] text-xs font-medium bg-background px-1 cursor-pointer',
                error ? 'text-red-500' : 'text-foreground',
                Icon && 'left-10',
                labelClassName
              )}
              onClick={focusTextarea}
            >
              {label}
              {required && <span className="text-red-500 ml-0.5">*</span>}
            </label>
          )}
        </div>
      )
    }
  )
)

Textarea.displayName = 'Textarea'
