import * as React from 'react'
import { cn } from '../../utils/cn'
import { useDataTable } from './DataTableContext'
import type { DataTableColumnVisibilityProps } from './types'
import { Button } from '../Button'
import { Checkbox } from '../Checkbox'
import { SlidersHorizontal } from 'lucide-react'

// ============================================================================
// COLUMN VISIBILITY COMPONENT - Toggle de colunas visíveis
// ============================================================================
//
// Uso:
// <DataTable.Toolbar>
//   <DataTable.ColumnVisibility />
// </DataTable.Toolbar>
//
// ============================================================================

export function DataTableColumnVisibility({
  className,
}: DataTableColumnVisibilityProps) {
  const table = useDataTable()
  const [open, setOpen] = React.useState(false)
  const dropdownRef = React.useRef<HTMLDivElement>(null)

  // Fecha dropdown ao clicar fora
  React.useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setOpen(false)
      }
    }

    if (open) {
      document.addEventListener('mousedown', handleClickOutside)
      return () => document.removeEventListener('mousedown', handleClickOutside)
    }
  }, [open])

  // Pega apenas colunas que podem ser ocultadas
  const columns = table.getAllColumns().filter((column) => column.getCanHide())

  return (
    <div className={cn('relative', className)} ref={dropdownRef}>
      <Button
        variant="outline"
        size="sm"
        className="h-8"
        onClick={() => setOpen(!open)}
        aria-expanded={open}
        aria-haspopup="true"
      >
        <SlidersHorizontal className="mr-2 h-4 w-4" />
        Colunas
      </Button>

      {open && (
        <div
          className={cn(
            'absolute right-0 top-full z-50 mt-1 w-48',
            'rounded-md border bg-popover p-2 shadow-md',
            'animate-in fade-in-0 zoom-in-95'
          )}
        >
          <div className="px-2 py-1.5 text-sm font-semibold">
            Alternar colunas
          </div>
          <div className="h-px bg-border my-1" />
          <div className="max-h-60 overflow-auto">
            {columns.map((column) => {
              const header = column.columnDef.header
              const title = typeof header === 'string'
                ? header
                : column.id

              return (
                <label
                  key={column.id}
                  className={cn(
                    'flex items-center gap-2 px-2 py-1.5 rounded-sm cursor-pointer',
                    'hover:bg-accent hover:text-accent-foreground',
                    'text-sm'
                  )}
                >
                  <Checkbox
                    checked={column.getIsVisible()}
                    onCheckedChange={(value) => column.toggleVisibility(!!value)}
                  />
                  <span className="capitalize">{title}</span>
                </label>
              )
            })}
          </div>
        </div>
      )}
    </div>
  )
}

DataTableColumnVisibility.displayName = 'DataTable.ColumnVisibility'
