'use client'

import * as React from 'react'
import { cn } from '../../utils/cn'

export interface NumberStepperProps {
  value?: number
  onChange?: (value: number) => void
  onBlur?: () => void
  min?: number
  max?: number
  step?: number
  defaultValue?: number
  label?: string
  required?: boolean
  disabled?: boolean
  error?: boolean
  labelSuffix?: React.ReactNode
  className?: string
  name?: string
}

export const NumberStepper = React.forwardRef<HTMLInputElement, NumberStepperProps>(
  (
    {
      value = 1,
      onChange,
      onBlur,
      min = 0,
      max,
      step = 0.5,
      defaultValue,
      label,
      required,
      disabled,
      error,
      labelSuffix,
      className,
      name,
    },
    ref
  ) => {
    const inputRef = React.useRef<HTMLInputElement | null>(null)
    const [displayValue, setDisplayValue] = React.useState<string>(String(value))
    const [isFocused, setIsFocused] = React.useState(false)

    React.useImperativeHandle(ref, () => inputRef.current!, [])

    // Sync display value when external value changes (buttons, form reset) and input is not focused
    React.useEffect(() => {
      if (!isFocused) {
        setDisplayValue(String(value))
      }
    }, [value, isFocused])

    const canDecrement = value - step >= min
    const canIncrement = max === undefined || value + step <= max

    const handleDecrement = React.useCallback(() => {
      if (!canDecrement || disabled) return
      const newValue = Math.round((value - step) * 1000) / 1000
      onChange?.(newValue)
    }, [value, step, min, disabled, onChange, canDecrement])

    const handleIncrement = React.useCallback(() => {
      if (!canIncrement || disabled) return
      const newValue = Math.round((value + step) * 1000) / 1000
      onChange?.(newValue)
    }, [value, step, max, disabled, onChange, canIncrement])

    const handleInputChange = React.useCallback(
      (e: React.ChangeEvent<HTMLInputElement>) => {
        const raw = e.target.value
        setDisplayValue(raw)

        if (raw === '' || raw === '-' || raw === '.') return

        const parsed = parseFloat(raw)
        if (isNaN(parsed)) return

        onChange?.(parsed)
      },
      [onChange]
    )

    const handleInputFocus = React.useCallback(() => {
      setIsFocused(true)
    }, [])

    const handleInputBlur = React.useCallback(() => {
      setIsFocused(false)
      const parsed = parseFloat(displayValue)

      if (isNaN(parsed) || displayValue === '') {
        const resetValue = defaultValue ?? min
        setDisplayValue(String(resetValue))
        if (value !== resetValue) onChange?.(resetValue)
        onBlur?.()
        return
      }

      // Clamp value on blur
      let clamped = parsed
      if (clamped < min) clamped = min
      if (max !== undefined && clamped > max) clamped = max
      setDisplayValue(String(clamped))
      if (clamped !== value) onChange?.(clamped)
      onBlur?.()
    }, [displayValue, value, min, max, onChange, onBlur])

    return (
      <div className={cn('relative', className)}>
        <div
          className={cn(
            'flex items-center h-12 rounded-md border-2 transition-colors overflow-hidden bg-background',
            error
              ? 'border-red-500 focus-within:border-red-600'
              : 'border-border focus-within:border-primary',
            disabled && 'opacity-50 cursor-not-allowed'
          )}
        >
          {/* Decrement button */}
          <button
            type="button"
            tabIndex={-1}
            onClick={handleDecrement}
            disabled={disabled || !canDecrement}
            className={cn(
              'flex items-center justify-center w-11 h-full transition-colors select-none shrink-0',
              'text-muted-foreground hover:text-foreground hover:bg-muted',
              'disabled:opacity-30 disabled:hover:bg-transparent disabled:hover:text-muted-foreground disabled:cursor-not-allowed'
            )}
            aria-label="Diminuir"
          >
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
              <line x1="5" y1="12" x2="19" y2="12" />
            </svg>
          </button>

          {/* Divider */}
          <div className="w-px h-6 bg-border shrink-0" />

          {/* Input */}
          <input
            ref={inputRef}
            name={name}
            type="text"
            inputMode="decimal"
            value={displayValue}
            onChange={handleInputChange}
            onFocus={handleInputFocus}
            onBlur={handleInputBlur}
            disabled={disabled}
            className={cn(
              'flex-1 min-w-0 h-full text-center text-sm font-medium bg-transparent outline-none',
              'disabled:cursor-not-allowed',
              label ? 'pt-1' : ''
            )}
          />

          {/* Divider */}
          <div className="w-px h-6 bg-border shrink-0" />

          {/* Increment button */}
          <button
            type="button"
            tabIndex={-1}
            onClick={handleIncrement}
            disabled={disabled || !canIncrement}
            className={cn(
              'flex items-center justify-center w-11 h-full transition-colors select-none shrink-0',
              'text-muted-foreground hover:text-foreground hover:bg-muted',
              'disabled:opacity-30 disabled:hover:bg-transparent disabled:hover:text-muted-foreground disabled:cursor-not-allowed'
            )}
            aria-label="Aumentar"
          >
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
              <line x1="12" y1="5" x2="12" y2="19" />
              <line x1="5" y1="12" x2="19" y2="12" />
            </svg>
          </button>
        </div>

        {/* Floating Label */}
        {label && (
          <label
            className={cn(
              'absolute left-3 top-[-6px] text-xs font-medium bg-background px-1 cursor-pointer inline-flex items-center gap-1',
              error ? 'text-red-500' : 'text-foreground'
            )}
            onClick={() => inputRef.current?.focus()}
          >
            {label}
            {required && <span className="text-red-500 ml-0.5">*</span>}
            {labelSuffix}
          </label>
        )}
      </div>
    )
  }
)

NumberStepper.displayName = 'NumberStepper'
