import * as React from 'react'
import { Area, AreaChart, ResponsiveContainer, Tooltip } from 'recharts'
import { cva } from 'class-variance-authority'
import { cn } from '../../utils/cn'

// ============================================================================
// Context
// ============================================================================

type ColorScheme = 'green' | 'red' | 'yellow' | 'blue' | 'primary'
type Variant = 'default' | 'compact' | 'mini'

interface StatsCardContextValue {
  colorScheme: ColorScheme
  variant: Variant
  config: ColorConfig
}

const StatsCardContext = React.createContext<StatsCardContextValue | null>(null)

function useStatsCard() {
  const context = React.useContext(StatsCardContext)
  if (!context) {
    throw new Error('StatsCard components must be used within StatsCard.Root')
  }
  return context
}

// ============================================================================
// Color Configuration
// ============================================================================

interface ColorConfig {
  lineColor: string
  gradientStart: string
  gradientEnd: string
  bgGradient: string
  iconBg: string
  textColor: string
}

const colorConfigs: Record<ColorScheme, ColorConfig> = {
  green: {
    lineColor: '#22c55e',
    gradientStart: 'rgba(34, 197, 94, 0.4)',
    gradientEnd: 'rgba(34, 197, 94, 0.02)',
    bgGradient: 'from-white via-emerald-50/30 to-emerald-100/50',
    iconBg: 'bg-emerald-100/80 text-emerald-600',
    textColor: 'text-emerald-500',
  },
  red: {
    lineColor: '#f87171',
    gradientStart: 'rgba(248, 113, 113, 0.4)',
    gradientEnd: 'rgba(248, 113, 113, 0.02)',
    bgGradient: 'from-white via-rose-50/30 to-rose-100/50',
    iconBg: 'bg-rose-100/80 text-rose-500',
    textColor: 'text-rose-500',
  },
  yellow: {
    lineColor: '#f59e0b',
    gradientStart: 'rgba(245, 158, 11, 0.4)',
    gradientEnd: 'rgba(245, 158, 11, 0.02)',
    bgGradient: 'from-white via-amber-50/30 to-amber-100/50',
    iconBg: 'bg-amber-100/80 text-amber-600',
    textColor: 'text-amber-500',
  },
  blue: {
    lineColor: '#3b82f6',
    gradientStart: 'rgba(59, 130, 246, 0.4)',
    gradientEnd: 'rgba(59, 130, 246, 0.02)',
    bgGradient: 'from-white via-blue-50/30 to-blue-100/50',
    iconBg: 'bg-blue-100/80 text-blue-600',
    textColor: 'text-blue-500',
  },
  primary: {
    lineColor: '#3b82f6',
    gradientStart: 'rgba(59, 130, 246, 0.4)',
    gradientEnd: 'rgba(59, 130, 246, 0.02)',
    bgGradient: 'from-white via-primary/5 to-primary/10',
    iconBg: 'bg-primary/10 text-primary',
    textColor: 'text-primary',
  },
}

// ============================================================================
// Root Component
// ============================================================================

const rootVariants = cva(
  'relative overflow-hidden bg-card shadow-sm border border-border',
  {
    variants: {
      variant: {
        default: 'rounded-2xl h-full',
        compact: 'rounded-xl h-full',
        mini: 'rounded-xl w-fit',
      },
    },
    defaultVariants: {
      variant: 'default',
    },
  }
)

interface StatsCardRootProps extends React.HTMLAttributes<HTMLDivElement> {
  colorScheme?: ColorScheme
  variant?: Variant
}

function StatsCardRoot({
  colorScheme = 'blue',
  variant = 'default',
  className,
  children,
  ...props
}: StatsCardRootProps) {
  const config = colorConfigs[colorScheme]

  return (
    <StatsCardContext.Provider value={{ colorScheme, variant, config }}>
      <div className={cn(rootVariants({ variant }), className)} {...props}>
        <div className={cn('absolute inset-0 bg-gradient-to-br pointer-events-none', config.bgGradient)} />
        <div className={cn(
          'relative flex h-full',
          variant === 'default' && 'flex-col',
          variant === 'compact' && 'flex-row items-center p-3 gap-3',
          variant === 'mini' && 'flex-row items-center p-3 gap-3'
        )}>
          {children}
        </div>
      </div>
    </StatsCardContext.Provider>
  )
}

// ============================================================================
// Header Component
// ============================================================================

interface StatsCardHeaderProps extends React.HTMLAttributes<HTMLDivElement> {}

function StatsCardHeader({ className, children, ...props }: StatsCardHeaderProps) {
  const { variant } = useStatsCard()

  return (
    <div
      className={cn(
        'flex items-center justify-between',
        variant === 'default' && 'p-4 pb-2',
        (variant === 'compact' || variant === 'mini') && 'flex-1 min-w-0',
        className
      )}
      {...props}
    >
      {children}
    </div>
  )
}

// ============================================================================
// Icon Component
// ============================================================================

interface StatsCardIconProps extends React.HTMLAttributes<HTMLDivElement> {
  icon: React.ComponentType<{ className?: string }>
}

function StatsCardIcon({ icon: Icon, className, ...props }: StatsCardIconProps) {
  const { config } = useStatsCard()

  return (
    <div
      className={cn(
        'rounded-lg p-2',
        config.iconBg,
        className
      )}
      {...props}
    >
      <Icon className="w-4 h-4" />
    </div>
  )
}

// ============================================================================
// Title Component
// ============================================================================

interface StatsCardTitleProps extends React.HTMLAttributes<HTMLHeadingElement> {}

function StatsCardTitle({ className, children, ...props }: StatsCardTitleProps) {
  return (
    <h3
      className={cn(
        'font-medium text-gray-700 text-sm',
        className
      )}
      {...props}
    >
      {children}
    </h3>
  )
}

// ============================================================================
// Subtitle Component
// ============================================================================

interface StatsCardSubtitleProps extends React.HTMLAttributes<HTMLParagraphElement> {}

function StatsCardSubtitle({ className, children, ...props }: StatsCardSubtitleProps) {
  return (
    <p
      className={cn(
        'text-gray-400 text-[10px]',
        className
      )}
      {...props}
    >
      {children}
    </p>
  )
}

// ============================================================================
// Value Component
// ============================================================================

interface StatsCardValueProps extends React.HTMLAttributes<HTMLParagraphElement> {}

function StatsCardValue({ className, children, ...props }: StatsCardValueProps) {
  const { variant } = useStatsCard()

  return (
    <p
      className={cn(
        'font-light tracking-tight text-gray-900',
        variant === 'default' && 'text-4xl',
        (variant === 'compact' || variant === 'mini') && 'text-2xl',
        className
      )}
      {...props}
    >
      {children}
    </p>
  )
}

// ============================================================================
// Change Indicator Component
// ============================================================================

interface StatsCardChangeProps extends React.HTMLAttributes<HTMLDivElement> {
  type?: 'positive' | 'negative'
}

function StatsCardChange({ type = 'positive', className, children, ...props }: StatsCardChangeProps) {
  const { config } = useStatsCard()

  return (
    <div className={cn('flex items-center gap-0.5', className)} {...props}>
      <svg
        className={cn('w-2.5 h-2.5', config.textColor)}
        viewBox="0 0 12 12"
        fill="currentColor"
      >
        <path d={type === 'negative' ? 'M6 10L10 5H2L6 10Z' : 'M6 2L10 7H2L6 2Z'} />
      </svg>
      <span className={cn(
        'font-medium text-[10px]',
        config.textColor
      )}>
        {children}
      </span>
    </div>
  )
}

// ============================================================================
// Chart Component
// ============================================================================

interface ChartDataPoint {
  value: number
  date: string
}

interface StatsCardChartProps extends React.HTMLAttributes<HTMLDivElement> {
  data: ChartDataPoint[]
  height?: number
}

function StatsCardChart({ data, height, className, ...props }: StatsCardChartProps) {
  const { config, variant } = useStatsCard()
  const gradientId = React.useId()

  // Mini variant doesn't show chart
  if (variant === 'mini') {
    return null
  }

  const chartHeight = height ?? (variant === 'compact' ? 40 : 70)

  return (
    <div
      className={cn(
        variant === 'compact' && 'w-16 h-10 shrink-0',
        variant === 'default' && 'flex-1 relative mt-auto',
        className
      )}
      {...props}
    >
      <ResponsiveContainer width="100%" height={chartHeight}>
        <AreaChart data={data} margin={{ top: 2, right: 0, left: 0, bottom: 0 }}>
          <defs>
            <linearGradient id={gradientId} x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor={config.gradientStart} />
              <stop offset="100%" stopColor={config.gradientEnd} />
            </linearGradient>
          </defs>
          <Tooltip
            content={({ active, payload }) => {
              if (active && payload && payload.length) {
                const point = payload[0].payload as ChartDataPoint
                return (
                  <div className="bg-white/95 backdrop-blur-sm rounded-lg px-2 py-1.5 shadow-lg border border-gray-100">
                    <p className="text-[10px] font-medium text-gray-700">{point.value}</p>
                    <p className="text-[9px] text-gray-400">{point.date}</p>
                  </div>
                )
              }
              return null
            }}
          />
          <Area
            type="monotone"
            dataKey="value"
            stroke={config.lineColor}
            strokeWidth={1.5}
            fill={`url(#${gradientId})`}
            dot={false}
            activeDot={{
              r: 3,
              fill: config.lineColor,
              stroke: 'white',
              strokeWidth: 2,
            }}
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  )
}

// ============================================================================
// Content Component (wrapper for flexible content)
// ============================================================================

interface StatsCardContentProps extends React.HTMLAttributes<HTMLDivElement> {}

function StatsCardContent({ className, children, ...props }: StatsCardContentProps) {
  const { variant } = useStatsCard()

  return (
    <div
      className={cn(
        variant === 'default' && 'mt-2',
        className
      )}
      {...props}
    >
      {children}
    </div>
  )
}

// ============================================================================
// Today Value Component
// ============================================================================

interface StatsCardTodayProps extends React.HTMLAttributes<HTMLParagraphElement> {
  label?: string
  type?: 'positive' | 'negative'
}

function StatsCardToday({ label, type = 'positive', className, children, ...props }: StatsCardTodayProps) {
  const { config } = useStatsCard()

  return (
    <p className={cn('text-xs mt-0.5', className)} {...props}>
      <span className={config.textColor}>
        {type === 'positive' ? '+' : ''}{children}
      </span>
      {label && <span className="text-gray-500 ml-1">{label}</span>}
    </p>
  )
}

// ============================================================================
// Compound Component Export
// ============================================================================

export const StatsCard = Object.assign(StatsCardRoot, {
  Header: StatsCardHeader,
  Icon: StatsCardIcon,
  Title: StatsCardTitle,
  Subtitle: StatsCardSubtitle,
  Value: StatsCardValue,
  Change: StatsCardChange,
  Chart: StatsCardChart,
  Content: StatsCardContent,
  Today: StatsCardToday,
})

// Export types
export type {
  StatsCardRootProps,
  StatsCardHeaderProps,
  StatsCardIconProps,
  StatsCardTitleProps,
  StatsCardSubtitleProps,
  StatsCardValueProps,
  StatsCardChangeProps,
  StatsCardChartProps,
  StatsCardContentProps,
  StatsCardTodayProps,
  ChartDataPoint,
  ColorScheme as StatsCardColorScheme,
  Variant as StatsCardVariant,
}
