'use client';

import { cn } from '../../utils/cn';
import { useWizardContext } from './WizardContext';
import type { WizardProgressProps } from './types';

/**
 * Progress bar component for the wizard
 *
 * Displays a visual progress indicator with optional percentage and step count
 *
 * @example
 * ```tsx
 * <Wizard.Progress showPercentage showStepCount />
 * ```
 */
export function WizardProgress({
  showPercentage = false,
  showStepCount = false,
  className,
}: WizardProgressProps) {
  const { progress, currentStep, totalSteps } = useWizardContext();

  return (
    <div className={cn('w-full', className)}>
      {/* Text indicators */}
      {(showPercentage || showStepCount) && (
        <div className="flex items-center justify-between mb-2 text-sm text-muted-foreground">
          {showStepCount && (
            <span>
              Etapa {currentStep + 1} de {totalSteps}
            </span>
          )}
          {showPercentage && (
            <span className={!showStepCount ? 'ml-auto' : ''}>
              {progress}%
            </span>
          )}
        </div>
      )}

      {/* Progress bar */}
      <div
        className="h-2 w-full bg-muted rounded-full overflow-hidden"
        role="progressbar"
        aria-valuenow={progress}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label={`Progresso: ${progress}%`}
      >
        <div
          className="h-full bg-primary transition-all duration-300 ease-out rounded-full"
          style={{ width: `${progress}%` }}
        />
      </div>
    </div>
  );
}
