import * as React from 'react'
import { cn } from '../../utils/cn'
import { useDataTableDensity } from './DataTableContext'
import type { DataTableDensityToggleProps, DataTableDensity } from './types'
import { Button } from '../Button'
import { LayoutList, Rows3, Rows4 } from 'lucide-react'

// ============================================================================
// DENSITY TOGGLE COMPONENT - Compact/Default/Comfortable
// ============================================================================
//
// Uso:
// <DataTable.Toolbar>
//   <DataTable.DensityToggle />
// </DataTable.Toolbar>
//
// ============================================================================

const densityOptions: Array<{
  value: DataTableDensity
  label: string
  icon: React.ElementType
}> = [
  { value: 'compact', label: 'Compacto', icon: Rows4 },
  { value: 'default', label: 'Padrão', icon: Rows3 },
  { value: 'comfortable', label: 'Confortável', icon: LayoutList },
]

export function DataTableDensityToggle({
  className,
}: DataTableDensityToggleProps) {
  const { density, setDensity } = useDataTableDensity()
  const [open, setOpen] = React.useState(false)
  const dropdownRef = React.useRef<HTMLDivElement>(null)

  // Fecha dropdown ao clicar fora
  React.useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setOpen(false)
      }
    }

    if (open) {
      document.addEventListener('mousedown', handleClickOutside)
      return () => document.removeEventListener('mousedown', handleClickOutside)
    }
  }, [open])

  const currentOption = densityOptions.find((opt) => opt.value === density) ?? densityOptions[1]
  const Icon = currentOption.icon

  return (
    <div className={cn('relative', className)} ref={dropdownRef}>
      <Button
        variant="outline"
        size="sm"
        className="h-8"
        onClick={() => setOpen(!open)}
        aria-expanded={open}
        aria-haspopup="true"
      >
        <Icon className="mr-2 h-4 w-4" />
        Densidade
      </Button>

      {open && (
        <div
          className={cn(
            'absolute right-0 top-full z-50 mt-1 w-40',
            'rounded-md border bg-popover p-1 shadow-md',
            'animate-in fade-in-0 zoom-in-95'
          )}
        >
          {densityOptions.map((option) => {
            const OptionIcon = option.icon
            const isSelected = density === option.value

            return (
              <button
                key={option.value}
                className={cn(
                  'flex w-full items-center gap-2 px-2 py-1.5 rounded-sm cursor-pointer',
                  'hover:bg-accent hover:text-accent-foreground',
                  'text-sm text-left',
                  isSelected && 'bg-accent'
                )}
                onClick={() => {
                  setDensity(option.value)
                  setOpen(false)
                }}
              >
                <OptionIcon className="h-4 w-4" />
                <span>{option.label}</span>
                {isSelected && (
                  <span className="ml-auto text-xs text-muted-foreground">✓</span>
                )}
              </button>
            )
          })}
        </div>
      )}
    </div>
  )
}

DataTableDensityToggle.displayName = 'DataTable.DensityToggle'
