import * as React from 'react'
import type { Table } from '@tanstack/react-table'
import type { DataTableMeta, DataTableDensity } from './types'

// ============================================================================
// SPLIT CONTEXTS - Performance otimizada
// Cada contexto tem frequência de mudança diferente
// ============================================================================

/**
 * Context 0: Loading State
 * - Setado pelo DataTable.Loading
 * - Lido pelo DataTableContent para renderizar skeleton rows dentro da tabela
 */
const DataTableLoadingContext = React.createContext<{
  isLoading: boolean
  setIsLoading: (loading: boolean) => void
  skeletonRows: number
  setSkeletonRows: (rows: number) => void
} | null>(null)

/**
 * Context 0b: Empty State Config
 * - Setado pelo DataTable.EmptyState
 * - Lido pelo DataTableContent para renderizar o EmptyState bonito
 */
export interface EmptyStateConfig {
  title?: string
  description?: string
  icon?: React.ComponentType<any>
  action?: React.ReactNode
}

const DataTableEmptyStateConfigContext = React.createContext<{
  config: EmptyStateConfig
  setConfig: (config: EmptyStateConfig) => void
} | null>(null)

/**
 * Context 1: Table Instance
 * - Nunca muda após criação (referência estável)
 * - Não causa re-renders nos consumers
 *
 * Nota: Usamos `object` como constraint base para aceitar interfaces TypeScript.
 */
const DataTableInstanceContext = React.createContext<Table<object> | null>(null)
DataTableInstanceContext.displayName = 'DataTableInstanceContext'

/**
 * Context 2: Meta State
 * - Muda com loading, empty, selection count
 * - Consumers que precisam desses dados vão re-renderizar
 */
const DataTableMetaContext = React.createContext<DataTableMeta | null>(null)
DataTableMetaContext.displayName = 'DataTableMetaContext'

/**
 * Context 3: Density
 * - Muda apenas quando usuário altera densidade
 * - Separado para não re-renderizar toda tabela
 */
interface DensityContextValue {
  density: DataTableDensity
  setDensity: (density: DataTableDensity) => void
}
const DataTableDensityContext = React.createContext<DensityContextValue | null>(null)
DataTableDensityContext.displayName = 'DataTableDensityContext'

/**
 * Context 4: Pagination State
 * - Muda quando usuário navega entre páginas ou muda pageSize
 * - Separado para permitir subscriptions reativas
 */
interface PaginationContextValue {
  pageIndex: number
  pageSize: number
}
const DataTablePaginationContext = React.createContext<PaginationContextValue | null>(null)
DataTablePaginationContext.displayName = 'DataTablePaginationContext'

// ============================================================================
// PROVIDER - Generic para type-safety
// ============================================================================

interface DataTableProviderProps<TData extends object> {
  children: React.ReactNode
  table: Table<TData>
  meta: DataTableMeta
  density: DataTableDensity
  setDensity: (density: DataTableDensity) => void
  pageIndex: number
  pageSize: number
}

export function DataTableProvider<TData extends object>({
  children,
  table,
  meta,
  density,
  setDensity,
  pageIndex,
  pageSize,
}: DataTableProviderProps<TData>) {
  // Loading state - setado pelo DataTable.Loading
  const [isLoading, setIsLoading] = React.useState(false)
  const [skeletonRows, setSkeletonRows] = React.useState(5)
  const loadingValue = React.useMemo(
    () => ({ isLoading, setIsLoading, skeletonRows, setSkeletonRows }),
    [isLoading, skeletonRows]
  )

  // Empty state config - setado pelo DataTable.EmptyState
  const [emptyStateConfig, setEmptyStateConfig] = React.useState<EmptyStateConfig>({})
  const emptyStateValue = React.useMemo(
    () => ({ config: emptyStateConfig, setConfig: setEmptyStateConfig }),
    [emptyStateConfig]
  )

  // Memoizar meta para evitar re-renders desnecessários
  const metaValue = React.useMemo(
    () => meta,
    [meta.isLoading, meta.isEmpty, meta.selectedRowCount, meta.totalRows, meta.density]
  )

  // Memoizar density context
  const densityValue = React.useMemo(
    () => ({ density, setDensity }),
    [density, setDensity]
  )

  // Memoizar pagination context - muda quando página ou tamanho muda
  const paginationValue = React.useMemo(
    () => ({ pageIndex, pageSize }),
    [pageIndex, pageSize]
  )

  // Cast seguro: TData extends object
  // O context armazena como base type, hooks fazem o cast de volta
  const tableValue = table as unknown as Table<object>

  return (
    <DataTableLoadingContext.Provider value={loadingValue}>
      <DataTableEmptyStateConfigContext.Provider value={emptyStateValue}>
        <DataTableInstanceContext.Provider value={tableValue}>
          <DataTableMetaContext.Provider value={metaValue}>
            <DataTableDensityContext.Provider value={densityValue}>
              <DataTablePaginationContext.Provider value={paginationValue}>
                {children}
              </DataTablePaginationContext.Provider>
            </DataTableDensityContext.Provider>
          </DataTableMetaContext.Provider>
        </DataTableInstanceContext.Provider>
      </DataTableEmptyStateConfigContext.Provider>
    </DataTableLoadingContext.Provider>
  )
}

// ============================================================================
// HOOKS - Acesso otimizado aos contexts
// ============================================================================

/**
 * Hook para acessar a instância da tabela
 * Não causa re-renders pois a instância é estável
 */
export function useDataTable<TData = unknown>(): Table<TData> {
  const context = React.useContext(DataTableInstanceContext)

  if (!context) {
    throw new Error(
      'useDataTable must be used within <DataTable>. ' +
      'Make sure your component is wrapped with DataTable.'
    )
  }

  return context as unknown as Table<TData>
}

/**
 * Hook para acessar o estado meta da tabela
 * Re-renderiza quando loading, empty, ou selection muda
 */
export function useDataTableMeta(): DataTableMeta {
  const context = React.useContext(DataTableMetaContext)

  if (!context) {
    throw new Error(
      'useDataTableMeta must be used within <DataTable>. ' +
      'Make sure your component is wrapped with DataTable.'
    )
  }

  return context
}

/**
 * Hook para acessar apenas o loading state
 * Otimizado para componentes que só precisam saber se está carregando
 */
export function useDataTableLoading(): boolean {
  const meta = useDataTableMeta()
  return meta.isLoading
}

/**
 * Hook para acessar apenas o empty state
 * Otimizado para componentes que só precisam saber se está vazio
 */
export function useDataTableEmpty(): boolean {
  const meta = useDataTableMeta()
  return meta.isEmpty
}

/**
 * Hook para acessar rows selecionadas
 * Re-renderiza quando seleção muda
 */
export function useDataTableSelection<TData = unknown>(): TData[] {
  const table = useDataTable<TData>()

  return React.useMemo(() => {
    return table.getSelectedRowModel().rows.map((row) => row.original)
  }, [table.getSelectedRowModel().rows])
}

/**
 * Hook para acessar densidade
 * Separado para não re-renderizar componentes que não usam
 */
export function useDataTableDensity(): DensityContextValue {
  const context = React.useContext(DataTableDensityContext)

  if (!context) {
    throw new Error(
      'useDataTableDensity must be used within <DataTable>. ' +
      'Make sure your component is wrapped with DataTable.'
    )
  }

  return context
}

/**
 * Hook para acessar estado de paginação do contexto
 * Re-renderiza quando pageIndex ou pageSize muda
 */
function useDataTablePaginationContext(): PaginationContextValue {
  const context = React.useContext(DataTablePaginationContext)

  if (!context) {
    throw new Error(
      'useDataTablePagination must be used within <DataTable>. ' +
      'Make sure your component is wrapped with DataTable.'
    )
  }

  return context
}

/**
 * Hook para paginação
 * Retorna informações de paginação memoizadas
 * Re-renderiza quando pageIndex ou pageSize muda (via contexto)
 */
export function useDataTablePagination() {
  const table = useDataTable()
  // Usar contexto para garantir re-render quando paginação muda
  const { pageIndex, pageSize } = useDataTablePaginationContext()

  return React.useMemo(() => {
    const pageCount = table.getPageCount()

    return {
      pageIndex,
      pageSize,
      pageCount,
      canPreviousPage: pageIndex > 0,
      canNextPage: pageIndex < pageCount - 1,
      setPageIndex: (index: number) => table.setPageIndex(index),
      setPageSize: (size: number) => table.setPageSize(size),
      previousPage: () => table.previousPage(),
      nextPage: () => table.nextPage(),
      firstPage: () => table.setPageIndex(0),
      lastPage: () => table.setPageIndex(pageCount - 1),
    }
  }, [table, pageIndex, pageSize])
}

/**
 * Hook para sorting
 * Retorna informações de sorting memoizadas
 */
export function useDataTableSorting() {
  const table = useDataTable()
  const sorting = table.getState().sorting

  return React.useMemo(() => ({
    sorting,
    setSorting: table.setSorting,
    clearSorting: () => table.resetSorting(),
    toggleSort: (columnId: string) => {
      const column = table.getColumn(columnId)
      column?.toggleSorting()
    },
  }), [table, sorting])
}

/**
 * Hook para column visibility
 * Retorna informações de visibilidade memoizadas
 */
export function useDataTableColumnVisibility() {
  const table = useDataTable()
  const columnVisibility = table.getState().columnVisibility

  return React.useMemo(() => ({
    columnVisibility,
    setColumnVisibility: table.setColumnVisibility,
    toggleColumn: (columnId: string) => {
      const column = table.getColumn(columnId)
      column?.toggleVisibility()
    },
    getAllColumns: () => table.getAllColumns().filter((col) => col.getCanHide()),
  }), [table, columnVisibility])
}

/**
 * Hook para acessar loading state do contexto
 * Usado internamente pelo DataTable.Loading e DataTableContent
 */
export function useDataTableLoadingState() {
  const context = React.useContext(DataTableLoadingContext)

  if (!context) {
    throw new Error(
      'useDataTableLoadingState must be used within <DataTable>.'
    )
  }

  return context
}

/**
 * Hook para acessar config do empty state
 * Usado internamente pelo DataTableContent e DataTable.EmptyState
 */
export function useDataTableEmptyStateConfig() {
  const context = React.useContext(DataTableEmptyStateConfigContext)

  if (!context) {
    throw new Error(
      'useDataTableEmptyStateConfig must be used within <DataTable>.'
    )
  }

  return context
}

// ============================================================================
// RE-EXPORTS para compatibilidade
// ============================================================================

// Alias para manter compatibilidade com código existente
export const useDataTableInstance = useDataTable
export const useDataTableState = useDataTableMeta
