'use client';

import type { FieldValues } from 'react-hook-form';
import { FormProvider } from 'react-hook-form';
import { cn } from '../../utils/cn';
import { WizardProvider } from './WizardContext';
import type { WizardProps } from './types';

// Import child components for compound component pattern
import { WizardSteps } from './WizardSteps';
import { WizardContent } from './WizardContent';
import { WizardPanel } from './WizardPanel';
import { WizardNavigation } from './WizardNavigation';
import { WizardProgress } from './WizardProgress';

/**
 * Root Wizard component
 *
 * Provides multi-step form functionality with:
 * - Per-step validation with Zod schemas
 * - Visual step indicators
 * - Navigation controls
 * - Progress tracking
 *
 * @example
 * ```tsx
 * const form = useForm<FormData>({
 *   resolver: zodResolver(schema),
 *   mode: 'onTouched',
 * });
 *
 * <Wizard form={form} steps={steps} onComplete={handleSubmit}>
 *   <Wizard.Steps />
 *   <Wizard.Content>
 *     <Wizard.Panel name="step1">...</Wizard.Panel>
 *     <Wizard.Panel name="step2">...</Wizard.Panel>
 *   </Wizard.Content>
 *   <Wizard.Navigation onCancel={handleClose} />
 * </Wizard>
 * ```
 */
function WizardRoot<T extends FieldValues>({
  children,
  form,
  steps,
  initialStep,
  onStepChange,
  onComplete,
  validateOnNext = true,
  allowJumpToStep = false,
  className,
}: WizardProps<T>) {
  /**
   * Handle form submission on the last step
   */
  const handleSubmit = async (data: T) => {
    if (onComplete) {
      await onComplete(data);
    }
  };

  return (
    <WizardProvider
      form={form}
      steps={steps}
      initialStep={initialStep}
      onStepChange={onStepChange}
      onComplete={onComplete}
      validateOnNext={validateOnNext}
      allowJumpToStep={allowJumpToStep}
    >
      <FormProvider {...form}>
        <form
          onSubmit={form.handleSubmit(handleSubmit)}
          className={cn('flex flex-col', className)}
          noValidate
        >
          {children}
        </form>
      </FormProvider>
    </WizardProvider>
  );
}

// Create compound component
export const Wizard = Object.assign(WizardRoot, {
  /** Visual step indicators */
  Steps: WizardSteps,
  /** Container for step panels */
  Content: WizardContent,
  /** Individual step content panel */
  Panel: WizardPanel,
  /** Navigation buttons (prev, next, submit) */
  Navigation: WizardNavigation,
  /** Progress bar indicator */
  Progress: WizardProgress,
});

export type { WizardProps };
