import * as React from 'react'
import {
  ChevronDown,
  ChevronRight,
  Menu,
  X,
  Pin,
  PinOff,
  LogOut,
  User,
} from 'lucide-react'
import { cn } from '../../../utils/cn'
import type {
  DashboardLayoutProps,
  DashboardLayoutContextValue,
  DashboardLayoutSidebarProps,
  DashboardLayoutSidebarHeaderProps,
  DashboardLayoutSidebarNavProps,
  DashboardLayoutSidebarNavItemProps,
  DashboardLayoutSidebarNavGroupProps,
  DashboardLayoutSidebarSectionProps,
  DashboardLayoutSidebarFooterProps,
  DashboardLayoutHeaderProps,
  DashboardLayoutHeaderTitleProps,
  DashboardLayoutHeaderActionsProps,
  DashboardLayoutHeaderUserProps,
  DashboardLayoutContentProps,
  DashboardLayoutBreadcrumbsProps,
  DashboardLayoutMobileNavProps,
  DashboardLayoutMobileNavItemProps,
} from './types'

// ============================================================================
// Context
// ============================================================================
const DashboardLayoutContext = React.createContext<DashboardLayoutContextValue | null>(null)

export function useDashboardLayout() {
  const context = React.useContext(DashboardLayoutContext)
  if (!context) {
    throw new Error('useDashboardLayout must be used within DashboardLayout')
  }
  return context
}

// Hook for media query
function useMediaQuery(query: string): boolean {
  const [matches, setMatches] = React.useState(false)

  React.useEffect(() => {
    const media = window.matchMedia(query)
    if (media.matches !== matches) {
      setMatches(media.matches)
    }
    const listener = () => setMatches(media.matches)
    media.addEventListener('change', listener)
    return () => media.removeEventListener('change', listener)
  }, [matches, query])

  return matches
}

// ============================================================================
// DashboardLayout Root
// ============================================================================
function DashboardLayoutRoot({
  children,
  className,
  defaultExpanded = false,
  defaultPinned = false,
}: DashboardLayoutProps) {
  // When pinned, sidebar should also be expanded
  const [sidebarExpanded, setSidebarExpanded] = React.useState(defaultExpanded || defaultPinned)
  const [sidebarPinned, setSidebarPinned] = React.useState(defaultPinned)
  const [mobileMenuOpen, setMobileMenuOpen] = React.useState(false)
  const isMobile = useMediaQuery('(max-width: 1024px)')

  // Close mobile menu when switching to desktop
  React.useEffect(() => {
    if (!isMobile) {
      setMobileMenuOpen(false)
    }
  }, [isMobile])

  const value: DashboardLayoutContextValue = {
    sidebarExpanded,
    setSidebarExpanded,
    sidebarPinned,
    setSidebarPinned,
    isMobile,
    mobileMenuOpen,
    setMobileMenuOpen,
  }

  return (
    <DashboardLayoutContext.Provider value={value}>
      <div className={cn('min-h-screen bg-muted/30 flex', className)}>
        {children}
      </div>
    </DashboardLayoutContext.Provider>
  )
}

// ============================================================================
// Sidebar
// ============================================================================
function DashboardLayoutSidebar({
  children,
  className,
  collapsedWidth = 64,
  expandedWidth = 256,
}: DashboardLayoutSidebarProps) {
  const {
    sidebarExpanded,
    setSidebarExpanded,
    sidebarPinned,
    isMobile,
    mobileMenuOpen,
    setMobileMenuOpen,
  } = useDashboardLayout()

  const handleMouseEnter = () => {
    if (!sidebarPinned && !isMobile) {
      setSidebarExpanded(true)
    }
  }

  const handleMouseLeave = () => {
    if (!sidebarPinned && !isMobile) {
      setSidebarExpanded(false)
    }
  }

  // Mobile overlay
  if (isMobile) {
    return (
      <>
        {/* Overlay */}
        {mobileMenuOpen && (
          <div
            className="fixed inset-0 bg-black/50 z-40 lg:hidden"
            onClick={() => setMobileMenuOpen(false)}
          />
        )}

        {/* Mobile Sidebar */}
        <aside
          className={cn(
            'fixed top-0 left-0 h-full bg-card z-50 shadow-xl',
            'transform transition-transform duration-300 ease-in-out',
            mobileMenuOpen ? 'translate-x-0' : '-translate-x-full',
            'w-[280px]',
            className
          )}
        >
          <div className="flex flex-col h-full">
            {/* Close button */}
            <button
              onClick={() => setMobileMenuOpen(false)}
              className="absolute top-4 right-4 p-2 hover:bg-muted rounded-md"
            >
              <X className="w-5 h-5" />
            </button>
            {children}
          </div>
        </aside>
      </>
    )
  }

  // Desktop Sidebar
  return (
    <aside
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      style={{
        width: sidebarExpanded ? expandedWidth : collapsedWidth,
      }}
      className={cn(
        'fixed top-0 left-0 h-screen bg-card z-40',
        'flex flex-col shadow-[0_0_20px_rgba(0,0,0,0.06)]',
        'transition-[width] duration-300 ease-in-out',
        className
      )}
    >
      {children}
    </aside>
  )
}

// ============================================================================
// Sidebar Header
// ============================================================================
function DashboardLayoutSidebarHeader({
  children,
  className,
  logo,
  collapsedLogo,
  title,
}: DashboardLayoutSidebarHeaderProps) {
  const { sidebarExpanded, sidebarPinned, setSidebarPinned, isMobile } = useDashboardLayout()

  if (children) {
    return (
      <div className={cn('p-4 border-b border-border', className)}>
        {children}
      </div>
    )
  }

  return (
    <div className={cn('p-4 border-b border-border', className)}>
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3 min-w-0">
          {/* Logo */}
          <div className="flex-shrink-0">
            {sidebarExpanded ? logo : (collapsedLogo || logo)}
          </div>

          {/* Title */}
          {sidebarExpanded && title && (
            <span className="font-semibold text-lg truncate">{title}</span>
          )}
        </div>

        {/* Pin button (desktop only) */}
        {sidebarExpanded && !isMobile && (
          <button
            onClick={() => setSidebarPinned(!sidebarPinned)}
            className="p-1.5 hover:bg-muted rounded-md transition-colors"
            title={sidebarPinned ? 'Unpin sidebar' : 'Pin sidebar'}
          >
            {sidebarPinned ? (
              <PinOff className="w-4 h-4 text-muted-foreground" />
            ) : (
              <Pin className="w-4 h-4 text-muted-foreground" />
            )}
          </button>
        )}
      </div>
    </div>
  )
}

// ============================================================================
// Sidebar Nav
// ============================================================================
function DashboardLayoutSidebarNav({ children, className }: DashboardLayoutSidebarNavProps) {
  return (
    <nav className={cn('flex-1 overflow-y-auto overflow-x-hidden py-2', className)}>
      {children}
    </nav>
  )
}

// ============================================================================
// Sidebar Nav Item
// ============================================================================
function DashboardLayoutSidebarNavItem({
  icon,
  label,
  href,
  onClick,
  isActive,
  badge,
  badgeVariant = 'default',
  className,
  disabled,
}: DashboardLayoutSidebarNavItemProps) {
  const { sidebarExpanded } = useDashboardLayout()

  const badgeColors = {
    default: 'bg-muted text-muted-foreground',
    primary: 'bg-primary/10 text-primary',
    destructive: 'bg-destructive/10 text-destructive',
  }

  // Render icon - handles both LucideIcon components and ReactNode elements
  const renderIcon = () => {
    if (!icon) return null
    // Already a React element
    if (React.isValidElement(icon)) {
      return icon
    }
    // Function component or forwardRef component (Lucide icons)
    if (typeof icon === 'function' || (typeof icon === 'object' && '$$typeof' in icon)) {
      const IconComponent = icon as React.ComponentType<{ className?: string }>
      return <IconComponent className="w-5 h-5 flex-shrink-0" />
    }
    return null
  }

  const content = (
    <div
      className={cn(
        'flex items-center gap-3 px-3 py-2.5 mx-2 rounded-md transition-colors',
        'hover:bg-muted cursor-pointer',
        isActive && 'bg-primary/10 text-primary hover:bg-primary/15',
        disabled && 'opacity-50 cursor-not-allowed pointer-events-none',
        className
      )}
      onClick={disabled ? undefined : onClick}
    >
      {renderIcon()}

      {sidebarExpanded && (
        <>
          <span className="flex-1 truncate text-sm">{label}</span>
          {badge !== undefined && (
            <span
              className={cn(
                'text-xs px-2 py-0.5 rounded-full',
                badgeColors[badgeVariant]
              )}
            >
              {badge}
            </span>
          )}
        </>
      )}

      {/* Badge dot when collapsed */}
      {!sidebarExpanded && badge !== undefined && (
        <span className="absolute top-1 right-1 w-2 h-2 bg-primary rounded-full" />
      )}
    </div>
  )

  if (href && !disabled) {
    return (
      <a href={href} className="block relative">
        {content}
      </a>
    )
  }

  return <div className="relative">{content}</div>
}

// ============================================================================
// Sidebar Nav Group
// ============================================================================
function DashboardLayoutSidebarNavGroup({
  icon,
  label,
  children,
  defaultOpen = false,
  isActive,
  badge,
  badgeVariant = 'default',
  className,
}: DashboardLayoutSidebarNavGroupProps) {
  const { sidebarExpanded } = useDashboardLayout()
  const [isOpen, setIsOpen] = React.useState(defaultOpen)

  const badgeColors = {
    default: 'bg-muted text-muted-foreground',
    primary: 'bg-primary/10 text-primary',
    destructive: 'bg-destructive/10 text-destructive',
  }

  // Render icon - handles both LucideIcon components and ReactNode elements
  const renderIcon = () => {
    if (!icon) return null
    // Already a React element
    if (React.isValidElement(icon)) {
      return icon
    }
    // Function component or forwardRef component (Lucide icons)
    if (typeof icon === 'function' || (typeof icon === 'object' && '$$typeof' in icon)) {
      const IconComponent = icon as React.ComponentType<{ className?: string }>
      return <IconComponent className="w-5 h-5 flex-shrink-0" />
    }
    return null
  }

  // Auto expand when sidebar expands if group is active
  React.useEffect(() => {
    if (isActive && sidebarExpanded) {
      setIsOpen(true)
    }
  }, [isActive, sidebarExpanded])

  return (
    <div className={className}>
      {/* Group Header */}
      <div
        onClick={() => sidebarExpanded && setIsOpen(!isOpen)}
        className={cn(
          'flex items-center gap-3 px-3 py-2.5 mx-2 rounded-md transition-colors',
          'hover:bg-muted cursor-pointer',
          isActive && 'text-primary'
        )}
      >
        {renderIcon()}

        {sidebarExpanded && (
          <>
            <span className="flex-1 truncate text-sm">{label}</span>
            {badge !== undefined && (
              <span
                className={cn(
                  'text-xs px-2 py-0.5 rounded-full',
                  badgeColors[badgeVariant]
                )}
              >
                {badge}
              </span>
            )}
            {isOpen ? (
              <ChevronDown className="w-4 h-4 text-muted-foreground" />
            ) : (
              <ChevronRight className="w-4 h-4 text-muted-foreground" />
            )}
          </>
        )}
      </div>

      {/* Group Items */}
      {sidebarExpanded && isOpen && (
        <div className="ml-4 mt-1 space-y-0.5">{children}</div>
      )}
    </div>
  )
}

// ============================================================================
// Sidebar Section
// ============================================================================
function DashboardLayoutSidebarSection({
  title,
  children,
  className,
}: DashboardLayoutSidebarSectionProps) {
  const { sidebarExpanded } = useDashboardLayout()

  return (
    <div className={cn('mb-2', className)}>
      {title && sidebarExpanded && (
        <div className="px-5 py-2">
          <span className="text-[10px] font-medium uppercase tracking-wider text-muted-foreground">
            {title}
          </span>
        </div>
      )}
      {children}
    </div>
  )
}

// ============================================================================
// Sidebar Footer
// ============================================================================
function DashboardLayoutSidebarFooter({ children, className }: DashboardLayoutSidebarFooterProps) {
  return (
    <div className={cn('p-4 border-t border-border mt-auto', className)}>
      {children}
    </div>
  )
}

// ============================================================================
// Header
// ============================================================================
function DashboardLayoutHeader({ children, className }: DashboardLayoutHeaderProps) {
  const { isMobile, setMobileMenuOpen, sidebarPinned } = useDashboardLayout()

  // Calculate left margin based on sidebar state (only pinned affects content position)
  const marginLeft = isMobile ? 0 : sidebarPinned ? 256 : 64

  return (
    <header
      style={{ marginLeft }}
      className={cn(
        'h-16 bg-background border-b border-border',
        'flex items-center px-4 lg:px-6',
        'sticky top-0 z-30',
        !isMobile && 'transition-[margin-left] duration-300',
        className
      )}
    >
      {/* Mobile menu button */}
      {isMobile && (
        <button
          onClick={() => setMobileMenuOpen(true)}
          className="p-2 hover:bg-muted rounded-md mr-2"
        >
          <Menu className="w-5 h-5" />
        </button>
      )}

      {children}
    </header>
  )
}

// ============================================================================
// Header Title
// ============================================================================
function DashboardLayoutHeaderTitle({
  children,
  className,
  title,
  subtitle,
}: DashboardLayoutHeaderTitleProps) {
  if (children) {
    return <div className={cn('flex-1', className)}>{children}</div>
  }

  return (
    <div className={cn('flex-1 min-w-0', className)}>
      {title && <h1 className="font-semibold text-lg truncate">{title}</h1>}
      {subtitle && (
        <p className="text-sm text-muted-foreground truncate">{subtitle}</p>
      )}
    </div>
  )
}

// ============================================================================
// Header Actions
// ============================================================================
function DashboardLayoutHeaderActions({ children, className }: DashboardLayoutHeaderActionsProps) {
  return (
    <div className={cn('flex items-center gap-2', className)}>
      {children}
    </div>
  )
}

// ============================================================================
// Header User
// ============================================================================
function DashboardLayoutHeaderUser({
  name,
  email,
  avatar,
  className,
  children,
  onLogout,
}: DashboardLayoutHeaderUserProps) {
  const [isOpen, setIsOpen] = React.useState(false)

  return (
    <div className={cn('relative', className)}>
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="flex items-center gap-2 p-1.5 hover:bg-muted rounded-md transition-colors"
      >
        {avatar ? (
          <img
            src={avatar}
            alt={name}
            className="w-8 h-8 rounded-full object-cover"
          />
        ) : (
          <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center">
            <User className="w-4 h-4 text-primary" />
          </div>
        )}
        <div className="hidden sm:block text-left">
          <p className="text-sm font-medium truncate max-w-[120px]">{name}</p>
          {email && (
            <p className="text-xs text-muted-foreground truncate max-w-[120px]">
              {email}
            </p>
          )}
        </div>
        <ChevronDown className="w-4 h-4 text-muted-foreground hidden sm:block" />
      </button>

      {/* Dropdown */}
      {isOpen && (
        <>
          <div
            className="fixed inset-0 z-40"
            onClick={() => setIsOpen(false)}
          />
          <div className="absolute right-0 top-full mt-1 w-56 bg-card border border-border rounded-md shadow-lg z-50">
            <div className="p-3 border-b border-border">
              <p className="font-medium truncate">{name}</p>
              {email && (
                <p className="text-sm text-muted-foreground truncate">{email}</p>
              )}
            </div>

            {children && <div className="p-1">{children}</div>}

            {onLogout && (
              <div className="p-1 border-t border-border">
                <button
                  onClick={() => {
                    setIsOpen(false)
                    onLogout()
                  }}
                  className="flex items-center gap-2 w-full px-3 py-2 text-sm hover:bg-muted rounded-md transition-colors text-destructive"
                >
                  <LogOut className="w-4 h-4" />
                  Sair
                </button>
              </div>
            )}
          </div>
        </>
      )}
    </div>
  )
}

// ============================================================================
// Content
// ============================================================================
function DashboardLayoutContent({ children, className }: DashboardLayoutContentProps) {
  const { isMobile, sidebarPinned } = useDashboardLayout()

  // Calculate left margin based on sidebar state
  const marginLeft = isMobile ? 0 : sidebarPinned ? 256 : 64

  return (
    <main
      style={{ marginLeft }}
      className={cn(
        'flex-1 flex flex-col min-h-screen',
        'transition-[margin-left] duration-300',
        className
      )}
    >
      {children}
    </main>
  )
}

// ============================================================================
// Breadcrumbs
// ============================================================================
function DashboardLayoutBreadcrumbs({
  items,
  className,
  separator,
}: DashboardLayoutBreadcrumbsProps) {
  const defaultSeparator = <ChevronRight className="w-4 h-4 text-muted-foreground" />

  return (
    <nav className={cn('flex items-center gap-1 text-sm', className)}>
      {items.map((item, index) => {
        const Icon = item.icon
        const isLast = index === items.length - 1

        return (
          <React.Fragment key={index}>
            {item.href && !isLast ? (
              <a
                href={item.href}
                className="flex items-center gap-1 text-muted-foreground hover:text-foreground transition-colors"
              >
                {Icon && <Icon className="w-4 h-4" />}
                <span>{item.label}</span>
              </a>
            ) : (
              <span
                className={cn(
                  'flex items-center gap-1',
                  isLast ? 'text-foreground font-medium' : 'text-muted-foreground'
                )}
              >
                {Icon && <Icon className="w-4 h-4" />}
                <span>{item.label}</span>
              </span>
            )}

            {!isLast && (
              <span className="mx-1">{separator || defaultSeparator}</span>
            )}
          </React.Fragment>
        )
      })}
    </nav>
  )
}

// ============================================================================
// Mobile Nav
// ============================================================================
function DashboardLayoutMobileNav({ children, className }: DashboardLayoutMobileNavProps) {
  return (
    <nav
      className={cn(
        'fixed bottom-0 left-0 right-0 h-16 bg-card border-t border-border',
        'flex items-center justify-around px-2 z-50 lg:hidden',
        className
      )}
    >
      {children}
    </nav>
  )
}

// ============================================================================
// Mobile Nav Item
// ============================================================================
function DashboardLayoutMobileNavItem({
  icon: Icon,
  label,
  href,
  onClick,
  isActive,
  badge,
}: DashboardLayoutMobileNavItemProps) {
  const content = (
    <div
      className={cn(
        'flex flex-col items-center gap-1 p-2 rounded-md transition-colors relative',
        'hover:bg-muted',
        isActive && 'text-primary'
      )}
      onClick={onClick}
    >
      <Icon className="w-5 h-5" />
      <span className="text-[10px]">{label}</span>

      {badge !== undefined && (
        <span className="absolute -top-1 -right-1 min-w-[18px] h-[18px] flex items-center justify-center text-[10px] font-medium bg-destructive text-destructive-foreground rounded-full px-1">
          {badge}
        </span>
      )}
    </div>
  )

  if (href) {
    return <a href={href}>{content}</a>
  }

  return content
}

// ============================================================================
// Display Names
// ============================================================================
DashboardLayoutRoot.displayName = 'DashboardLayout'
DashboardLayoutSidebar.displayName = 'DashboardLayout.Sidebar'
DashboardLayoutSidebarHeader.displayName = 'DashboardLayout.SidebarHeader'
DashboardLayoutSidebarNav.displayName = 'DashboardLayout.SidebarNav'
DashboardLayoutSidebarNavItem.displayName = 'DashboardLayout.SidebarNavItem'
DashboardLayoutSidebarNavGroup.displayName = 'DashboardLayout.SidebarNavGroup'
DashboardLayoutSidebarSection.displayName = 'DashboardLayout.SidebarSection'
DashboardLayoutSidebarFooter.displayName = 'DashboardLayout.SidebarFooter'
DashboardLayoutHeader.displayName = 'DashboardLayout.Header'
DashboardLayoutHeaderTitle.displayName = 'DashboardLayout.HeaderTitle'
DashboardLayoutHeaderActions.displayName = 'DashboardLayout.HeaderActions'
DashboardLayoutHeaderUser.displayName = 'DashboardLayout.HeaderUser'
DashboardLayoutContent.displayName = 'DashboardLayout.Content'
DashboardLayoutBreadcrumbs.displayName = 'DashboardLayout.Breadcrumbs'
DashboardLayoutMobileNav.displayName = 'DashboardLayout.MobileNav'
DashboardLayoutMobileNavItem.displayName = 'DashboardLayout.MobileNavItem'

// ============================================================================
// Compound Component Export
// ============================================================================
export const DashboardLayout = Object.assign(DashboardLayoutRoot, {
  Sidebar: DashboardLayoutSidebar,
  SidebarHeader: DashboardLayoutSidebarHeader,
  SidebarNav: DashboardLayoutSidebarNav,
  SidebarNavItem: DashboardLayoutSidebarNavItem,
  SidebarNavGroup: DashboardLayoutSidebarNavGroup,
  SidebarSection: DashboardLayoutSidebarSection,
  SidebarFooter: DashboardLayoutSidebarFooter,
  Header: DashboardLayoutHeader,
  HeaderTitle: DashboardLayoutHeaderTitle,
  HeaderActions: DashboardLayoutHeaderActions,
  HeaderUser: DashboardLayoutHeaderUser,
  Content: DashboardLayoutContent,
  Breadcrumbs: DashboardLayoutBreadcrumbs,
  MobileNav: DashboardLayoutMobileNav,
  MobileNavItem: DashboardLayoutMobileNavItem,
})
