import { cn } from '../../utils/cn'
import type { DataTableProps } from './types'
import { useDataTableInternal } from './hooks/useDataTable'
import { DataTableProvider } from './DataTableContext'

// ============================================================================
// ROOT COMPONENT - Compound Component Pattern (Composição Explícita)
// ============================================================================
//
// Props MÍNIMAS no root - features via subcomponentes:
//
// <DataTable data={data} columns={columns}>
//   <DataTable.Loading visible={isLoading} />
//   <DataTable.Toolbar>...</DataTable.Toolbar>
//   <DataTable.Content />
//   <DataTable.Pagination mode="server" pageCount={10} />
// </DataTable>
//
// ============================================================================

export function DataTableRoot<TData extends object>({
  children,
  data,
  columns,
  getRowId,
  manualPagination,
  pageCount,
  initialPageSize,
  onPaginationChange,
  className,
}: DataTableProps<TData>) {
  // Hook interno gerencia todo o state
  const { table, meta, density, setDensity, pageIndex, pageSize } = useDataTableInternal({
    data,
    columns,
    getRowId,
    manualPagination,
    pageCount,
    initialPageSize,
    onPaginationChange,
  })

  return (
    <DataTableProvider
      table={table}
      meta={meta}
      density={density}
      setDensity={setDensity}
      pageIndex={pageIndex}
      pageSize={pageSize}
    >
      <div
        className={cn('w-full space-y-4', className)}
        data-density={density}
      >
        {children}
      </div>
    </DataTableProvider>
  )
}

// Display name for DevTools
DataTableRoot.displayName = 'DataTable'
