import * as React from 'react'
import { cn } from '../../../utils/cn'
import type {
  AuthLayoutProps,
  AuthLayoutImageProps,
  AuthLayoutContentProps,
  AuthLayoutHeaderProps,
  AuthLayoutBodyProps,
  AuthLayoutFooterProps,
  AuthLayoutLinkProps,
  AuthLayoutDividerProps,
} from './types'

// Context para compartilhar estado entre componentes
interface AuthLayoutContextValue {
  imagePosition: 'left' | 'right'
}

const AuthLayoutContext = React.createContext<AuthLayoutContextValue>({
  imagePosition: 'left',
})

// ============================================================================
// AuthLayout Root
// ============================================================================
function AuthLayoutRoot({ children, className }: AuthLayoutProps) {
  const [imagePosition, setImagePosition] = React.useState<'left' | 'right'>('left')

  // Detecta a posição da imagem baseado nos children
  React.useEffect(() => {
    React.Children.forEach(children, (child) => {
      if (React.isValidElement<AuthLayoutImageProps>(child) && child.type === AuthLayoutImage) {
        setImagePosition(child.props.position || 'left')
      }
    })
  }, [children])

  return (
    <AuthLayoutContext.Provider value={{ imagePosition }}>
      <div
        className={cn(
          'min-h-screen flex flex-col xl:flex-row max-xl:justify-center',
          imagePosition === 'right' && 'xl:flex-row-reverse',
          className
        )}
      >
        {children}
      </div>
    </AuthLayoutContext.Provider>
  )
}

// ============================================================================
// AuthLayout.Image
// ============================================================================
function AuthLayoutImage({
  src,
  alt,
  position: _position = 'left',
  className,
  priority = true,
  showPattern = false,
}: AuthLayoutImageProps) {
  // _position is used by parent (AuthLayoutRoot) via child.props.position
  void _position

  return (
    <div
      className={cn(
        'hidden xl:block relative w-full xl:w-3/6 h-64 xl:h-screen overflow-hidden bg-muted',
        className
      )}
    >
      {src ? (
        <img
          src={src}
          alt={alt}
          className="absolute inset-0 w-full h-full object-cover object-top"
          loading={priority ? 'eager' : 'lazy'}
        />
      ) : null}

      {/* Pattern overlay */}
      {showPattern && (
        <div className="absolute inset-0 flex items-center justify-center">
          {/* Geometric patterns */}
          <svg
            className="absolute inset-0 w-full h-full opacity-10"
            xmlns="http://www.w3.org/2000/svg"
          >
            <defs>
              <pattern
                id="auth-grid"
                width="40"
                height="40"
                patternUnits="userSpaceOnUse"
              >
                <path
                  d="M 40 0 L 0 0 0 40"
                  fill="none"
                  stroke="currentColor"
                  strokeWidth="0.5"
                />
              </pattern>
            </defs>
            <rect width="100%" height="100%" fill="url(#auth-grid)" />
          </svg>

          {/* Center decorative elements */}
          <div className="relative z-10">
            {/* Large circle */}
            <div className="w-64 h-64 rounded-full border border-muted-foreground/20" />
            {/* Inner circle with icon */}
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-24 h-24 rounded-full border border-muted-foreground/30 flex items-center justify-center">
              <svg
                className="w-10 h-10 text-muted-foreground/40"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={1}
                  d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"
                />
              </svg>
            </div>
            {/* Decorative lines */}
            <div className="absolute top-1/2 left-full ml-4 w-32 h-px bg-gradient-to-r from-muted-foreground/20 to-transparent" />
            <div className="absolute top-1/2 right-full mr-4 w-32 h-px bg-gradient-to-l from-muted-foreground/20 to-transparent" />
            <div className="absolute top-full left-1/2 -translate-x-1/2 mt-4 w-px h-32 bg-gradient-to-b from-muted-foreground/20 to-transparent" />
            <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-4 w-px h-32 bg-gradient-to-t from-muted-foreground/20 to-transparent" />
          </div>
        </div>
      )}
    </div>
  )
}

// ============================================================================
// AuthLayout.Content
// ============================================================================
function AuthLayoutContent({
  children,
  className,
  maxWidth = 'md',
}: AuthLayoutContentProps) {
  const maxWidthClasses = {
    sm: 'max-w-sm',
    md: 'max-w-md',
    lg: 'max-w-lg',
  }

  return (
    <div
      className={cn(
        'relative w-full lg:w-3/6 flex items-center justify-center p-6 lg:p-12 bg-background',
        className
      )}
    >
      <div className={cn('w-full space-y-8', maxWidthClasses[maxWidth])}>
        {children}
      </div>
    </div>
  )
}

// ============================================================================
// AuthLayout.Header
// ============================================================================
function AuthLayoutHeader({
  children,
  className,
  logo,
  title,
  description,
  centered = true,
  position = 'top-right',
}: AuthLayoutHeaderProps) {
  // Logo positioned at top-left corner (absolute)
  if (position === 'top-left' && logo) {
    return (
      <div className={cn('absolute top-6 left-6 lg:top-8 lg:left-8', className)}>
        {logo}
      </div>
    )
  }

  // Logo positioned at top-right corner (absolute)
  if (position === 'top-right' && logo) {
    return (
      <div className={cn('absolute top-6 right-6 lg:top-8 lg:right-8', className)}>
        {logo}
      </div>
    )
  }

  // Se children fornecido, renderiza diretamente
  if (children) {
    return (
      <div className={cn('space-y-2', centered && 'text-center', className)}>
        {children}
      </div>
    )
  }

  // Renderização padrão com props
  return (
    <div
      className={cn(
        'flex flex-col gap-2',
        centered && 'items-center text-center',
        className
      )}
    >
      {logo && <div className="mb-2">{logo}</div>}
      {title && <h1 className="text-2xl font-bold">{title}</h1>}
      {description && (
        <p className="text-balance text-sm text-muted-foreground">{description}</p>
      )}
    </div>
  )
}

// ============================================================================
// AuthLayout.Body
// ============================================================================
function AuthLayoutBody({ children, className }: AuthLayoutBodyProps) {
  return <div className={cn('space-y-6', className)}>{children}</div>
}

// ============================================================================
// AuthLayout.Footer
// ============================================================================
function AuthLayoutFooter({ children, className }: AuthLayoutFooterProps) {
  return (
    <div className={cn('text-center text-sm text-muted-foreground', className)}>
      {children}
    </div>
  )
}

// ============================================================================
// AuthLayout.Link
// ============================================================================
function AuthLayoutLink({ children, className, ...props }: AuthLayoutLinkProps) {
  return (
    <a
      className={cn(
        'text-sm text-primary hover:underline cursor-pointer',
        className
      )}
      {...props}
    >
      {children}
    </a>
  )
}

// ============================================================================
// AuthLayout.Divider
// ============================================================================
function AuthLayoutDivider({ text = 'ou', className }: AuthLayoutDividerProps) {
  return (
    <div className={cn('relative', className)}>
      <div className="absolute inset-0 flex items-center">
        <span className="w-full border-t" />
      </div>
      <div className="relative flex justify-center text-xs uppercase">
        <span className="bg-background px-2 text-muted-foreground">{text}</span>
      </div>
    </div>
  )
}

// ============================================================================
// Compound Component Export
// ============================================================================
AuthLayoutRoot.displayName = 'AuthLayout'
AuthLayoutImage.displayName = 'AuthLayout.Image'
AuthLayoutContent.displayName = 'AuthLayout.Content'
AuthLayoutHeader.displayName = 'AuthLayout.Header'
AuthLayoutBody.displayName = 'AuthLayout.Body'
AuthLayoutFooter.displayName = 'AuthLayout.Footer'
AuthLayoutLink.displayName = 'AuthLayout.Link'
AuthLayoutDivider.displayName = 'AuthLayout.Divider'

export const AuthLayout = Object.assign(AuthLayoutRoot, {
  Image: AuthLayoutImage,
  Content: AuthLayoutContent,
  Header: AuthLayoutHeader,
  Body: AuthLayoutBody,
  Footer: AuthLayoutFooter,
  Link: AuthLayoutLink,
  Divider: AuthLayoutDivider,
})
