import * as React from 'react'
import { cva, type VariantProps } from 'class-variance-authority'
import { cn } from '../../utils/cn'

const inputVariants = cva(
  'w-full h-12 px-3 pt-4 pb-2 text-sm bg-background rounded-md border-2 transition-colors focus:outline-none focus:ring-0 disabled:cursor-not-allowed disabled:opacity-50',
  {
    variants: {
      variant: {
        default: 'border-border focus:border-primary',
        error: 'border-red-500 focus:border-red-600',
      },
      inputSize: {
        default: 'h-12',
        sm: 'h-10 pt-3 pb-1',
        lg: 'h-14 pt-5 pb-2',
      },
    },
    defaultVariants: {
      variant: 'default',
      inputSize: 'default',
    },
  }
)

export interface InputProps
  extends Omit<React.InputHTMLAttributes<HTMLInputElement>, 'size'>,
    VariantProps<typeof inputVariants> {
  label?: string
  error?: boolean
  icon?: React.ComponentType<any>
  /** Extra ReactNode rendered after label text (used by Form.Input for tooltip icon) */
  labelSuffix?: React.ReactNode
  containerClassName?: string
  labelClassName?: string
}

export const Input = React.forwardRef<HTMLInputElement, InputProps>(
  (
    {
      className,
      variant,
      inputSize,
      error,
      type = 'text',
      label,
      icon: Icon,
      required,
      labelSuffix,
      containerClassName,
      labelClassName,
      ...props
    },
    ref
  ) => {
    const inputRef = React.useRef<HTMLInputElement | null>(null)
    const [showPassword, setShowPassword] = React.useState(false)

    React.useImperativeHandle(ref, () => inputRef.current!, [])

    const focusInput = React.useCallback(() => {
      inputRef.current?.focus()
    }, [])

    const togglePasswordVisibility = React.useCallback(() => {
      setShowPassword((prev) => !prev)
    }, [])

    const inputType = type === 'password' ? (showPassword ? 'text' : 'password') : type

    return (
      <div className={cn('relative', containerClassName)}>
        {/* Icon */}
        {Icon && (
          <Icon
            className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground h-4 w-4 cursor-pointer z-10"
            onClick={focusInput}
          />
        )}

        {/* Input */}
        <input
          type={inputType}
          className={cn(
            inputVariants({
              variant: error ? 'error' : variant,
              inputSize,
            }),
            !label && 'h-9 pt-0 pb-0 py-2',
            Icon && 'pl-10',
            type === 'password' && 'pr-11',
            className
          )}
          ref={inputRef}
          {...props}
        />

        {/* Floating Label */}
        {label && (
          <label
            className={cn(
              'absolute left-3 top-[-6px] text-xs font-medium bg-background px-1 cursor-pointer inline-flex items-center gap-1',
              error ? 'text-red-500' : 'text-foreground',
              Icon && 'left-10',
              labelClassName
            )}
            onClick={focusInput}
          >
            {label}
            {required && <span className="text-red-500 ml-0.5">*</span>}
            {labelSuffix}
          </label>
        )}

        {/* Password Toggle */}
        {type === 'password' && (
          <button
            type="button"
            onClick={togglePasswordVisibility}
            className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors z-10"
            aria-label={showPassword ? 'Ocultar senha' : 'Mostrar senha'}
          >
            {showPassword ? (
              <svg
                className="h-5 w-5"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"
                />
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"
                />
              </svg>
            ) : (
              <svg
                className="h-5 w-5"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21"
                />
              </svg>
            )}
          </button>
        )}
      </div>
    )
  }
)

Input.displayName = 'Input'
