'use client'

import * as React from 'react'
import { Controller } from 'react-hook-form'
import type { FieldValues } from 'react-hook-form'
import { Checkbox } from '../Checkbox'
import { useFormContext, FormFieldProvider } from './FormContext'
import type { FormCheckboxProps } from './types'
import { cn } from '../../utils/cn'

export function FormCheckbox<T extends FieldValues = FieldValues>({
  name,
  label,
  description,
  required,
  disabled,
  className,
  hideError = false,
}: FormCheckboxProps<T>) {
  const form = useFormContext<T>()
  const fieldState = form.getFieldState(name, form.formState)
  const error = fieldState.error?.message
  const id = React.useId()

  return (
    <FormFieldProvider name={name as string}>
      <Controller
        control={form.control}
        name={name}
        render={({ field }) => (
          <div className={cn('space-y-1', className)}>
            <div className="flex items-start gap-3">
              <Checkbox
                id={id}
                ref={field.ref}
                checked={field.value ?? false}
                onCheckedChange={(checked) => field.onChange(checked)}
                onBlur={field.onBlur}
                disabled={disabled}
              />

              {(label || description) && (
                <div className="grid gap-0.5 leading-none">
                  {label && (
                    <label
                      htmlFor={id}
                      className={cn(
                        'text-sm font-medium leading-none cursor-pointer',
                        disabled && 'cursor-not-allowed opacity-50'
                      )}
                    >
                      {label}
                      {required && <span className="text-red-500 ml-0.5">*</span>}
                    </label>
                  )}

                  {description && (
                    <p className="text-xs text-muted-foreground">
                      {description}
                    </p>
                  )}
                </div>
              )}
            </div>

            {!hideError && error && (
              <p className="text-xs text-red-500 pl-8">{error}</p>
            )}
          </div>
        )}
      />
    </FormFieldProvider>
  )
}

FormCheckbox.displayName = 'Form.Checkbox'
