'use client'

import { Controller } from 'react-hook-form'
import type { FieldValues } from 'react-hook-form'
import * as RadioGroupPrimitive from '@radix-ui/react-radio-group'
import { Circle } from 'lucide-react'
import { useFormContext, FormFieldProvider } from './FormContext'
import type { FormRadioGroupProps, RadioOptionColor } from './types'
import { cn } from '../../utils/cn'

const colorStyles: Record<RadioOptionColor, { border: string; bg: string; text: string; radio: string }> = {
  default: {
    border: 'border-primary',
    bg: 'bg-primary/5',
    text: 'text-primary',
    radio: 'border-primary text-primary',
  },
  destructive: {
    border: 'border-red-500',
    bg: 'bg-red-500/10',
    text: 'text-red-600',
    radio: 'border-red-500 text-red-500',
  },
  warning: {
    border: 'border-amber-500',
    bg: 'bg-amber-500/10',
    text: 'text-amber-600',
    radio: 'border-amber-500 text-amber-500',
  },
  success: {
    border: 'border-green-500',
    bg: 'bg-green-500/10',
    text: 'text-green-600',
    radio: 'border-green-500 text-green-500',
  },
  info: {
    border: 'border-blue-500',
    bg: 'bg-blue-500/10',
    text: 'text-blue-600',
    radio: 'border-blue-500 text-blue-500',
  },
}

export function FormRadioGroup<T extends FieldValues = FieldValues>({
  name,
  label,
  description,
  required,
  disabled,
  className,
  options,
  orientation = 'vertical',
  hideError = false,
}: FormRadioGroupProps<T>) {
  const form = useFormContext<T>()
  const fieldState = form.getFieldState(name, form.formState)
  const error = fieldState.error?.message

  return (
    <FormFieldProvider name={name as string}>
      <Controller
        control={form.control}
        name={name}
        render={({ field }) => (
          <div className={cn('space-y-2', className)}>
            {label && (
              <label className="text-sm font-medium">
                {label}
                {required && <span className="text-red-500 ml-0.5">*</span>}
              </label>
            )}

            {description && !error && (
              <p className="text-xs text-muted-foreground">{description}</p>
            )}

            <RadioGroupPrimitive.Root
              ref={field.ref}
              value={field.value}
              onValueChange={(value) => field.onChange(value || undefined)}
              disabled={disabled}
              className={cn(
                'grid gap-2',
                orientation === 'horizontal' && 'flex flex-wrap gap-4'
              )}
            >
              {options.map((option) => {
                const optionId = `${name}-${option.value}`
                const isSelected = field.value === option.value
                const color = option.color || 'default'
                const styles = colorStyles[color]

                return (
                  <label
                    key={option.value}
                    htmlFor={optionId}
                    className={cn(
                      'flex items-center gap-3 border-2 py-2 px-4 rounded-lg transition-colors cursor-pointer',
                      isSelected
                        ? cn(styles.border, styles.bg)
                        : 'border-border hover:border-muted-foreground/50',
                      (option.disabled || disabled) && 'opacity-50 cursor-not-allowed'
                    )}
                  >
                    <RadioGroupPrimitive.Item
                      id={optionId}
                      value={option.value}
                      disabled={option.disabled || disabled}
                      className={cn(
                        'aspect-square h-4 w-4 rounded-full border',
                        isSelected ? styles.radio : 'border-border text-muted-foreground',
                        'ring-offset-background focus:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2',
                        'disabled:cursor-not-allowed disabled:opacity-50'
                      )}
                    >
                      <RadioGroupPrimitive.Indicator className="flex items-center justify-center">
                        <Circle className="h-2.5 w-2.5 fill-current text-current" />
                      </RadioGroupPrimitive.Indicator>
                    </RadioGroupPrimitive.Item>

                    <div className="grid gap-0.5 leading-none">
                      <span
                        className={cn(
                          'text-sm font-medium leading-none',
                          isSelected && styles.text
                        )}
                      >
                        {option.label}
                      </span>

                      {option.description && (
                        <span className="text-xs text-muted-foreground">
                          {option.description}
                        </span>
                      )}
                    </div>
                  </label>
                )
              })}
            </RadioGroupPrimitive.Root>

            {!hideError && error && (
              <p className="text-xs text-red-500">{error}</p>
            )}
          </div>
        )}
      />
    </FormFieldProvider>
  )
}

FormRadioGroup.displayName = 'Form.RadioGroup'
