import * as React from 'react'
import type { DataTableLoadingProps } from './types'
import { useDataTableLoadingState } from './DataTableContext'

// ============================================================================
// LOADING COMPONENT - Registra loading state no context
// ============================================================================
//
// Não renderiza nada diretamente. Passa `visible` para o context,
// e o DataTableContent renderiza skeleton rows dentro da tabela.
//
// Uso:
// <DataTable data={data} columns={columns}>
//   <DataTable.Loading visible={isLoading} />
//   <DataTable.Content />
// </DataTable>
//
// ============================================================================

export function DataTableLoading({
  visible,
  skeletonRows = 5,
}: DataTableLoadingProps) {
  const { setIsLoading, setSkeletonRows } = useDataTableLoadingState()

  React.useLayoutEffect(() => {
    setIsLoading(visible)
    return () => setIsLoading(false)
  }, [visible, setIsLoading])

  React.useLayoutEffect(() => {
    setSkeletonRows(skeletonRows)
  }, [skeletonRows, setSkeletonRows])

  return null
}

DataTableLoading.displayName = 'DataTable.Loading'
