import * as React from 'react'
import { motion } from 'framer-motion'
import { cn } from '../../utils/cn'
import { SidebarProvider, useMediaQuery, useSidebar, useSidebarOptional } from './SidebarContext'
import { SidebarHeader } from './SidebarHeader'
import { SidebarNav } from './SidebarNav'
import { SidebarSection } from './SidebarSection'
import { SidebarNavItem } from './SidebarNavItem'
import { SidebarNavGroup } from './SidebarNavGroup'
import { SidebarFooter } from './SidebarFooter'
import type { SidebarProps, SidebarContextValue } from './types'

const COLLAPSED_WIDTH = 60
const EXPANDED_WIDTH = 250

// ============================================================================
// SidebarRoot - Provider with state management
// ============================================================================

interface SidebarRootProps {
  children: React.ReactNode
  defaultExpanded?: boolean
  defaultPinned?: boolean
  collapsedWidth?: number
  expandedWidth?: number
}

function SidebarRoot({
  children,
  defaultExpanded = false,
  defaultPinned = false,
  collapsedWidth = COLLAPSED_WIDTH,
  expandedWidth = EXPANDED_WIDTH,
}: SidebarRootProps) {
  // If pinned, sidebar should also be expanded
  const [expanded, setExpanded] = React.useState(defaultExpanded || defaultPinned)
  const [pinned, setPinned] = React.useState(defaultPinned)
  const [activeSection, setActiveSection] = React.useState<string | null>(null)
  const isMobile = useMediaQuery('(max-width: 768px)')

  const handleSetPinned = React.useCallback((value: boolean) => {
    setPinned(value)
    if (value) {
      setExpanded(true)
    }
  }, [])

  const contextValue = React.useMemo<SidebarContextValue>(
    () => ({
      expanded,
      setExpanded,
      pinned,
      setPinned: handleSetPinned,
      activeSection,
      setActiveSection,
      isMobile,
      collapsedWidth,
      expandedWidth,
    }),
    [expanded, pinned, handleSetPinned, activeSection, isMobile, collapsedWidth, expandedWidth]
  )

  return (
    <SidebarProvider value={contextValue}>
      {children}
    </SidebarProvider>
  )
}

SidebarRoot.displayName = 'SidebarRoot'

// ============================================================================
// SidebarAside - The actual sidebar UI
// ============================================================================

interface SidebarAsideProps {
  children: React.ReactNode
  className?: string
}

function SidebarAside({ children, className }: SidebarAsideProps) {
  const { expanded, pinned, setExpanded, isMobile, collapsedWidth, expandedWidth } = useSidebar()
  const sidebarRef = React.useRef<HTMLDivElement>(null)

  const handleMouseEnter = React.useCallback(() => {
    if (!pinned && !isMobile) {
      setExpanded(true)
    }
  }, [pinned, isMobile, setExpanded])

  const handleMouseLeave = React.useCallback(() => {
    if (!pinned && !isMobile) {
      setExpanded(false)
    }
  }, [pinned, isMobile, setExpanded])

  // Don't render desktop sidebar on mobile
  if (isMobile) {
    return null
  }

  return (
    <motion.aside
      ref={sidebarRef}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      initial={{ width: collapsedWidth }}
      animate={{ width: expanded ? expandedWidth : collapsedWidth }}
      transition={{
        type: 'spring',
        stiffness: 300,
        damping: 30,
        mass: 1,
      }}
      className={cn(
        'relative flex h-screen flex-col bg-card',
        'shadow-[0_0_20px_rgba(0,0,0,0.06)]',
        'fixed top-0 left-0 z-50',
        className
      )}
    >
      {children}
    </motion.aside>
  )
}

SidebarAside.displayName = 'SidebarAside'

// ============================================================================
// SidebarContent - Main content wrapper that responds to sidebar
// ============================================================================

interface SidebarContentProps {
  children: React.ReactNode
  className?: string
}

function SidebarContent({ children, className }: SidebarContentProps) {
  const sidebar = useSidebarOptional()

  // If no sidebar context, render without margin
  if (!sidebar) {
    return <div className={className}>{children}</div>
  }

  const { expanded, pinned, isMobile, collapsedWidth, expandedWidth } = sidebar

  // On mobile, no margin needed
  if (isMobile) {
    return <div className={className}>{children}</div>
  }

  // Calculate margin based on sidebar state
  const marginLeft = pinned && expanded ? expandedWidth : collapsedWidth

  return (
    <motion.div
      initial={{ marginLeft: collapsedWidth }}
      animate={{ marginLeft }}
      transition={{
        type: 'spring',
        stiffness: 300,
        damping: 30,
        mass: 1,
      }}
      className={cn('min-h-screen flex flex-col', className)}
    >
      {children}
    </motion.div>
  )
}

SidebarContent.displayName = 'SidebarContent'

// ============================================================================
// Legacy Sidebar - Backwards compatible wrapper (for existing usage)
// ============================================================================

function LegacySidebar({
  children,
  defaultExpanded = false,
  defaultPinned = false,
  collapsedWidth = COLLAPSED_WIDTH,
  expandedWidth = EXPANDED_WIDTH,
  className,
}: SidebarProps) {
  // If pinned, sidebar should also be expanded
  const [expanded, setExpanded] = React.useState(defaultExpanded || defaultPinned)
  const [pinned, setPinned] = React.useState(defaultPinned)
  const [activeSection, setActiveSection] = React.useState<string | null>(null)
  const isMobile = useMediaQuery('(max-width: 768px)')

  const sidebarRef = React.useRef<HTMLDivElement>(null)

  const handleMouseEnter = React.useCallback(() => {
    if (!pinned && !isMobile) {
      setExpanded(true)
    }
  }, [pinned, isMobile])

  const handleMouseLeave = React.useCallback(() => {
    if (!pinned && !isMobile) {
      setExpanded(false)
    }
  }, [pinned, isMobile])

  const handleSetPinned = React.useCallback((value: boolean) => {
    setPinned(value)
    if (value) {
      setExpanded(true)
    }
  }, [])

  const contextValue = React.useMemo<SidebarContextValue>(
    () => ({
      expanded,
      setExpanded,
      pinned,
      setPinned: handleSetPinned,
      activeSection,
      setActiveSection,
      isMobile,
      collapsedWidth,
      expandedWidth,
    }),
    [expanded, pinned, handleSetPinned, activeSection, isMobile, collapsedWidth, expandedWidth]
  )

  // Don't render desktop sidebar on mobile
  if (isMobile) {
    return (
      <SidebarProvider value={contextValue}>
        {children}
      </SidebarProvider>
    )
  }

  return (
    <SidebarProvider value={contextValue}>
      <motion.aside
        ref={sidebarRef}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
        initial={{ width: collapsedWidth }}
        animate={{ width: expanded ? expandedWidth : collapsedWidth }}
        transition={{
          type: 'spring',
          stiffness: 300,
          damping: 30,
          mass: 1,
        }}
        className={cn(
          'relative flex h-screen flex-col bg-card',
          'shadow-[0_0_20px_rgba(0,0,0,0.06)]',
          'fixed top-0 left-0 z-50',
          className
        )}
      >
        {children}
      </motion.aside>
    </SidebarProvider>
  )
}

LegacySidebar.displayName = 'Sidebar'

// ============================================================================
// Compound component pattern
// ============================================================================

export const Sidebar = Object.assign(LegacySidebar, {
  // Layout components
  Root: SidebarRoot,
  Aside: SidebarAside,
  Content: SidebarContent,
  // Sidebar content components
  Header: SidebarHeader,
  Nav: SidebarNav,
  Section: SidebarSection,
  NavItem: SidebarNavItem,
  NavGroup: SidebarNavGroup,
  Footer: SidebarFooter,
})
