import * as React from 'react'
import type { KanbanContextValue } from './types'

const KanbanContext = React.createContext<KanbanContextValue | null>(null)

export function useKanban(): KanbanContextValue {
  const context = React.useContext(KanbanContext)
  if (!context) {
    throw new Error('useKanban must be used within a Kanban.Board component')
  }
  return context
}

export function useKanbanOptional(): KanbanContextValue | null {
  return React.useContext(KanbanContext)
}

interface KanbanProviderProps {
  children: React.ReactNode
  value: KanbanContextValue
}

export function KanbanProvider({ children, value }: KanbanProviderProps) {
  return (
    <KanbanContext.Provider value={value}>
      {children}
    </KanbanContext.Provider>
  )
}

export { KanbanContext }
