import * as React from 'react'
import { cn } from '../../utils/cn'
import { useDataTableInstance } from './DataTableContext'
import type { DataTableFiltersProps, DataTableFilterProps } from './types'
import { Select, SelectItem } from '../Select'

// ============================================================================
// FILTERS CONTAINER - Agrupa múltiplos filtros
// ============================================================================

export const DataTableFilters = React.memo(function DataTableFilters({
  onChange,
  className,
  children,
}: DataTableFiltersProps) {
  const table = useDataTableInstance()
  const filters = table.getState().columnFilters
  const filtersRef = React.useRef(filters)

  // Sync filter state with external callback
  React.useEffect(() => {
    if (onChange && JSON.stringify(filters) !== JSON.stringify(filtersRef.current)) {
      filtersRef.current = filters
      onChange(filters)
    }
  }, [filters, onChange])

  return <div className={cn('flex gap-2', className)}>{children}</div>
})

// ============================================================================
// FILTER COMPONENT - Filtro individual (client-side e server-side)
// ============================================================================

export const DataTableFilter = React.memo(function DataTableFilter({
  column: columnId,
  title,
  options,
  onValueChange: onServerValueChange,
  className,
}: DataTableFilterProps) {
  const table = useDataTableInstance()
  const column = columnId ? table.getColumn(columnId) : null

  const filterValue = (column?.getFilterValue() as string[]) ?? []
  const [localValue, setLocalValue] = React.useState('all')

  const currentValue = column ? (filterValue.length > 0 ? filterValue[0] : 'all') : localValue

  const isServerSide = !!onServerValueChange

  const handleValueChange = React.useCallback(
    (value: string) => {
      const resolvedValue = value === 'all' ? undefined : value

      if (isServerSide) {
        // Server-side: only call external callback
        onServerValueChange(resolvedValue)
      } else if (column) {
        // Client-side: set column filter
        column.setFilterValue(resolvedValue ? [resolvedValue] : undefined)
      }

      // Track local state
      setLocalValue(value)
    },
    [column, onServerValueChange]
  )

  return (
    <Select
      value={currentValue}
      onValueChange={handleValueChange}
      selectSize="sm"
      placeholder={title}
      className={className}
    >
      <SelectItem value="all">Todos</SelectItem>
      {options.map((option) => (
        <SelectItem key={option.value} value={option.value}>
          <span className="flex items-center gap-2">
            {option.icon && <span className="shrink-0 text-muted-foreground">{option.icon}</span>}
            {option.label}
          </span>
        </SelectItem>
      ))}
    </Select>
  )
})
