import * as React from 'react'
import { Bell, LogOut, Settings, User } from 'lucide-react'
import { Avatar, AvatarFallback, AvatarImage } from '../Avatar'
import { Button } from '../Button'
import { Popover, PopoverContent, PopoverTrigger } from '../Popover'

export interface UserMenuItemConfig {
  icon?: React.ReactNode
  label: string
  onClick?: () => void
  href?: string
  variant?: 'default' | 'destructive'
}

export interface NavbarUserMenuProps {
  /** Nome do usuário */
  name: string
  /** Email do usuário */
  email?: string
  /** URL do avatar */
  avatarUrl?: string
  /** Se está no modo colapsado (só mostra avatar) */
  isCollapsed?: boolean
  /** Itens do menu */
  menuItems?: UserMenuItemConfig[]
  /** Children customizado para o menu */
  children?: React.ReactNode
}

function getInitials(name: string): string {
  return name
    .split(' ')
    .map((part) => part[0])
    .join('')
    .toUpperCase()
    .slice(0, 2)
}

const defaultMenuItems: UserMenuItemConfig[] = [
  { icon: <User className="h-4 w-4" />, label: 'Ver Perfil' },
  { icon: <Settings className="h-4 w-4" />, label: 'Configurações' },
  { icon: <Bell className="h-4 w-4" />, label: 'Atualizações' },
  { icon: <LogOut className="h-4 w-4" />, label: 'Sair', variant: 'destructive' },
]

export function NavbarUserMenu({
  name,
  email,
  avatarUrl,
  isCollapsed = false,
  menuItems = defaultMenuItems,
  children,
}: NavbarUserMenuProps) {
  return (
    <Popover>
      <PopoverTrigger asChild>
        <Button variant="ghost" className="w-full justify-start p-2">
          <Avatar className="h-8 w-8">
            {avatarUrl && <AvatarImage src={avatarUrl} alt={name} />}
            <AvatarFallback>{getInitials(name)}</AvatarFallback>
          </Avatar>
          {!isCollapsed && (
            <div className="ml-2 text-left">
              <p className="text-sm font-medium">{name}</p>
              {email && (
                <p className="text-xs text-muted-foreground">{email}</p>
              )}
            </div>
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-56 p-2" align="end">
        {children ? (
          children
        ) : (
          <div className="space-y-1">
            {menuItems.map((item, index) => {
              const content = (
                <Button
                  key={index}
                  variant="ghost"
                  className={`w-full justify-start text-sm ${
                    item.variant === 'destructive' ? 'text-red-500' : ''
                  }`}
                  onClick={item.onClick}
                >
                  {item.icon && (
                    <span className="mr-2">{item.icon}</span>
                  )}
                  {item.label}
                </Button>
              )

              if (item.href) {
                return (
                  <a
                    key={index}
                    href={item.href}
                    className="flex flex-col items-center text-center"
                  >
                    {content}
                  </a>
                )
              }

              return content
            })}
          </div>
        )}
      </PopoverContent>
    </Popover>
  )
}

NavbarUserMenu.displayName = 'NavbarUserMenu'
