'use client'

import * as React from 'react'
import { Controller } from 'react-hook-form'
import type { FieldValues } from 'react-hook-form'
import { Check, ChevronDown, Search, Loader2, X } from 'lucide-react'
import { useFormContext, FormFieldProvider } from './FormContext'
import { FieldTooltipIcon } from './FormParts'
import type { FormMultiSelectProps, SelectOption, FieldTooltip } from './types'
import { cn } from '../../utils/cn'
import { Popover, PopoverContent, PopoverTrigger } from '../Popover'

export function FormMultiSelect<T extends FieldValues = FieldValues>({
  name,
  label,
  description,
  tooltip,
  required,
  disabled,
  className,
  options,
  placeholder = 'Selecione...',
  hideError = false,
  emptyText = 'Nenhuma opção disponível',
  loading = false,
  searchable = false,
  searchPlaceholder = 'Buscar...',
  clearable = true,
  maxVisibleChips = 3,
  dropdownPosition = 'bottom',
}: FormMultiSelectProps<T>) {
  const form = useFormContext<T>()
  const fieldState = form.getFieldState(name, form.formState)
  const error = fieldState.error?.message

  return (
    <FormFieldProvider name={name as string}>
      <Controller
        control={form.control}
        name={name}
        render={({ field }) => {
          const values: string[] = Array.isArray(field.value) ? field.value : []

          return (
            <div className={cn('space-y-1', className)}>
              <MultiSelectDropdown
                options={options}
                value={values}
                onChange={(v) => field.onChange(v)}
                disabled={disabled}
                label={label}
                tooltip={tooltip}
                required={required}
                error={!!error}
                placeholder={placeholder}
                searchable={searchable}
                loading={loading}
                emptyText={emptyText}
                searchPlaceholder={searchPlaceholder}
                clearable={clearable}
                maxVisibleChips={maxVisibleChips}
                dropdownPosition={dropdownPosition}
              />

              {description && !error && (
                <p className="text-xs text-muted-foreground px-1">{description}</p>
              )}

              {!hideError && error && (
                <p className="text-xs text-red-500 px-1">{error}</p>
              )}
            </div>
          )
        }}
      />
    </FormFieldProvider>
  )
}

FormMultiSelect.displayName = 'Form.MultiSelect'

// ============================================
// MULTI SELECT DROPDOWN (Popover-based)
// ============================================

interface MultiSelectDropdownProps {
  options: SelectOption[]
  value: string[]
  onChange: (value: string[]) => void
  disabled?: boolean
  label?: string
  tooltip?: FieldTooltip
  required?: boolean
  error?: boolean
  placeholder?: string
  searchable?: boolean
  loading?: boolean
  emptyText?: string
  searchPlaceholder?: string
  clearable?: boolean
  maxVisibleChips?: number
  dropdownPosition?: 'bottom' | 'top' | 'auto'
}

function MultiSelectDropdown({
  options,
  value,
  onChange,
  disabled,
  label,
  tooltip,
  required,
  error,
  placeholder = 'Selecione...',
  searchable,
  loading,
  emptyText = 'Nenhuma opção disponível',
  searchPlaceholder = 'Buscar...',
  clearable = true,
  maxVisibleChips = 3,
  dropdownPosition = 'bottom',
}: MultiSelectDropdownProps) {
  const [open, setOpen] = React.useState(false)
  const [search, setSearch] = React.useState('')
  const [computedMax, setComputedMax] = React.useState(maxVisibleChips)
  const [prevValueKey, setPrevValueKey] = React.useState(() => value.join(','))
  const contentRef = React.useRef<HTMLDivElement>(null)
  const listRef = React.useRef<HTMLDivElement>(null)
  const searchRef = React.useRef<HTMLInputElement>(null)
  const chipsRef = React.useRef<HTMLDivElement>(null)

  const selectedOptions = React.useMemo(
    () => options.filter((o) => value.includes(o.value)),
    [options, value]
  )

  // Reset computedMax synchronously during render when selection changes.
  // This ensures the first committed render has all chips for measurement.
  const valueKey = value.join(',')
  if (valueKey !== prevValueKey) {
    setPrevValueKey(valueKey)
    setComputedMax(maxVisibleChips)
  }

  // Measure rendered chips and reduce count if they overflow (runs before paint)
  React.useLayoutEffect(() => {
    const container = chipsRef.current
    if (!container || selectedOptions.length === 0) return

    const containerRect = container.getBoundingClientRect()
    const containerWidth = containerRect.width
    const chips = container.querySelectorAll<HTMLElement>('[data-chip]')
    if (chips.length === 0 || containerWidth === 0) return

    const gap = 4 // gap-1 = 0.25rem = 4px
    const buffer = 4 // safety buffer for sub-pixel rounding
    // Measure actual badge if rendered, otherwise estimate
    const badge = container.querySelector<HTMLElement>('[data-badge]')
    const badgeWidth = badge ? badge.getBoundingClientRect().width : 28
    const availableWidth = containerWidth - buffer
    let usedWidth = 0
    let fits = 0

    for (let i = 0; i < chips.length; i++) {
      const chipWidth = chips[i].getBoundingClientRect().width
      const widthWithGap = fits > 0 ? chipWidth + gap : chipWidth
      const remaining = selectedOptions.length - (fits + 1)
      const needsBadge = remaining > 0
      const badgeSpace = needsBadge ? badgeWidth + gap : 0

      if (usedWidth + widthWithGap + badgeSpace > availableWidth && fits > 0) {
        break
      }

      usedWidth += widthWithGap
      fits++
    }

    const newMax = Math.max(1, fits)
    if (newMax !== computedMax) {
      setComputedMax(newMax)
    }
  })

  // Local filtering
  const filteredOptions = React.useMemo(() => {
    if (!searchable || !search) return options
    const q = search.toLowerCase()
    return options.filter(
      (o) =>
        o.label.toLowerCase().includes(q) ||
        o.description?.toLowerCase().includes(q)
    )
  }, [options, search, searchable])

  const toggleOption = React.useCallback(
    (optionValue: string) => {
      if (value.includes(optionValue)) {
        onChange(value.filter((v) => v !== optionValue))
      } else {
        onChange([...value, optionValue])
      }
    },
    [value, onChange]
  )

  const handleClearAll = React.useCallback(
    (e: React.MouseEvent) => {
      e.stopPropagation()
      onChange([])
    },
    [onChange]
  )

  const handleRemoveChip = React.useCallback(
    (e: React.MouseEvent, optionValue: string) => {
      e.stopPropagation()
      onChange(value.filter((v) => v !== optionValue))
    },
    [value, onChange]
  )

  const handleOpenChange = React.useCallback((nextOpen: boolean) => {
    setOpen(nextOpen)
    if (!nextOpen) {
      setSearch('')
    }
  }, [])

  // Wheel scroll fix for portaled content inside Dialog.
  // Uses requestAnimationFrame because Radix Portal defers mount.
  React.useEffect(() => {
    if (!open) return
    let cancelled = false
    let removeHandler: (() => void) | undefined

    requestAnimationFrame(() => {
      if (cancelled) return
      const content = contentRef.current
      const list = listRef.current
      if (!content || !list) return

      const handleWheel = (e: WheelEvent) => {
        if (!content.contains(e.target as Node)) return
        const { scrollTop, scrollHeight, clientHeight } = list
        if (scrollHeight <= clientHeight) return
        e.preventDefault()
        e.stopPropagation()
        list.scrollTop = Math.max(0, Math.min(scrollTop + e.deltaY, scrollHeight - clientHeight))
      }

      document.addEventListener('wheel', handleWheel, { passive: false, capture: true })
      removeHandler = () => document.removeEventListener('wheel', handleWheel, { capture: true } as EventListenerOptions)
    })

    return () => {
      cancelled = true
      removeHandler?.()
    }
  }, [open])

  const side = dropdownPosition === 'top' ? ('top' as const) : ('bottom' as const)
  const avoidCollisions = dropdownPosition === 'auto'

  const visibleChips = selectedOptions.slice(0, computedMax)
  const overflowCount = selectedOptions.length - computedMax

  return (
    <Popover open={open} onOpenChange={handleOpenChange}>
      <div className="relative">
        <PopoverTrigger asChild>
          <button
            type="button"
            disabled={disabled}
            className={cn(
              'flex w-full items-center justify-between rounded-md border-2 bg-background px-3 text-sm transition-colors',
              'focus:outline-none focus:border-primary',
              'disabled:cursor-not-allowed disabled:opacity-50',
              label ? 'min-h-[3rem] pt-4 pb-1.5' : 'min-h-[2.25rem] py-1.5',
              error ? 'border-red-500' : 'border-border',
              open && !error && 'border-primary'
            )}
          >
            <div ref={chipsRef} className="flex gap-1 items-center flex-1 overflow-hidden">
              {selectedOptions.length > 0 ? (
                <>
                  {visibleChips.map((option) => (
                    <span
                      key={option.value}
                      data-chip
                      className="inline-flex items-center gap-1 max-w-[150px] shrink-0 rounded-sm bg-primary/10 px-1.5 py-0.5 text-xs font-medium text-primary"
                    >
                      {option.icon && (
                        <option.icon className="h-3 w-3 shrink-0" />
                      )}
                      <span className="truncate">{option.label}</span>
                      <X
                        className="h-3 w-3 shrink-0 cursor-pointer hover:text-destructive"
                        onClick={(e) => handleRemoveChip(e, option.value)}
                      />
                    </span>
                  ))}
                  {overflowCount > 0 && (
                    <span data-badge className="inline-flex items-center justify-center h-5 min-w-5 px-1.5 shrink-0 rounded-full bg-gray-100 text-gray-500 text-[10px] font-medium">
                      +{overflowCount}
                    </span>
                  )}
                </>
              ) : (
                <span className="text-muted-foreground">{placeholder}</span>
              )}
            </div>
            <div className="flex items-center gap-1 ml-1 shrink-0">
              {clearable && selectedOptions.length > 0 && (
                <X
                  className="h-4 w-4 text-muted-foreground hover:text-foreground cursor-pointer"
                  onClick={handleClearAll}
                />
              )}
              <ChevronDown className={cn('h-4 w-4 opacity-50 transition-transform', open && 'rotate-180')} />
            </div>
          </button>
        </PopoverTrigger>

        {label && (
          <label
            className={cn(
              'absolute left-3 top-[-6px] text-xs font-medium bg-background px-1 inline-flex items-center gap-1',
              tooltip ? 'pointer-events-auto' : 'pointer-events-none',
              error ? 'text-red-500' : 'text-foreground'
            )}
          >
            {label}
            {required && <span className="text-red-500 ml-0.5">*</span>}
            {tooltip && <FieldTooltipIcon tooltip={tooltip} />}
          </label>
        )}
      </div>

      <PopoverContent
        ref={contentRef}
        side={side}
        align="start"
        sideOffset={4}
        avoidCollisions={avoidCollisions}
        collisionPadding={16}
        className="p-0 overflow-hidden flex flex-col"
        style={{
          minWidth: 'var(--radix-popover-trigger-width)',
          width: 'fit-content',
          maxWidth: 'var(--radix-popover-content-available-width, 100%)',
          maxHeight: 'min(340px, var(--radix-popover-content-available-height, 340px))',
        }}
        onOpenAutoFocus={(e) => {
          e.preventDefault()
          if (searchable) {
            setTimeout(() => searchRef.current?.focus(), 0)
          }
        }}
      >
        {searchable && (
          <div className="flex items-center gap-2 px-3 py-2 border-b border-border">
            <Search className="h-4 w-4 shrink-0 text-muted-foreground" />
            <input
              ref={searchRef}
              type="text"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder={searchPlaceholder}
              className="flex-1 bg-transparent text-sm outline-none placeholder:text-muted-foreground"
            />
          </div>
        )}

        <div
          ref={listRef}
          className="overflow-y-auto overscroll-contain min-h-0 flex-1"
        >
          <div className="p-1">
            {filteredOptions.length === 0 && !loading ? (
              <p className="py-4 text-center text-sm text-muted-foreground">
                {emptyText}
              </p>
            ) : (
              filteredOptions.map((option) => {
                const isSelected = value.includes(option.value)
                const isDisabled = option.disabled || disabled

                return (
                  <button
                    key={option.value}
                    type="button"
                    disabled={isDisabled}
                    onClick={() => toggleOption(option.value)}
                    className={cn(
                      'flex w-full items-center gap-2 rounded-sm px-2 text-left text-sm outline-none',
                      'cursor-pointer hover:bg-accent hover:text-accent-foreground',
                      isSelected && 'bg-accent/50',
                      isDisabled && 'pointer-events-none opacity-50',
                      option.description ? 'py-2' : 'py-1.5'
                    )}
                  >
                    {option.icon && (
                      <div className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-primary/10">
                        <option.icon className="h-3 w-3 text-primary" />
                      </div>
                    )}

                    <div className="min-w-0 flex-1">
                      <span className="block leading-tight">{option.label}</span>
                      {option.description && (
                        <span className="block text-xs leading-tight text-muted-foreground">{option.description}</span>
                      )}
                    </div>

                    {isSelected && (
                      <Check className="h-4 w-4 shrink-0 text-primary" />
                    )}
                  </button>
                )
              })
            )}

            {loading && (
              <div className="flex items-center justify-center py-3">
                <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />
              </div>
            )}
          </div>
        </div>
      </PopoverContent>
    </Popover>
  )
}
