'use client'

import * as React from 'react'
import type { FieldValues, UseFormReturn, SubmitHandler, SubmitErrorHandler } from 'react-hook-form'
import { FormProvider } from 'react-hook-form'
import { cn } from '../../utils/cn'

// ============================================
// FORM ROOT COMPONENT
// ============================================

interface FormRootProps<T extends FieldValues = FieldValues>
  extends Omit<React.FormHTMLAttributes<HTMLFormElement>, 'onSubmit' | 'onError'> {
  form: UseFormReturn<T, any, any>
  onSubmit: SubmitHandler<T>
  onError?: SubmitErrorHandler<T>
}

function FormRoot<T extends FieldValues = FieldValues>({
  form,
  onSubmit,
  onError,
  children,
  className,
  ...props
}: FormRootProps<T>) {
  return (
    <FormProvider {...form}>
      <form
        onSubmit={form.handleSubmit(onSubmit, onError)}
        className={cn('space-y-4', className)}
        {...props}
      >
        {children}
      </form>
    </FormProvider>
  )
}

FormRoot.displayName = 'Form'

// ============================================
// COMPOUND COMPONENT EXPORTS
// ============================================

import { FormInput } from './FormInput'
import { FormSelect } from './FormSelect'
import { FormMultiSelect } from './FormMultiSelect'
import { FormTextarea } from './FormTextarea'
import { FormCheckbox } from './FormCheckbox'
import { FormSwitch } from './FormSwitch'
import { FormRadioGroup } from './FormRadioGroup'
import { FormNumberStepper } from './FormNumberStepper'
import { FormLabel, FormDescription, FormError, FormFieldWrapper } from './FormParts'
import { FormFieldProvider, useFormContext, useFormFieldContext } from './FormContext'

// Compound component
export const Form = Object.assign(FormRoot, {
  // Campos com auto-bind
  Input: FormInput,
  Select: FormSelect,
  MultiSelect: FormMultiSelect,
  Textarea: FormTextarea,
  Checkbox: FormCheckbox,
  Switch: FormSwitch,
  RadioGroup: FormRadioGroup,
  NumberStepper: FormNumberStepper,

  // Partes auxiliares
  Label: FormLabel,
  Description: FormDescription,
  Error: FormError,
  FieldWrapper: FormFieldWrapper,
  Field: FormFieldProvider,
})

// Export hooks
export { useFormContext, useFormFieldContext }

// Export types
export type { FormRootProps }
