import * as React from 'react'
import { motion } from 'framer-motion'
import { Inbox } from 'lucide-react'
import { cva, type VariantProps } from 'class-variance-authority'
import { cn } from '../../utils/cn'
import { Button } from '../Button'

const emptyStateVariants = cva(
  'flex items-center justify-center p-8 text-center w-full',
  {
    variants: {
      layout: {
        vertical: 'flex-col',
        horizontal: 'flex-row gap-4 px-4 py-3',
      },
    },
    defaultVariants: {
      layout: 'vertical',
    },
  }
)

const iconWrapperVariants = cva('rounded-full bg-primary/5', {
  variants: {
    size: {
      default: 'mb-3 p-6',
      sm: 'mb-4 p-3',
    },
    layout: {
      vertical: '',
      horizontal: 'mb-0',
    },
  },
  defaultVariants: {
    size: 'default',
    layout: 'vertical',
  },
})

const iconVariants = cva('text-primary', {
  variants: {
    size: {
      default: 'h-10 w-10',
      sm: 'h-8 w-8',
    },
  },
  defaultVariants: {
    size: 'default',
  },
})

const titleVariants = cva('font-semibold text-foreground', {
  variants: {
    size: {
      default: 'text-lg',
      sm: 'text-base',
    },
  },
  defaultVariants: {
    size: 'default',
  },
})

const descriptionVariants = cva('text-muted-foreground', {
  variants: {
    size: {
      default: 'mb-6 text-sm',
      sm: 'mb-4 text-xs',
    },
    layout: {
      vertical: '',
      horizontal: 'mb-0',
    },
  },
  defaultVariants: {
    size: 'default',
    layout: 'vertical',
  },
})

export interface EmptyStateProps extends VariantProps<typeof emptyStateVariants> {
  message?: string
  description?: string
  icon?: React.ComponentType<any>
  actionLabel?: string
  onAction?: () => void
  hideDescription?: boolean
  size?: 'default' | 'sm'
  className?: string
  animated?: boolean
}

const defaultDescriptionMessage =
  'Não se preocupe, isso é normal quando não há itens para exibir.'

// Animações memoizadas
const containerAnimation = {
  initial: { opacity: 0, y: 20 },
  animate: { opacity: 1, y: 0 },
  transition: { duration: 0.5 },
}

const iconAnimation = {
  whileHover: { scale: 1.1 },
  whileTap: { scale: 0.9 },
}

// Componente interno sem animação (para performance)
const EmptyStateContent = React.memo<EmptyStateProps>(
  ({
    message = 'Nenhum item encontrado',
    description,
    icon: IconComponent = Inbox,
    actionLabel,
    onAction,
    hideDescription = false,
    size = 'default',
    layout = 'vertical',
    className,
  }) => {
    const handleAction = React.useCallback(() => {
      if (onAction) {
        onAction()
      }
    }, [onAction])

    return (
      <div className={cn(emptyStateVariants({ layout }), className)}>
        <div className={iconWrapperVariants({ size, layout })}>
          <IconComponent
            className={iconVariants({ size })}
            aria-hidden="true"
          />
        </div>

        <div
          className={cn(
            layout === 'horizontal' && 'flex flex-col items-start text-left'
          )}
        >
          <h3 className={titleVariants({ size })}>{message}</h3>

          {!hideDescription && (
            <p className={descriptionVariants({ size, layout })}>
              {description || defaultDescriptionMessage}
            </p>
          )}
        </div>

        {actionLabel && onAction && (
          <Button onClick={handleAction} className="mt-2">
            {actionLabel}
          </Button>
        )}
      </div>
    )
  }
)

EmptyStateContent.displayName = 'EmptyStateContent'

// Componente com animação
const AnimatedEmptyState = React.memo<EmptyStateProps>((props) => {
  const {
    message = 'Nenhum item encontrado',
    description,
    icon: IconComponent = Inbox,
    actionLabel,
    onAction,
    hideDescription = false,
    size = 'default',
    layout = 'vertical',
    className,
  } = props

  const handleAction = React.useCallback(() => {
    if (onAction) {
      onAction()
    }
  }, [onAction])

  return (
    <motion.div
      {...containerAnimation}
      className={cn(emptyStateVariants({ layout }), className)}
    >
      <motion.div
        {...iconAnimation}
        className={iconWrapperVariants({ size, layout })}
      >
        <IconComponent
          className={iconVariants({ size })}
          aria-hidden="true"
        />
      </motion.div>

      <div
        className={cn(
          layout === 'horizontal' && 'flex flex-col items-start text-left'
        )}
      >
        <h3 className={titleVariants({ size })}>{message}</h3>

        {!hideDescription && (
          <p className={descriptionVariants({ size, layout })}>
            {description || defaultDescriptionMessage}
          </p>
        )}
      </div>

      {actionLabel && onAction && (
        <Button onClick={handleAction} className="mt-2">
          {actionLabel}
        </Button>
      )}
    </motion.div>
  )
})

AnimatedEmptyState.displayName = 'AnimatedEmptyState'

// Componente principal que escolhe versão animada ou não
export const EmptyState = React.memo<EmptyStateProps>(
  ({ animated = true, ...props }) => {
    if (!animated) {
      return <EmptyStateContent {...props} />
    }
    return <AnimatedEmptyState {...props} />
  }
)

EmptyState.displayName = 'EmptyState'
