import * as React from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Pin, PinOff } from 'lucide-react'
import { cn } from '../../utils/cn'
import { useSidebar } from './SidebarContext'
import type { SidebarHeaderProps } from './types'

export const SidebarHeader = React.memo<SidebarHeaderProps>(function SidebarHeader({
  logo,
  collapsedLogo,
  title,
  showPinButton = true,
  className,
}) {
  const { expanded, pinned, setPinned } = useSidebar()

  const handleTogglePin = React.useCallback(() => {
    setPinned(!pinned)
  }, [pinned, setPinned])

  return (
    <div
      className={cn(
        'flex items-center justify-between h-[60px] border-b border-border bg-primary px-3',
        className
      )}
    >
      <div className="flex items-center gap-2 overflow-hidden">
        {/* Collapsed Logo */}
        <AnimatePresence mode="wait">
          {!expanded && collapsedLogo && (
            <motion.div
              key="collapsed-logo"
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.8 }}
              transition={{ duration: 0.15 }}
              className="flex items-center justify-center"
            >
              {collapsedLogo}
            </motion.div>
          )}
        </AnimatePresence>

        {/* Expanded Logo + Title */}
        <AnimatePresence>
          {expanded && (
            <motion.div
              initial={{ opacity: 0, x: -10 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -10 }}
              transition={{ duration: 0.2 }}
              className="flex items-center gap-2"
            >
              {logo && <div className="flex-shrink-0">{logo}</div>}
              {title && (
                <span className="text-sm font-semibold text-primary-foreground whitespace-nowrap">
                  {title}
                </span>
              )}  
            </motion.div>
          )}
        </AnimatePresence>

        {/* Fallback: Show collapsed logo if no expanded logo */}
        {expanded && !logo && collapsedLogo && (
          <div className="flex items-center gap-2">
            {collapsedLogo}
            {title && (
              <motion.span
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -10 }}
                transition={{ duration: 0.2 }}
                className="text-sm font-semibold text-primary-foreground whitespace-nowrap"
              >
                {title}
              </motion.span>
            )}
          </div>
        )}
      </div>

      {/* Pin Button */}
      <AnimatePresence>
        {showPinButton && expanded && (
          <motion.button
            initial={{ opacity: 0, scale: 0.8 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.8 }}
            transition={{ duration: 0.15 }}
            onClick={handleTogglePin}
            className={cn(
              'flex h-6 w-6 items-center justify-center rounded-md transition-colors',
              'hover:bg-primary-foreground/10',
              // pinned ? '' : 'text-primary-foreground/60'
            )}
            title={pinned ? 'Unpin sidebar' : 'Pin sidebar'}
          >
            {pinned ? (
              <PinOff className="h-3.5 w-3.5" />
            ) : (
              <Pin className="h-3.5 w-3.5" />
            )}
          </motion.button>
        )}
      </AnimatePresence>
    </div>
  )
})

SidebarHeader.displayName = 'Sidebar.Header'
