import * as React from 'react'
import { Info } from 'lucide-react'
import { useFormFieldContextOptional } from './FormContext'
import { cn } from '../../utils/cn'
import { TooltipRoot, TooltipTrigger, TooltipContent } from '../Tooltip'
import type { FieldTooltip } from './types'

// ============================================
// FORM LABEL
// ============================================

export interface FormLabelProps extends React.LabelHTMLAttributes<HTMLLabelElement> {
  required?: boolean
}

export const FormLabel = React.forwardRef<HTMLLabelElement, FormLabelProps>(
  ({ className, required, children, ...props }, ref) => {
    const fieldContext = useFormFieldContextOptional()

    return (
      <label
        ref={ref}
        htmlFor={fieldContext?.id}
        className={cn(
          'text-sm font-medium leading-none',
          fieldContext?.error && 'text-red-500',
          className
        )}
        {...props}
      >
        {children}
        {(required || fieldContext?.isRequired) && (
          <span className="text-red-500 ml-0.5">*</span>
        )}
      </label>
    )
  }
)

FormLabel.displayName = 'Form.Label'

// ============================================
// FORM DESCRIPTION
// ============================================

export interface FormDescriptionProps extends React.HTMLAttributes<HTMLParagraphElement> {}

export const FormDescription = React.forwardRef<
  HTMLParagraphElement,
  FormDescriptionProps
>(({ className, ...props }, ref) => {
  const fieldContext = useFormFieldContextOptional()

  // Não mostra descrição se tem erro
  if (fieldContext?.error) {
    return null
  }

  return (
    <p
      ref={ref}
      className={cn('text-xs text-muted-foreground', className)}
      {...props}
    />
  )
})

FormDescription.displayName = 'Form.Description'

// ============================================
// FORM ERROR
// ============================================

export interface FormErrorProps extends React.HTMLAttributes<HTMLParagraphElement> {
  message?: string
}

export const FormError = React.forwardRef<HTMLParagraphElement, FormErrorProps>(
  ({ className, message, children, ...props }, ref) => {
    const fieldContext = useFormFieldContextOptional()
    const errorMessage = message ?? fieldContext?.error

    if (!errorMessage && !children) {
      return null
    }

    return (
      <p
        ref={ref}
        className={cn('text-xs text-red-500', className)}
        {...props}
      >
        {children || errorMessage}
      </p>
    )
  }
)

FormError.displayName = 'Form.Error'

// ============================================
// FORM FIELD WRAPPER
// ============================================

export interface FormFieldWrapperProps extends React.HTMLAttributes<HTMLDivElement> {
  label?: string
  description?: string
  required?: boolean
  error?: string
}

export const FormFieldWrapper = React.forwardRef<
  HTMLDivElement,
  FormFieldWrapperProps
>(({ className, label, description, required, error, children, ...props }, ref) => {
  return (
    <div ref={ref} className={cn('space-y-1', className)} {...props}>
      {label && <FormLabel required={required}>{label}</FormLabel>}
      {children}
      {description && <FormDescription>{description}</FormDescription>}
      {error && <FormError message={error} />}
    </div>
  )
})

FormFieldWrapper.displayName = 'Form.FieldWrapper'

// ============================================
// FIELD TOOLTIP ICON
// ============================================

export function FieldTooltipIcon({ tooltip }: { tooltip: FieldTooltip }) {
  return (
    <TooltipRoot delayDuration={200}>
      <TooltipTrigger asChild>
        <Info className="h-3 w-3 text-primary cursor-help shrink-0" />
      </TooltipTrigger>
      <TooltipContent side="top" size="md">
        {typeof tooltip === 'string' ? (
          <span className="text-xs">{tooltip}</span>
        ) : (
          <div className="space-y-0.5">
            <p className="text-xs font-semibold leading-snug">{tooltip.title}</p>
            <p className="text-xs text-muted-foreground leading-snug">{tooltip.description}</p>
          </div>
        )}
      </TooltipContent>
    </TooltipRoot>
  )
}
