import { cn } from '../../utils/cn'
import { useDataTableSelection, useDataTableMeta, useDataTable } from './DataTableContext'
import type { DataTableBulkActionsProps } from './types'
import { Button } from '../Button'
import { X } from 'lucide-react'

// ============================================================================
// BULK ACTIONS COMPONENT - Barra de ações quando rows selecionadas
// ============================================================================
//
// Uso:
// <DataTable.BulkActions>
//   {(selectedRows) => (
//     <>
//       <span>{selectedRows.length} selecionados</span>
//       <Button onClick={() => handleDelete(selectedRows)}>Deletar</Button>
//     </>
//   )}
// </DataTable.BulkActions>
//
// ============================================================================

export function DataTableBulkActions<TData extends Record<string, unknown>>({
  children,
  className,
}: DataTableBulkActionsProps<TData>) {
  const table = useDataTable<TData>()
  const { selectedRowCount } = useDataTableMeta()
  const selectedRows = useDataTableSelection<TData>()

  // Não renderiza se não há seleção
  if (selectedRowCount === 0) {
    return null
  }

  const handleClearSelection = () => {
    table.toggleAllRowsSelected(false)
  }

  return (
    <div
      className={cn(
        'flex items-center gap-3 rounded-lg border bg-muted/50 p-3',
        'animate-in fade-in-0 slide-in-from-top-2',
        className
      )}
    >
      <div className="flex items-center gap-2">
        <span className="text-sm font-medium">
          {selectedRowCount} {selectedRowCount === 1 ? 'item selecionado' : 'itens selecionados'}
        </span>
        <Button
          variant="ghost"
          size="sm"
          className="h-7 px-2"
          onClick={handleClearSelection}
        >
          <X className="h-4 w-4 mr-1" />
          Limpar
        </Button>
      </div>

      <div className="h-5 w-px bg-border" />

      <div className="flex items-center gap-2">
        {children(selectedRows)}
      </div>
    </div>
  )
}

DataTableBulkActions.displayName = 'DataTable.BulkActions'
