import * as React from 'react'
import { cn } from '../../utils/cn'

export interface PageHeaderProps {
  /** Título da página */
  title: string

  /** Descrição/subtítulo */
  description: string

  /** Ações (botões) no lado direito */
  children?: React.ReactNode

  /** Custom className */
  className?: string
}

export const PageHeader = React.memo(function PageHeader({
  title,
  description,
  children,
  className,
}: PageHeaderProps) {
  return (
    <div
      className={cn(
        'px-3 py-4 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4',
        className
      )}
    >
      <div className="flex flex-col leading-none">
        <span className="text-3xl font-semibold font-heading">{title}</span>
        <span className="text-[1.05rem] text-muted-foreground max-w-lg text-balance leading-relaxed">
          {description}
        </span>
      </div>
      {children && (
        <div className="flex gap-3 mt-2 sm:mt-0 shrink-0">{children}</div>
      )}
    </div>
  )
})

PageHeader.displayName = 'PageHeader'
