// ============================================================================
// COMPOUND COMPONENT PATTERN - Enterprise DataTable
// ============================================================================
//
// Uso com Composição Explícita:
//
// <DataTable data={data} columns={columns}>
//   <DataTable.Loading visible={isLoading} />
//   <DataTable.Toolbar>
//     <DataTable.Search placeholder="Buscar..." />
//     <DataTable.Filters>
//       <DataTable.Filter column="status" options={statusOptions} />
//     </DataTable.Filters>
//     <DataTable.ColumnVisibility />
//     <DataTable.DensityToggle />
//     <DataTable.Export formats={['csv']} />
//   </DataTable.Toolbar>
//   <DataTable.BulkActions>
//     {(selectedRows) => <Button>Deletar {selectedRows.length}</Button>}
//   </DataTable.BulkActions>
//   <DataTable.Content />
//   <DataTable.Pagination mode="server" pageCount={10} />
// </DataTable>
//
// ============================================================================

import { DataTableRoot } from './DataTable'
import { DataTableContent } from './DataTableContent'
import { DataTableToolbar } from './DataTableToolbar'
import { DataTableSearch } from './DataTableSearch'
import { DataTableFilters, DataTableFilter } from './DataTableFilters'
import { DataTablePagination } from './DataTablePagination'
import { DataTableEmptyState } from './DataTableEmptyState'
import { DataTableLoading } from './DataTableLoading'
import { DataTableColumnHeader } from './DataTableColumnHeader'
import { DataTableColumnVisibility } from './DataTableColumnVisibility'
import { DataTableDensityToggle } from './DataTableDensityToggle'
import { DataTableBulkActions } from './DataTableBulkActions'
import { DataTableExport } from './DataTableExport'
import { DataTableTabs } from './DataTableTabs'

// ============================================================================
// COMPOUND COMPONENT - Use como: <DataTable><DataTable.Content /></DataTable>
// ============================================================================

export const DataTable = Object.assign(DataTableRoot, {
  // Estado
  Loading: DataTableLoading,
  EmptyState: DataTableEmptyState,

  // Layout
  Tabs: DataTableTabs,
  Toolbar: DataTableToolbar,
  Content: DataTableContent,

  // Search & Filter
  Search: DataTableSearch,
  Filters: DataTableFilters,
  Filter: DataTableFilter,

  // Pagination
  Pagination: DataTablePagination,

  // Actions
  BulkActions: DataTableBulkActions,

  // Preferences
  ColumnVisibility: DataTableColumnVisibility,
  DensityToggle: DataTableDensityToggle,
  Export: DataTableExport,

  // Column utilities (para uso em column definitions)
  ColumnHeader: DataTableColumnHeader,
})

// ============================================================================
// PRIMITIVE TABLE COMPONENTS - Base table components
// ============================================================================

export {
  Table,
  TableHeader,
  TableBody,
  TableFooter,
  TableHead,
  TableRow,
  TableCell,
  TableCaption,
} from './Table'

// ============================================================================
// CONTEXT & HOOKS - Acesso aos dados da tabela
// ============================================================================

export {
  // Hooks principais
  useDataTable,
  useDataTableMeta,
  useDataTableDensity,

  // Hooks especializados
  useDataTableLoading,
  useDataTableEmpty,
  useDataTableSelection,
  useDataTablePagination,
  useDataTableSorting,
  useDataTableColumnVisibility,

  // Aliases para compatibilidade
  useDataTableInstance,
  useDataTableState,
} from './DataTableContext'

// Re-exports from @tanstack/react-table
export { flexRender } from './hooks/useDataTable'
export type { ColumnDef } from '@tanstack/react-table'

// Utilities
export { useDebounce, useDebouncedCallback } from './hooks/useDebounce'

// ============================================================================
// TYPES
// ============================================================================

export type {
  // Root props
  DataTableProps,

  // State types
  DataTableState,
  DataTableMeta,
  DataTableDensity,

  // Component props
  DataTableContentProps,
  DataTableToolbarProps,
  DataTableSearchProps,
  DataTableFiltersProps,
  DataTableFilterProps,
  DataTableFilterOption,
  DataTablePaginationProps,
  DataTablePaginationMode,
  DataTableEmptyStateProps,
  DataTableLoadingProps,
  DataTableColumnHeaderProps,
  DataTableBulkActionsProps,
  DataTableColumnVisibilityProps,
  DataTableDensityToggleProps,
  DataTableExportProps,
  DataTableExportFormat,
  DataTableRowActionsProps,
  DataTableTabsProps,
  DataTableTab,

  // Context types
  DataTableContextValue,

  // Hook config types
  UseDataTableConfig,

  // Pagination types (para integração com API)
  PaginationMeta,
  PaginatedResponse,
  PaginationParams,
} from './types'

// Constante exportada separadamente (não é tipo)
export { DENSITY_CONFIG } from './types'
