'use client';

import {
  createContext,
  useContext,
  useState,
  useCallback,
  useMemo,
  type ReactNode,
} from 'react';
import type { FieldValues, Path } from 'react-hook-form';
import type { WizardContextValue, WizardProps } from './types';

// Create context with undefined default
const WizardContext = createContext<WizardContextValue<any> | undefined>(undefined);

/**
 * Hook to access wizard context
 * @throws Error if used outside of Wizard component
 */
export function useWizardContext<T extends FieldValues = FieldValues>(): WizardContextValue<T> {
  const context = useContext(WizardContext) as WizardContextValue<T> | undefined;

  if (context === undefined) {
    throw new Error('useWizardContext must be used within a Wizard component');
  }

  return context;
}

/**
 * Optional hook that returns undefined if outside wizard context
 */
export function useWizardContextOptional<T extends FieldValues = FieldValues>(): WizardContextValue<T> | undefined {
  return useContext(WizardContext) as WizardContextValue<T> | undefined;
}

interface WizardProviderProps<T extends FieldValues> extends WizardProps<T> {
  children: ReactNode;
}

/**
 * Wizard context provider component
 */
export function WizardProvider<T extends FieldValues>({
  children,
  form,
  steps,
  initialStep = 0,
  onStepChange,
  validateOnNext = true,
  allowJumpToStep = false,
}: WizardProviderProps<T>) {
  // Track completed steps
  const [completedSteps, setCompletedSteps] = useState<Set<number>>(new Set());

  // Calculate active (visible) steps based on form data
  const activeSteps = useMemo(() => {
    const formValues = form.getValues();
    return steps.filter((step) => {
      if (typeof step.isHidden === 'function') {
        return !step.isHidden(formValues);
      }
      return !step.isHidden;
    });
  }, [steps, form]);

  // Current step state (index within activeSteps)
  const [currentStep, setCurrentStep] = useState(() => {
    // Ensure initial step is within bounds
    return Math.min(Math.max(0, initialStep), activeSteps.length - 1);
  });

  // Computed values
  const totalSteps = activeSteps.length;
  const isFirstStep = currentStep === 0;
  const isLastStep = currentStep === totalSteps - 1;
  const progress = totalSteps > 0 ? Math.round(((currentStep + 1) / totalSteps) * 100) : 0;
  const currentStepConfig = activeSteps[currentStep];

  /**
   * Get step configuration by index
   */
  const getStepConfig = useCallback(
    (index: number) => activeSteps[index],
    [activeSteps]
  );

  /**
   * Get step configuration by name
   */
  const getStepByName = useCallback(
    (name: string) => activeSteps.find((step) => step.name === name || step.id === name),
    [activeSteps]
  );

  /**
   * Get step index by name
   */
  const getStepIndexByName = useCallback(
    (name: string) => activeSteps.findIndex((step) => step.name === name || step.id === name),
    [activeSteps]
  );

  /**
   * Check if step is completed
   */
  const isStepCompleted = useCallback(
    (index: number) => completedSteps.has(index),
    [completedSteps]
  );

  /**
   * Check if step has errors
   */
  const hasStepErrors = useCallback(
    (index: number) => {
      const stepConfig = activeSteps[index];
      if (!stepConfig?.fields) return false;

      const errors = form.formState.errors;
      return stepConfig.fields.some((field) => {
        const fieldPath = field as string;
        return fieldPath in errors;
      });
    },
    [activeSteps, form.formState.errors]
  );

  /**
   * Validate current step fields
   */
  const validateCurrentStep = useCallback(async (): Promise<boolean> => {
    const stepConfig = currentStepConfig;

    // If no validation schema, consider valid
    if (!stepConfig?.validationSchema) {
      return true;
    }

    const formValues = form.getValues();
    const result = await stepConfig.validationSchema.safeParseAsync(formValues);

    if (!result.success) {
      // Trigger validation only for fields in current step
      // This respects the form's mode (onTouched, onBlur, etc.)
      if (stepConfig.fields) {
        await Promise.all(
          stepConfig.fields.map((field) => form.trigger(field as Path<T>))
        );
      }
      return false;
    }

    // Clear errors for current step fields on success
    if (stepConfig.fields) {
      stepConfig.fields.forEach((field) => {
        form.clearErrors(field as Path<T>);
      });
    }

    return true;
  }, [currentStepConfig, form]);

  /**
   * Navigate to next step
   */
  const goToNextStep = useCallback(async (): Promise<boolean> => {
    // Already at last step
    if (isLastStep) {
      return false;
    }

    // Validate if required
    if (validateOnNext) {
      const isValid = await validateCurrentStep();
      if (!isValid) {
        return false;
      }
    }

    // Mark current step as completed
    setCompletedSteps((prev) => new Set([...prev, currentStep]));

    // Advance to next step
    const nextStep = currentStep + 1;
    setCurrentStep(nextStep);
    onStepChange?.(nextStep, 'next');

    return true;
  }, [isLastStep, validateOnNext, validateCurrentStep, currentStep, onStepChange]);

  /**
   * Navigate to previous step
   */
  const goToPrevStep = useCallback(() => {
    if (isFirstStep) {
      return;
    }

    const prevStep = currentStep - 1;
    setCurrentStep(prevStep);
    onStepChange?.(prevStep, 'prev');
  }, [isFirstStep, currentStep, onStepChange]);

  /**
   * Navigate to specific step
   */
  const goToStep = useCallback(
    async (targetStep: number): Promise<boolean> => {
      // Validate target step is in bounds
      if (targetStep < 0 || targetStep >= totalSteps) {
        return false;
      }

      // Check if jumping is allowed
      if (!allowJumpToStep && targetStep > currentStep) {
        // Can only jump forward if all previous steps are completed
        for (let i = currentStep; i < targetStep; i++) {
          if (!completedSteps.has(i)) {
            return false;
          }
        }
      }

      // If jumping backward, always allowed
      if (targetStep < currentStep) {
        setCurrentStep(targetStep);
        onStepChange?.(targetStep, 'jump');
        return true;
      }

      // If jumping forward, validate current step first
      if (validateOnNext && targetStep > currentStep) {
        const isValid = await validateCurrentStep();
        if (!isValid) {
          return false;
        }
        // Mark current as completed
        setCompletedSteps((prev) => new Set([...prev, currentStep]));
      }

      setCurrentStep(targetStep);
      onStepChange?.(targetStep, 'jump');
      return true;
    },
    [totalSteps, allowJumpToStep, currentStep, completedSteps, validateOnNext, validateCurrentStep, onStepChange]
  );

  /**
   * Reset wizard to initial state
   */
  const reset = useCallback(() => {
    setCurrentStep(Math.min(Math.max(0, initialStep), activeSteps.length - 1));
    setCompletedSteps(new Set());
    form.reset();
  }, [initialStep, activeSteps.length, form]);

  // Build context value
  const contextValue: WizardContextValue<T> = useMemo(
    () => ({
      // State
      currentStep,
      totalSteps,
      activeSteps,
      allSteps: steps,

      // Computed
      isFirstStep,
      isLastStep,
      progress,

      // Navigation
      goToNextStep,
      goToPrevStep,
      goToStep,
      reset,

      // Validation
      validateCurrentStep,
      isStepCompleted,
      hasStepErrors,

      // Form
      form,

      // Step info
      currentStepConfig,
      getStepConfig,
      getStepByName,
      getStepIndexByName,

      // Settings
      allowJumpToStep,
    }),
    [
      currentStep,
      totalSteps,
      activeSteps,
      steps,
      isFirstStep,
      isLastStep,
      progress,
      goToNextStep,
      goToPrevStep,
      goToStep,
      reset,
      validateCurrentStep,
      isStepCompleted,
      hasStepErrors,
      form,
      currentStepConfig,
      getStepConfig,
      getStepByName,
      getStepIndexByName,
      allowJumpToStep,
    ]
  );

  return (
    <WizardContext.Provider value={contextValue}>
      {children}
    </WizardContext.Provider>
  );
}

export { WizardContext };
