import * as React from 'react'
import type { DataTableEmptyStateProps } from './types'
import { useDataTableEmptyStateConfig } from './DataTableContext'

// ============================================================================
// EMPTY STATE COMPONENT - Registra config no context
// ============================================================================
//
// Não renderiza nada diretamente. Passa suas props para o context,
// e o DataTableContent renderiza o EmptyState standalone quando vazio.
//
// Uso:
// <DataTable data={data} columns={columns}>
//   <DataTable.Content />
//   <DataTable.EmptyState
//     title="Nenhum orçamento"
//     description="Crie um orçamento a partir de uma OS."
//   />
// </DataTable>
//
// ============================================================================

export const DataTableEmptyState = React.memo(function DataTableEmptyState({
  title,
  description,
  icon,
  action,
}: DataTableEmptyStateProps) {
  const { setConfig } = useDataTableEmptyStateConfig()

  React.useLayoutEffect(() => {
    setConfig({ title, description, icon, action })
    return () => setConfig({})
  }, [title, description, icon, action, setConfig])

  return null
})

DataTableEmptyState.displayName = 'DataTable.EmptyState'
