/**
 * Facter Design System - Theme Presets
 *
 * Temas disponíveis:
 * - default: Neutro (shadcn default)
 * - truck: Azul (Facter Truck)
 * - vagas: Roxo (Facter Vagas)
 * - techcare: Verde (Facter TechCare)
 *
 * Uso no projeto:
 * ```css
 * // globals.css
 * @import '@facter/ds-core/themes/base.css';
 * @import '@facter/ds-core/themes/default.css';
 * @tailwind base;
 * @tailwind components;
 * @tailwind utilities;
 * ```
 */

export const FACTER_THEMES = {
  default: 'default',
  truck: 'truck',
  vagas: 'vagas',
  techcare: 'techcare',
} as const

export type FacterTheme = keyof typeof FACTER_THEMES

