import * as React from 'react'
import { cva, type VariantProps } from 'class-variance-authority'
import { cn } from '../../utils/cn'
import { DialogHeader } from './Dialog'
import {
  RippleBackground,
  RippleWrapper,
  type RippleEffectProps,
} from '../RippleEffect'

// Variantes do ícone
const iconWrapperVariants = cva(
  'p-3 rounded-2xl shadow-lg transition-all duration-200',
  {
    variants: {
      variant: {
        default: 'bg-primary shadow-primary/25',
        secondary: 'bg-secondary shadow-secondary/25',
        accent: 'bg-accent shadow-accent/25',
        destructive: 'bg-red-600 shadow-red-600/25',
        success: 'bg-green-600 shadow-green-600/25',
        muted: 'bg-muted-foreground shadow-muted-foreground/25',
      },
      size: {
        sm: 'p-2',
        md: 'p-3',
        lg: 'p-4',
      },
    },
    defaultVariants: {
      variant: 'default',
      size: 'md',
    },
  }
)

const iconVariants = cva('text-white', {
  variants: {
    size: {
      sm: 'h-4 w-4',
      md: 'h-5 w-5',
      lg: 'h-6 w-6',
    },
  },
  defaultVariants: {
    size: 'md',
  },
})

// Status indicator
const statusIndicatorVariants = cva(
  'absolute -top-1 -right-0 w-4 h-4 rounded-full border-2 border-white/70 shadow-sm z-20',
  {
    variants: {
      status: {
        active: 'bg-green-500',
        inactive: 'bg-slate-500',
        warning: 'bg-yellow-500',
        error: 'bg-red-500',
      },
    },
    defaultVariants: {
      status: 'active',
    },
  }
)

export interface DialogWrapperProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof iconWrapperVariants> {
  children?: React.ReactNode
  icon?: React.ElementType<{ className?: string }>
  status?: 'active' | 'inactive' | 'warning' | 'error' | null
  showRipple?: boolean
  rippleProps?: Partial<RippleEffectProps>
  iconSize?: 'sm' | 'md' | 'lg'
}

export const DialogWrapper = React.memo<DialogWrapperProps>(
  ({
    children,
    className,
    icon: Icon,
    status,
    variant = 'default',
    size = 'md',
    iconSize = 'md',
    showRipple = true,
    rippleProps,
    ...props
  }) => {
    // Props padrão do ripple baseado na variante
    const defaultRippleProps: RippleEffectProps = React.useMemo(
      () => ({
        size: size === 'sm' ? 'md' : size === 'lg' ? 'xl' : 'lg',
        color:
          variant === 'secondary'
            ? 'secondary'
            : variant === 'accent'
              ? 'accent'
              : 'primary',
        intensity: 'light',
        rings: 3,
        ...rippleProps,
      }),
      [size, variant, rippleProps]
    )

    const backgroundRippleProps: RippleEffectProps = React.useMemo(
      () => ({
        position: 'top-right',
        size: 'xl',
        color:
          variant === 'secondary'
            ? 'secondary'
            : variant === 'accent'
              ? 'accent'
              : 'primary',
        intensity: 'light',
        rings: 5,
      }),
      [variant]
    )

    // Sem ícone: apenas background ripple
    if (!Icon) {
      return (
        <DialogHeader
          className={cn('flex flex-col justify-between px-0', className)}
          {...props}
        >
          {showRipple && <RippleBackground {...backgroundRippleProps} />}
          <div className="flex items-center gap-3 w-full">
            <div className="w-full">{children}</div>
          </div>
        </DialogHeader>
      )
    }

    // Com ícone: ripple wrapper + background
    return (
      <DialogHeader
        className={cn('flex flex-col justify-between px-0 pb-3', className)}
        {...props}
      >
        {showRipple && <RippleBackground {...backgroundRippleProps} />}
        <div className="flex items-center gap-2 w-full">
          <RippleWrapper
            rippleProps={showRipple ? defaultRippleProps : undefined}
          >
            <div className={cn(iconWrapperVariants({ variant, size }), 'mr-2')}>
              <Icon className={iconVariants({ size: iconSize })} />
            </div>
            {status && (
              <div className={statusIndicatorVariants({ status })} />
            )}
          </RippleWrapper>
          <div className="w-full">{children}</div>
        </div>
      </DialogHeader>
    )
  }
)
DialogWrapper.displayName = 'DialogWrapper'
