'use client';

import { cn } from '../../utils/cn';
import { useWizardContext } from './WizardContext';
import { WizardStepIndicator } from './WizardStepIndicator';
import { WizardStepConnector } from './WizardStepConnector';
import type { WizardStepsProps, StepState } from './types';

/**
 * Visual step indicators component
 *
 * Displays the wizard steps with their current states:
 * - Completed (checkmark, green)
 * - Current (highlighted, primary)
 * - Pending (muted)
 * - Error (red indicator)
 * - Disabled (grayed out)
 *
 * @example
 * ```tsx
 * <Wizard.Steps variant="horizontal" showDescription />
 * ```
 */
export function WizardSteps({
  variant = 'horizontal',
  showDescription = false,
  showNumbers = false,
  size = 'md',
  className,
}: WizardStepsProps) {
  const {
    activeSteps,
    currentStep,
    isStepCompleted,
    hasStepErrors,
    goToStep,
    allowJumpToStep,
  } = useWizardContext();

  /**
   * Determine the state of a step
   */
  const getStepState = (index: number): StepState => {
    const step = activeSteps[index];

    // Check if step is disabled
    if (step.isDisabled) {
      return 'disabled';
    }

    // Current step
    if (index === currentStep) {
      return hasStepErrors(index) ? 'error' : 'current';
    }

    // Completed step
    if (isStepCompleted(index)) {
      return hasStepErrors(index) ? 'error' : 'completed';
    }

    // Pending step
    return 'pending';
  };

  /**
   * Check if step is clickable
   */
  const isStepClickable = (index: number): boolean => {
    if (index === currentStep) return false;

    const step = activeSteps[index];
    if (step.isDisabled) return false;

    // Can always go back
    if (index < currentStep) return true;

    // Can jump forward only if allowed and all previous steps completed
    if (allowJumpToStep && index > currentStep) {
      for (let i = currentStep; i < index; i++) {
        if (!isStepCompleted(i)) return false;
      }
      return true;
    }

    return false;
  };

  /**
   * Handle step click
   */
  const handleStepClick = async (index: number) => {
    if (isStepClickable(index)) {
      await goToStep(index);
    }
  };

  const isHorizontal = variant === 'horizontal';

  return (
    <nav
      aria-label="Progresso do formulário"
      className={cn(
        'flex',
        isHorizontal ? 'flex-row items-center justify-center' : 'flex-col items-start',
        className
      )}
    >
      {activeSteps.map((step, index) => (
        <div
          key={step.id}
          className={cn(
            'flex',
            isHorizontal ? 'flex-row items-center' : 'flex-col',
            index !== activeSteps.length - 1 && isHorizontal && 'flex-1'
          )}
        >
          {/* Step indicator */}
          <WizardStepIndicator
            step={step}
            index={index}
            state={getStepState(index)}
            showNumber={showNumbers}
            showDescription={showDescription}
            size={size}
            isClickable={isStepClickable(index)}
            onClick={() => handleStepClick(index)}
          />

          {/* Connector line (except for last step) */}
          {index !== activeSteps.length - 1 && (
            <WizardStepConnector
              isCompleted={isStepCompleted(index)}
              variant={variant}
            />
          )}
        </div>
      ))}
    </nav>
  );
}
