'use client'

import * as React from 'react'
import { ChevronRight } from 'lucide-react'
import { cn } from '../../utils/cn'

// ============================================================================
// Actions Container
// ============================================================================

export interface ItemCardActionsProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Whether to show border on top */
  bordered?: boolean
}

const ItemCardActions = React.forwardRef<HTMLDivElement, ItemCardActionsProps>(
  ({ className, bordered = true, children, ...props }, ref) => {
    return (
      <div
        ref={ref}
        className={cn(
          'mt-auto',
          bordered && 'border-t border-border',
          className
        )}
        {...props}
      >
        {children}
      </div>
    )
  }
)

ItemCardActions.displayName = 'ItemCardActions'

// ============================================================================
// Action Button (full width)
// ============================================================================

export interface ItemCardActionButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  /** Whether to show chevron arrow */
  showArrow?: boolean
  /** Loading state */
  loading?: boolean
  /** Variant style */
  variant?: 'default' | 'primary' | 'secondary' | 'destructive'
}

const ItemCardActionButton = React.forwardRef<
  HTMLButtonElement,
  ItemCardActionButtonProps
>(
  (
    {
      className,
      showArrow = true,
      loading = false,
      variant = 'default',
      disabled,
      children,
      ...props
    },
    ref
  ) => {
    const variantClasses = {
      default:
        'bg-muted/50 text-foreground hover:bg-muted active:bg-muted/80',
      primary:
        'bg-primary/10 text-primary hover:bg-primary/20 active:bg-primary/30',
      secondary:
        'bg-secondary text-secondary-foreground hover:bg-secondary/80',
      destructive:
        'bg-red-500/10 text-red-600 hover:bg-red-500/20 active:bg-red-500/30',
    }

    return (
      <button
        ref={ref}
        type="button"
        disabled={disabled || loading}
        className={cn(
          'w-full px-6 py-3 flex items-center justify-between',
          'text-sm font-medium transition-colors',
          'focus:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2',
          'disabled:opacity-50 disabled:cursor-not-allowed',
          variantClasses[variant],
          className
        )}
        {...props}
      >
        <span>{children}</span>
        {showArrow && !loading && (
          <ChevronRight className="w-4 h-4 opacity-60" />
        )}
        {loading && (
          <div className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
        )}
      </button>
    )
  }
)

ItemCardActionButton.displayName = 'ItemCardActionButton'

// ============================================================================
// Actions Row (for multiple inline actions)
// ============================================================================

export interface ItemCardActionsRowProps extends React.HTMLAttributes<HTMLDivElement> {}

const ItemCardActionsRow = React.forwardRef<HTMLDivElement, ItemCardActionsRowProps>(
  ({ className, children, ...props }, ref) => {
    return (
      <div
        ref={ref}
        className={cn('flex items-center gap-2 p-3', className)}
        {...props}
      >
        {children}
      </div>
    )
  }
)

ItemCardActionsRow.displayName = 'ItemCardActionsRow'

export { ItemCardActions, ItemCardActionButton, ItemCardActionsRow }
