import * as React from 'react'
import { Loader, type LoaderProps } from './Loader'

interface LoaderContextValue {
  show: (options?: LoaderOptions) => void
  hide: () => void
  isLoading: boolean
}

interface LoaderOptions {
  message?: string
  variant?: LoaderProps['variant']
  scope?: LoaderProps['scope']
  isTransparentBg?: boolean
}

const LoaderContext = React.createContext<LoaderContextValue | undefined>(
  undefined
)

export function LoaderProvider({ children }: { children: React.ReactNode }) {
  const [isLoading, setIsLoading] = React.useState(false)
  const [loaderOptions, setLoaderOptions] = React.useState<LoaderOptions>({})

  const show = React.useCallback((options: LoaderOptions = {}) => {
    setLoaderOptions(options)
    setIsLoading(true)
  }, [])

  const hide = React.useCallback(() => {
    setIsLoading(false)
    // Limpar opções após animação de saída
    setTimeout(() => setLoaderOptions({}), 300)
  }, [])

  const value = React.useMemo(
    () => ({ show, hide, isLoading }),
    [show, hide, isLoading]
  )

  return (
    <LoaderContext.Provider value={value}>
      {children}
      {isLoading && (
        <Loader
          variant={loaderOptions.variant}
          message={loaderOptions.message}
          scope={loaderOptions.scope}
          isTransparentBg={loaderOptions.isTransparentBg}
          show={isLoading}
        />
      )}
    </LoaderContext.Provider>
  )
}

export function useLoader() {
  const context = React.useContext(LoaderContext)
  if (context === undefined) {
    throw new Error('useLoader must be used within a LoaderProvider')
  }
  return context
}

// Helper function para usar fora de componentes
let globalLoaderController: LoaderContextValue | null = null

export function setGlobalLoader(controller: LoaderContextValue) {
  globalLoaderController = controller
}

export const loader = {
  show: (options?: LoaderOptions) => {
    if (globalLoaderController) {
      globalLoaderController.show(options)
    } else {
      console.warn(
        'Loader: GlobalLoaderController not initialized. Wrap your app with LoaderProvider.'
      )
    }
  },
  hide: () => {
    if (globalLoaderController) {
      globalLoaderController.hide()
    } else {
      console.warn(
        'Loader: GlobalLoaderController not initialized. Wrap your app with LoaderProvider.'
      )
    }
  },
}

// Component que registra o controller global
export function GlobalLoaderController() {
  const loaderController = useLoader()

  React.useEffect(() => {
    setGlobalLoader(loaderController)
    return () => {
      setGlobalLoader(null as any)
    }
  }, [loaderController])

  return null
}
