'use client'

import { ItemCardRoot } from './ItemCardRoot'
import { ItemCardBadge } from './ItemCardBadge'
import {
  ItemCardHeader,
  ItemCardIcon,
  ItemCardTitleGroup,
  ItemCardTitle,
  ItemCardSubtitle,
} from './ItemCardHeader'
import {
  ItemCardContent,
  ItemCardContentItem,
  ItemCardEmpty,
} from './ItemCardContent'
import {
  ItemCardFooter,
  ItemCardFooterItem,
  ItemCardFooterDivider,
} from './ItemCardFooter'
import {
  ItemCardActions,
  ItemCardActionButton,
  ItemCardActionsRow,
} from './ItemCardActions'

/**
 * ItemCard - A compound component for building item/resource cards
 *
 * Inspired by the Kit de Peças card pattern. Use for displaying items like:
 * - Part Kits (Kits de Peças)
 * - Maintenance Plans (Planejamento de Manutenção)
 * - Resources, Products, or any item with icon, details, and actions
 *
 * @example Basic Usage
 * ```tsx
 * <ItemCard.Root>
 *   <ItemCard.Badge variant="primary">Publicado</ItemCard.Badge>
 *
 *   <ItemCard.Header>
 *     <ItemCard.Icon variant="primary">
 *       <BoxIcon className="w-5 h-5" />
 *     </ItemCard.Icon>
 *     <ItemCard.TitleGroup>
 *       <ItemCard.Title>Kit Cubo</ItemCard.Title>
 *       <ItemCard.Subtitle>2 Peças</ItemCard.Subtitle>
 *     </ItemCard.TitleGroup>
 *   </ItemCard.Header>
 *
 *   <ItemCard.Content>
 *     <ItemCard.ContentItem label="Araldite 10min" value="2x" secondary="R$ 28,00" />
 *     <ItemCard.ContentItem label="Aditivo Radiador 1L" value="1x" secondary="R$ 55,00" />
 *   </ItemCard.Content>
 *
 *   <ItemCard.Footer>
 *     <ItemCard.FooterItem label="Tipo Ativo" value="Implemento" />
 *     <ItemCard.FooterItem label="Custo Total" value="R$ 111,00" align="right" />
 *   </ItemCard.Footer>
 *
 *   <ItemCard.Actions>
 *     <ItemCard.ActionButton>Ações</ItemCard.ActionButton>
 *   </ItemCard.Actions>
 * </ItemCard.Root>
 * ```
 *
 * @example With Selection
 * ```tsx
 * <ItemCard.Root selected={isSelected} onClick={() => setSelected(!isSelected)}>
 *   ...
 * </ItemCard.Root>
 * ```
 *
 * @example Maintenance Planning Card
 * ```tsx
 * <ItemCard.Root>
 *   <ItemCard.Badge variant="warning">Crítico</ItemCard.Badge>
 *
 *   <ItemCard.Header>
 *     <ItemCard.Icon variant="warning" ripple>
 *       <TruckIcon className="w-5 h-5" />
 *     </ItemCard.Icon>
 *     <ItemCard.TitleGroup>
 *       <ItemCard.Title>ABC-1234</ItemCard.Title>
 *       <ItemCard.Subtitle>Scania R450</ItemCard.Subtitle>
 *     </ItemCard.TitleGroup>
 *   </ItemCard.Header>
 *
 *   <ItemCard.Content>
 *     <ItemCard.ContentItem label="Troca de Óleo" value="500 km" />
 *     <ItemCard.ContentItem label="Revisão Freios" value="1.200 km" />
 *   </ItemCard.Content>
 *
 *   <ItemCard.Footer>
 *     <ItemCard.FooterItem label="Status" value="Urgente" />
 *     <ItemCard.FooterItem label="Próxima" value="15/02/2024" align="right" />
 *   </ItemCard.Footer>
 *
 *   <ItemCard.Actions>
 *     <ItemCard.ActionButton variant="primary">Ver Detalhes</ItemCard.ActionButton>
 *   </ItemCard.Actions>
 * </ItemCard.Root>
 * ```
 */
export const ItemCard = Object.assign(ItemCardRoot, {
  // Badge
  Badge: ItemCardBadge,

  // Header components
  Header: ItemCardHeader,
  Icon: ItemCardIcon,
  TitleGroup: ItemCardTitleGroup,
  Title: ItemCardTitle,
  Subtitle: ItemCardSubtitle,

  // Content components
  Content: ItemCardContent,
  ContentItem: ItemCardContentItem,
  Empty: ItemCardEmpty,

  // Footer components
  Footer: ItemCardFooter,
  FooterItem: ItemCardFooterItem,
  FooterDivider: ItemCardFooterDivider,

  // Actions components
  Actions: ItemCardActions,
  ActionButton: ItemCardActionButton,
  ActionsRow: ItemCardActionsRow,
})

// Also export as namespace for alternative usage
export {
  ItemCardRoot,
  ItemCardBadge,
  ItemCardHeader,
  ItemCardIcon,
  ItemCardTitleGroup,
  ItemCardTitle,
  ItemCardSubtitle,
  ItemCardContent,
  ItemCardContentItem,
  ItemCardEmpty,
  ItemCardFooter,
  ItemCardFooterItem,
  ItemCardFooterDivider,
  ItemCardActions,
  ItemCardActionButton,
  ItemCardActionsRow,
}
