'use client'

import * as React from 'react'
import { Controller } from 'react-hook-form'
import type { FieldValues } from 'react-hook-form'
import { Input } from '../Input'
import { useFormContext, FormFieldProvider } from './FormContext'
import { FieldTooltipIcon } from './FormParts'
import type { FormInputProps, MaskType } from './types'
import { cn } from '../../utils/cn'

// ============================================
// MÁSCARAS
// ============================================

function applyMask(value: string, mask: MaskType): string {
  const digits = value.replace(/\D/g, '')

  switch (mask) {
    case 'phone':
      if (digits.length <= 10) {
        return digits.replace(/(\d{2})(\d{4})(\d{0,4})/, '($1) $2-$3').trim()
      }
      return digits.replace(/(\d{2})(\d{5})(\d{0,4})/, '($1) $2-$3').trim()

    case 'cpf':
      return digits
        .replace(/(\d{3})(\d)/, '$1.$2')
        .replace(/(\d{3})(\d)/, '$1.$2')
        .replace(/(\d{3})(\d{1,2})$/, '$1-$2')

    case 'cnpj':
      return digits
        .replace(/(\d{2})(\d)/, '$1.$2')
        .replace(/(\d{3})(\d)/, '$1.$2')
        .replace(/(\d{3})(\d)/, '$1/$2')
        .replace(/(\d{4})(\d{1,2})$/, '$1-$2')

    case 'cep':
      return digits.replace(/(\d{5})(\d{0,3})/, '$1-$2')

    case 'money':
      if (!digits) return ''
      const cents = parseInt(digits, 10) / 100
      return new Intl.NumberFormat('pt-BR', {
        style: 'currency',
        currency: 'BRL',
      }).format(cents)

    case 'percent':
      if (!digits) return ''
      const percent = parseInt(digits, 10) / 100
      return `${percent.toFixed(2)}%`

    case 'plate':
      const upper = value.toUpperCase().replace(/[^A-Z0-9]/g, '')
      if (upper.length <= 3) return upper
      if (upper.length <= 7) {
        // Placa antiga: ABC-1234 ou Mercosul: ABC1D23
        return upper.replace(/([A-Z]{3})(\d{0,1})([A-Z0-9]{0,1})(\d{0,2})/, '$1-$2$3$4')
      }
      return upper.slice(0, 7).replace(/([A-Z]{3})(\d{0,1})([A-Z0-9]{0,1})(\d{0,2})/, '$1-$2$3$4')

    case 'date':
      return digits
        .replace(/(\d{2})(\d)/, '$1/$2')
        .replace(/(\d{2})(\d)/, '$1/$2')
        .slice(0, 10)

    case 'time':
      return digits.replace(/(\d{2})(\d{0,2})/, '$1:$2').slice(0, 5)

    case 'datetime':
      const dateTime = digits
        .replace(/(\d{2})(\d)/, '$1/$2')
        .replace(/(\d{2})(\d)/, '$1/$2')
        .replace(/(\d{4})(\d)/, '$1 $2')
        .replace(/(\d{2})(\d{0,2})$/, '$1:$2')
      return dateTime.slice(0, 16)

    default:
      return value
  }
}

function getMaxLength(mask?: MaskType): number | undefined {
  switch (mask) {
    case 'phone':
      return 15
    case 'cpf':
      return 14
    case 'cnpj':
      return 18
    case 'cep':
      return 9
    case 'plate':
      return 8
    case 'date':
      return 10
    case 'time':
      return 5
    case 'datetime':
      return 16
    default:
      return undefined
  }
}

function parseValue(displayValue: string, mask?: MaskType): any {
  if (!displayValue) return undefined

  switch (mask) {
    case 'money':
      const moneyDigits = displayValue.replace(/\D/g, '')
      return moneyDigits ? parseInt(moneyDigits, 10) / 100 : undefined

    case 'percent':
      const percentDigits = displayValue.replace(/\D/g, '')
      return percentDigits ? parseInt(percentDigits, 10) / 100 : undefined

    default:
      return displayValue || undefined
  }
}

// ============================================
// FORM INPUT COMPONENT
// ============================================

export function FormInput<T extends FieldValues = FieldValues>({
  name,
  label,
  description,
  tooltip,
  required,
  disabled,
  className,
  mask,
  icon,
  showPasswordToggle = true,
  inputSize = 'default',
  hideError = false,
  type = 'text',
  maxLength,
  ...inputProps
}: FormInputProps<T>) {
  const form = useFormContext<T>()
  const fieldState = form.getFieldState(name, form.formState)
  const error = fieldState.error?.message

  const getInputType = React.useCallback(() => {
    if (['money', 'percent', 'phone', 'cpf', 'cnpj', 'cep'].includes(mask || '')) {
      return 'tel'
    }
    return type
  }, [mask, type])

  return (
    <FormFieldProvider name={name as string}>
      <Controller
        control={form.control}
        name={name}
        render={({ field }) => {
          // Formatação do valor para exibição
          const getDisplayValue = (): string => {
            if (field.value === undefined || field.value === null) return ''
            if (mask) {
              return applyMask(String(field.value), mask)
            }
            return String(field.value)
          }

          const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
            let newValue = e.target.value

            if (mask) {
              newValue = applyMask(newValue, mask)
              const parsed = parseValue(newValue, mask)
              field.onChange(parsed)
            } else {
              field.onChange(newValue || undefined)
            }
          }

          return (
            <div className={cn('space-y-1', className)}>
              <Input
                {...inputProps}
                ref={field.ref}
                name={field.name}
                value={getDisplayValue()}
                onChange={handleChange}
                onBlur={field.onBlur}
                disabled={disabled}
                type={getInputType()}
                label={label}
                required={required}
                error={!!error}
                icon={icon}
                inputSize={inputSize}
                maxLength={maxLength ?? getMaxLength(mask)}
                labelSuffix={tooltip ? <FieldTooltipIcon tooltip={tooltip} /> : undefined}
              />

              {description && !error && (
                <p className="text-xs text-muted-foreground px-1">{description}</p>
              )}

              {!hideError && error && (
                <p className="text-xs text-red-500 px-1">{error}</p>
              )}
            </div>
          )
        }}
      />
    </FormFieldProvider>
  )
}

FormInput.displayName = 'Form.Input'
