'use client'

import * as React from 'react'
import { cn } from '../../utils/cn'



// ============================================
// ROOT COMPONENT
// ============================================

interface SectionHeaderRootProps extends React.HTMLAttributes<HTMLDivElement> {
  /**
   * Adds a gradient from primary color on the left side
   * @default true
   */
  gradient?: boolean
  /**
   * Adds bottom border
   * @default true
   */
  bordered?: boolean
}

function SectionHeaderRoot({
  children,
  className,
  gradient = true,
  bordered = true,
  ...props
}: SectionHeaderRootProps) {
  return (
    <div
      className={cn(
        'px-6 py-4',
        gradient && 'bg-gradient-to-r from-primary/5 to-transparent',
        bordered && 'border-b border-border/50',
        className
      )}
      {...props}
    >
      <div className="flex items-center justify-between gap-4">
        <div className="flex items-center gap-3 min-w-0 flex-1">
          {children}
        </div>
      </div>
    </div>
  )
}

SectionHeaderRoot.displayName = 'SectionHeader'

// ============================================
// ICON COMPONENT
// ============================================

interface SectionHeaderIconProps {
  icon: React.ComponentType<{ className?: string }>
  className?: string
}

function SectionHeaderIcon({ icon: Icon, className }: SectionHeaderIconProps) {
  return (
    <div className={cn('p-2.5 rounded-xl bg-primary/10 shrink-0', className)}>
      <Icon className="h-5 w-5 text-primary" />
    </div>
  )
}

SectionHeaderIcon.displayName = 'SectionHeader.Icon'

// ============================================
// CONTENT WRAPPER (for title + subtitle)
// ============================================

interface SectionHeaderContentProps extends React.HTMLAttributes<HTMLDivElement> {}

function SectionHeaderContent({ children, className, ...props }: SectionHeaderContentProps) {
  return (
    <div className={cn('min-w-0 flex-1', className)} {...props}>
      {children}
    </div>
  )
}

SectionHeaderContent.displayName = 'SectionHeader.Content'

// ============================================
// TITLE COMPONENT
// ============================================

interface SectionHeaderTitleProps extends React.HTMLAttributes<HTMLHeadingElement> {}

function SectionHeaderTitle({ children, className, ...props }: SectionHeaderTitleProps) {
  return (
    <h3
      className={cn('font-semibold text-foreground truncate', className)}
      {...props}
    >
      {children}
    </h3>
  )
}

SectionHeaderTitle.displayName = 'SectionHeader.Title'

// ============================================
// SUBTITLE COMPONENT
// ============================================

interface SectionHeaderSubtitleProps extends React.HTMLAttributes<HTMLParagraphElement> {}

function SectionHeaderSubtitle({ children, className, ...props }: SectionHeaderSubtitleProps) {
  return (
    <p
      className={cn('text-sm text-muted-foreground truncate', className)}
      {...props}
    >
      {children}
    </p>
  )
}

SectionHeaderSubtitle.displayName = 'SectionHeader.Subtitle'

// ============================================
// ACTIONS COMPONENT
// ============================================

interface SectionHeaderActionsProps extends React.HTMLAttributes<HTMLDivElement> {}

function SectionHeaderActions({ children, className, ...props }: SectionHeaderActionsProps) {
  return (
    <div
      className={cn('flex items-center gap-2 shrink-0 ml-auto', className)}
      {...props}
    >
      {children}
    </div>
  )
}

SectionHeaderActions.displayName = 'SectionHeader.Actions'

// ============================================
// BADGE COMPONENT (for count display)
// ============================================

interface SectionHeaderBadgeProps extends React.HTMLAttributes<HTMLSpanElement> {
  variant?: 'default' | 'muted'
}

function SectionHeaderBadge({
  children,
  className,
  variant = 'muted',
  ...props
}: SectionHeaderBadgeProps) {
  return (
    <span
      className={cn(
        'text-xs px-2 py-1 rounded-full shrink-0',
        variant === 'muted' && 'bg-muted text-muted-foreground',
        variant === 'default' && 'bg-primary/10 text-primary',
        className
      )}
      {...props}
    >
      {children}
    </span>
  )
}

SectionHeaderBadge.displayName = 'SectionHeader.Badge'

// ============================================
// COMPOUND COMPONENT EXPORT
// ============================================

export const SectionHeader = Object.assign(SectionHeaderRoot, {
  Icon: SectionHeaderIcon,
  Content: SectionHeaderContent,
  Title: SectionHeaderTitle,
  Subtitle: SectionHeaderSubtitle,
  Actions: SectionHeaderActions,
  Badge: SectionHeaderBadge,
})

// Export individual components for flexibility
export {
  SectionHeaderRoot,
  SectionHeaderIcon,
  SectionHeaderContent,
  SectionHeaderTitle,
  SectionHeaderSubtitle,
  SectionHeaderActions,
  SectionHeaderBadge,
}

// Export types
export type {
  SectionHeaderRootProps,
  SectionHeaderIconProps,
  SectionHeaderContentProps,
  SectionHeaderTitleProps,
  SectionHeaderSubtitleProps,
  SectionHeaderActionsProps,
  SectionHeaderBadgeProps,
}
