'use client';

import { cn } from '../../utils/cn';
import type { WizardStepConnectorProps } from './types';

/**
 * Connector line between wizard steps
 *
 * Changes color based on completion state:
 * - Completed: primary/green color
 * - Pending: muted gray
 */
export function WizardStepConnector({
  isCompleted = false,
  variant = 'horizontal',
  className,
}: WizardStepConnectorProps) {
  const isHorizontal = variant === 'horizontal';

  return (
    <div
      className={cn(
        'transition-colors duration-300',
        isHorizontal
          ? 'flex-1 h-0.5 min-w-[24px] mx-2'
          : 'w-0.5 min-h-[24px] my-2 ml-[18px]',
        isCompleted ? 'bg-green-500' : 'bg-muted-foreground/20',
        className
      )}
      aria-hidden="true"
    />
  );
}
