'use client'

import * as React from 'react'
import { cva, type VariantProps } from 'class-variance-authority'
import { cn } from '../../utils/cn'

// ============================================================================
// Variants
// ============================================================================

const itemCardVariants = cva(
  'relative flex flex-col bg-card rounded-lg border shadow-md overflow-hidden transition-all duration-200',
  {
    variants: {
      variant: {
        default: 'border-border',
        selected: 'border-primary ring-2 ring-primary/20',
        muted: 'border-border/50 opacity-80',
      },
      hover: {
        true: 'hover:shadow-lg hover:border-border',
        false: '',
      },
    },
    defaultVariants: {
      variant: 'default',
      hover: true,
    },
  }
)

// ============================================================================
// Context
// ============================================================================

interface ItemCardContextValue {
  isSelected?: boolean
}

const ItemCardContext = React.createContext<ItemCardContextValue | null>(null)

export function useItemCard() {
  const context = React.useContext(ItemCardContext)
  if (!context) {
    throw new Error('ItemCard components must be used within ItemCard.Root')
  }
  return context
}

// ============================================================================
// Root Component
// ============================================================================

export interface ItemCardRootProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof itemCardVariants> {
  /** Whether the card is selected */
  selected?: boolean
  /** Whether the card is clickable */
  asButton?: boolean
}

const ItemCardRoot = React.forwardRef<HTMLDivElement, ItemCardRootProps>(
  (
    {
      className,
      variant,
      hover,
      selected = false,
      asButton = false,
      children,
      ...props
    },
    ref
  ) => {
    const contextValue = React.useMemo(
      () => ({ isSelected: selected }),
      [selected]
    )

    return (
      <ItemCardContext.Provider value={contextValue}>
        <div
          ref={ref}
          role={asButton ? 'button' : undefined}
          tabIndex={asButton ? 0 : undefined}
          className={cn(
            itemCardVariants({
              variant: selected ? 'selected' : variant,
              hover,
            }),
            asButton && 'cursor-pointer',
            className
          )}
          {...props}
        >
          {children}
        </div>
      </ItemCardContext.Provider>
    )
  }
)

ItemCardRoot.displayName = 'ItemCardRoot'

export { ItemCardRoot, itemCardVariants }
