import type {
  ColumnDef,
  SortingState,
  ColumnFiltersState,
  VisibilityState,
  RowSelectionState,
  PaginationState,
  Table,
  Column,
} from '@tanstack/react-table'
import type * as React from 'react'

// ============================================================================
// DATATABLE ROOT PROPS (Mínimas - Composição Explícita)
// ============================================================================

/**
 * Props do componente root DataTable.
 *
 * TData deve ser um objeto para garantir type-safety com o TanStack Table.
 * Usando `extends object` para aceitar interfaces TypeScript normalmente.
 */
export interface DataTableProps<TData extends object> {
  /** Data array - deve ser memoizado pelo consumer */
  data: TData[]

  /** Column definitions - deve ser memoizado pelo consumer */
  columns: ColumnDef<TData, unknown>[]

  /** Children usando Compound Component pattern */
  children: React.ReactNode

  /** Função para obter ID único da row */
  getRowId?: (row: TData) => string

  /**
   * Habilita server-side pagination.
   * Quando true, a tabela não faz paginação local e depende do servidor.
   */
  manualPagination?: boolean

  /** Número inicial de items por página (default: 10) */
  initialPageSize?: number

  /**
   * Total de páginas (obrigatório se manualPagination=true).
   * Usado para calcular navegação quando dados vêm do servidor.
   */
  pageCount?: number

  /**
   * Callback disparado quando page ou pageSize mudam (server-side pagination).
   * Inclui mudanças do autoPageSize e do seletor manual.
   */
  onPaginationChange?: (pagination: { pageIndex: number; pageSize: number }) => void

  /** Custom className */
  className?: string
}

// ============================================================================
// INTERNAL STATE (Gerenciado pelo Context)
// ============================================================================

export interface DataTableState {
  sorting: SortingState
  columnFilters: ColumnFiltersState
  columnVisibility: VisibilityState
  rowSelection: RowSelectionState
  pagination: PaginationState
  globalFilter: string
  density: DataTableDensity
}

export type DataTableDensity = 'compact' | 'default' | 'comfortable'

export interface DataTableMeta {
  isLoading: boolean
  isEmpty: boolean
  selectedRowCount: number
  totalRows: number
  density: DataTableDensity
}

// ============================================================================
// LOADING COMPONENT
// ============================================================================

export interface DataTableLoadingProps {
  /** Controla visibilidade do loading */
  visible: boolean

  /** Custom skeleton component */
  skeleton?: React.ReactNode

  /** Número de rows no skeleton */
  skeletonRows?: number

  /** Custom className */
  className?: string
}

// ============================================================================
// TOOLBAR COMPONENT
// ============================================================================

export interface DataTableToolbarProps {
  /** Children components */
  children?: React.ReactNode

  /** Custom className */
  className?: string
}

// ============================================================================
// SEARCH COMPONENT
// ============================================================================

export interface DataTableSearchProps {
  /** Placeholder text */
  placeholder?: string

  /** Coluna específica para buscar (se não passar, busca global) */
  column?: string

  /** Debounce delay em ms */
  debounce?: number

  /** Callback para server-side search (recebe valor com debounce aplicado) */
  onSearch?: (value: string) => void

  /** Custom className */
  className?: string
}

// ============================================================================
// FILTERS CONTAINER
// ============================================================================

export interface DataTableFiltersProps {
  /** Children: Individual filters */
  children?: React.ReactNode

  /** Callback when any column filter changes (server-side filtering) */
  onChange?: (filters: import('@tanstack/react-table').ColumnFiltersState) => void

  /** Custom className */
  className?: string
}

// ============================================================================
// FILTER COMPONENT
// ============================================================================

export interface DataTableFilterOption {
  label: string
  value: string
  icon?: React.ReactNode
}

export interface DataTableFilterProps {
  /** Coluna para filtrar (opcional para server-side only) */
  column?: string

  /** Label do filtro */
  title: string

  /** Opções de filtro */
  options: DataTableFilterOption[]

  /** Permitir seleção múltipla */
  multiSelect?: boolean

  /** Callback para server-side filtering (recebe valor selecionado ou undefined para "todos") */
  onValueChange?: (value: string | undefined) => void

  /** Custom className */
  className?: string
}

// ============================================================================
// CONTENT COMPONENT (Tabela em si)
// ============================================================================

export interface DataTableContentProps {
  /** Header fixo no scroll */
  stickyHeader?: boolean

  /** Linhas alternadas (zebra) */
  stripedRows?: boolean

  /** Highlight no hover */
  highlightOnHover?: boolean

  /** Callback quando uma row é clicada */
  onRowClick?: (row: unknown) => void

  /**
   * Habilita scroll vertical com altura calculada automaticamente.
   * O header das colunas fica sticky e apenas as rows fazem scroll.
   */
  scrollable?: boolean

  /** Margem inferior em px para o cálculo de altura automática (default: 68) */
  scrollBottomOffset?: number

  /**
   * Calcula automaticamente o número de rows por página baseado na altura disponível.
   * Mede do início do tbody até o final do viewport, descontando pagination e margem.
   */
  autoPageSize?: boolean

  /** Custom className */
  className?: string
}

// ============================================================================
// PAGINATION COMPONENT
// ============================================================================

export type DataTablePaginationMode = 'client' | 'server'

export interface DataTablePaginationProps {
  /** Modo de paginação */
  mode?: DataTablePaginationMode

  /** Total de páginas (obrigatório se mode="server") */
  pageCount?: number

  /** Opções de items por página */
  pageSizes?: number[]

  /** Mostrar seletor de page size */
  showPageSize?: boolean

  /** Mostrar informação de página atual */
  showPageInfo?: boolean

  /** Mostrar botões primeira/última página */
  showFirstLast?: boolean

  /** Custom className */
  className?: string
}

// ============================================================================
// EMPTY STATE COMPONENT
// ============================================================================

export interface DataTableEmptyStateProps {
  /** Título */
  title?: string

  /** Descrição */
  description?: string

  /** Ícone customizado */
  icon?: React.ReactNode

  /** Ação (botão, link, etc) */
  action?: React.ReactNode

  /** Custom className */
  className?: string
}

// ============================================================================
// BULK ACTIONS COMPONENT
// ============================================================================

export interface DataTableBulkActionsProps<TData = unknown> {
  /** Render prop que recebe as rows selecionadas */
  children: (selectedRows: TData[]) => React.ReactNode

  /** Custom className */
  className?: string
}

// ============================================================================
// COLUMN VISIBILITY COMPONENT
// ============================================================================

export interface DataTableColumnVisibilityProps {
  /** Custom className */
  className?: string
}

// ============================================================================
// DENSITY TOGGLE COMPONENT
// ============================================================================

export interface DataTableDensityToggleProps {
  /** Custom className */
  className?: string
}

// ============================================================================
// TABS COMPONENT
// ============================================================================

export interface DataTableTab {
  /** Identificador único da tab */
  value: string

  /** Label exibido na tab */
  label: string

  /** Contador opcional (ex: "Todas 85") */
  count?: number
}

export interface DataTableTabsProps {
  /** Lista de tabs disponíveis */
  tabs: DataTableTab[]

  /** Tab ativa (controlled) */
  value?: string

  /** Tab ativa inicial (uncontrolled) */
  defaultValue?: string

  /** Callback quando tab muda */
  onValueChange?: (value: string) => void

  /** Custom className */
  className?: string
}

// ============================================================================
// EXPORT COMPONENT
// ============================================================================

export type DataTableExportFormat = 'csv' | 'xlsx' | 'pdf'

export interface DataTableExportProps {
  /** Formatos disponíveis para export */
  formats?: DataTableExportFormat[]

  /** Nome do arquivo (sem extensão) */
  filename?: string

  /** Custom className */
  className?: string
}

// ============================================================================
// COLUMN HEADER COMPONENT (Sortable)
// ============================================================================

export interface DataTableColumnHeaderProps<TData = unknown, TValue = unknown> {
  /** Column instance do TanStack Table */
  column: Column<TData, TValue>

  /** Título do header */
  title: string

  /** Custom className */
  className?: string
}

// ============================================================================
// ROW ACTIONS COMPONENT
// ============================================================================

export interface DataTableRowActionsProps {
  /** Children (DropdownMenuItems) */
  children: React.ReactNode

  /** Custom className */
  className?: string
}

// ============================================================================
// CONTEXT TYPES
// ============================================================================

export interface DataTableContextValue<TData = unknown> {
  table: Table<TData>
  state: DataTableMeta
  density: DataTableDensity
  setDensity: (density: DataTableDensity) => void
}

// ============================================================================
// HOOK CONFIG TYPES
// ============================================================================

export interface UseDataTableConfig<TData extends object> {
  data: TData[]
  columns: ColumnDef<TData, unknown>[]
  getRowId?: (row: TData) => string
  initialPageSize?: number
  initialPageIndex?: number
}

// ============================================================================
// PAGINATION TYPES (Para integração com API)
// ============================================================================

export interface PaginationMeta {
  page: number
  perPage: number
  totalItems: number
  totalPages: number
  hasNextPage: boolean
  hasPreviousPage: boolean
  sortBy?: string
  sortOrder?: 'asc' | 'desc'
}

export interface PaginatedResponse<T> {
  data: T[]
  meta: PaginationMeta
}

export interface PaginationParams {
  page?: number
  perPage?: number
  sortBy?: string
  sortOrder?: 'asc' | 'desc'
}

