import * as React from 'react'
import { cva, type VariantProps } from 'class-variance-authority'
import { cn } from '../../utils/cn'

const badgeVariants = cva(
  'inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2',
  {
    variants: {
      variant: {
        default:
          'border-primary/15 bg-primary/5 text-primary hover:bg-primary/15',
        secondary:
          'border-secondary/15 bg-secondary/80 text-secondary-foreground hover:bg-secondary/70',
        success:
          'border-green-500/15 bg-green-500/5 text-green-600 dark:text-green-400 hover:bg-green-500/15',
        warning:
          'border-yellow-500/15 bg-yellow-500/5 text-yellow-600 dark:text-yellow-400 hover:bg-yellow-500/15',
        error:
          'border-red-500/15 bg-red-500/5 text-red-600 dark:text-red-400 hover:bg-red-500/15',
        info:
          'border-blue-500/15 bg-blue-500/5 text-blue-600 dark:text-blue-400 hover:bg-blue-500/15',
        outline: 'border-border text-foreground hover:bg-muted',
      },
      size: {
        default: 'px-2.5 py-0.5 text-xs',
        sm: 'px-2 py-0.5 text-[10px]',
        lg: 'px-3 py-1 text-sm',
      },
    },
    defaultVariants: {
      variant: 'default',
      size: 'default',
    },
  }
)

export interface BadgeProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof badgeVariants> {}

export function Badge({ className, variant, size, ...props }: BadgeProps) {
  return (
    <div className={cn(badgeVariants({ variant, size }), className)} {...props} />
  )
}

Badge.displayName = 'Badge'
