import * as React from 'react'
import { cn } from '../../utils/cn'
import { MobileNavItem } from './MobileNavItem'
import type { MobileNavProps } from './types'

export const MobileNav = React.memo<MobileNavProps>(function MobileNav({
  items,
  fabAction,
  className,
}) {
  // Split items for FAB placement (if FAB is provided)
  const leftItems = fabAction ? items.slice(0, Math.ceil(items.length / 2)) : items
  const rightItems = fabAction ? items.slice(Math.ceil(items.length / 2)) : []

  return (
    <div
      className={cn(
        'fixed bottom-0 left-0 right-0 z-50 bg-card px-2 pb-2 pt-1.5 md:hidden',
        'border-t border-border',
        className
      )}
    >
      <div className="flex items-center justify-around">
        {/* Left Items */}
        {leftItems.map((item, index) => (
          <MobileNavItem
            key={`left-${index}-${item.label}`}
            icon={item.icon}
            label={item.label}
            isActive={item.isActive}
            onClick={() => {
              if (item.onClick) {
                item.onClick()
              } else if (item.href && typeof window !== 'undefined') {
                window.location.href = item.href
              }
            }}
          />
        ))}

        {/* FAB Button (Center) */}
        {fabAction && (
          <div className="relative -mt-5">
            <button
              onClick={fabAction.onClick}
              className={cn(
                'flex h-14 w-14 items-center justify-center rounded-full bg-primary text-primary-foreground shadow-lg',
                'transition-transform hover:bg-primary/90 active:scale-95'
              )}
              aria-label={fabAction.label}
            >
              {fabAction.icon}
            </button>
            <span className="mt-1 block text-center text-[10px] font-medium text-muted-foreground">
              {fabAction.label}
            </span>
          </div>
        )}

        {/* Right Items */}
        {rightItems.map((item, index) => (
          <MobileNavItem
            key={`right-${index}-${item.label}`}
            icon={item.icon}
            label={item.label}
            isActive={item.isActive}
            onClick={() => {
              if (item.onClick) {
                item.onClick()
              } else if (item.href && typeof window !== 'undefined') {
                window.location.href = item.href
              }
            }}
          />
        ))}
      </div>
    </div>
  )
})

MobileNav.displayName = 'MobileNav'
