'use client'

import * as React from 'react'
import { useFormContext } from 'react-hook-form'
import type { FormFieldContextValue } from './types'

// Re-export useFormContext from react-hook-form for convenience
// This allows Form.* components to work both inside <Form> and <Wizard>
export { useFormContext }

// ============================================
// FIELD CONTEXT (para acessar o campo atual)
// ============================================

const FormFieldContext = React.createContext<FormFieldContextValue | null>(null)

export function useFormFieldContext(): FormFieldContextValue {
  const context = React.useContext(FormFieldContext)

  if (!context) {
    throw new Error('useFormFieldContext must be used within a Form.Field')
  }

  return context
}

export function useFormFieldContextOptional(): FormFieldContextValue | null {
  return React.useContext(FormFieldContext)
}

interface FormFieldProviderProps {
  name: string
  children: React.ReactNode
}

export function FormFieldProvider({ name, children }: FormFieldProviderProps) {
  const form = useFormContext()
  const id = React.useId()

  const fieldState = form.getFieldState(name, form.formState)
  const error = fieldState.error?.message

  const value = React.useMemo<FormFieldContextValue>(
    () => ({
      name,
      id,
      error,
      isRequired: false,
    }),
    [name, id, error]
  )

  return (
    <FormFieldContext.Provider value={value}>
      {children}
    </FormFieldContext.Provider>
  )
}

// ============================================
// EXPORTS
// ============================================

export { FormFieldContext }
