'use client'

import { Controller } from 'react-hook-form'
import type { FieldValues } from 'react-hook-form'
import { NumberStepper } from '../NumberStepper'
import { useFormContext, FormFieldProvider } from './FormContext'
import { FieldTooltipIcon } from './FormParts'
import type { BaseFieldProps, FieldTooltip } from './types'
import { cn } from '../../utils/cn'

export interface FormNumberStepperProps<T extends FieldValues = FieldValues>
  extends BaseFieldProps<T> {
  min?: number
  max?: number
  step?: number
  defaultValue?: number
  hideError?: boolean
  tooltip?: FieldTooltip
}

export function FormNumberStepper<T extends FieldValues = FieldValues>({
  name,
  label,
  description,
  tooltip,
  required,
  disabled,
  className,
  min = 0,
  max,
  step = 0.5,
  defaultValue,
  hideError = false,
}: FormNumberStepperProps<T>) {
  const form = useFormContext<T>()
  const fieldState = form.getFieldState(name, form.formState)
  const error = fieldState.error?.message

  return (
    <FormFieldProvider name={name as string}>
      <Controller
        control={form.control}
        name={name}
        render={({ field }) => (
          <div className={cn('space-y-1', className)}>
            <NumberStepper
              ref={field.ref}
              name={field.name}
              value={typeof field.value === 'number' ? field.value : 0}
              onChange={field.onChange}
              onBlur={field.onBlur}
              min={min}
              max={max}
              step={step}
              defaultValue={defaultValue}
              label={label}
              required={required}
              disabled={disabled}
              error={!!error}
              labelSuffix={tooltip ? <FieldTooltipIcon tooltip={tooltip} /> : undefined}
            />

            {description && !error && (
              <p className="text-xs text-muted-foreground px-1">{description}</p>
            )}

            {!hideError && error && (
              <p className="text-xs text-red-500 px-1">{error}</p>
            )}
          </div>
        )}
      />
    </FormFieldProvider>
  )
}

FormNumberStepper.displayName = 'Form.NumberStepper'
