import * as React from 'react'
import { cn } from '../../utils/cn'
import { KanbanProvider } from './KanbanContext'
import type { KanbanBoardProps, KanbanContextValue, KanbanDragResult } from './types'

export function KanbanBoard({
  children,
  onDragEnd,
  onDragStart,
  className,
}: KanbanBoardProps) {
  const [isDragging, setIsDragging] = React.useState(false)
  const [draggedItemId, setDraggedItemId] = React.useState<string | null>(null)
  const [sourceColumnId, setSourceColumnId] = React.useState<string | null>(null)
  const [hoveredColumnId, setHoveredColumnId] = React.useState<string | null>(null)

  // Store drop validators for each column
  const dropValidatorsRef = React.useRef<Map<string, (itemId: string, sourceColumnId: string) => boolean>>(new Map())

  const registerDropValidator = React.useCallback((columnId: string, validator: (itemId: string, sourceColumnId: string) => boolean) => {
    dropValidatorsRef.current.set(columnId, validator)
  }, [])

  const unregisterDropValidator = React.useCallback((columnId: string) => {
    dropValidatorsRef.current.delete(columnId)
  }, [])

  const canDropInColumn = React.useCallback((columnId: string) => {
    if (!draggedItemId || !sourceColumnId) return false
    if (columnId === sourceColumnId) return false

    const validator = dropValidatorsRef.current.get(columnId)
    if (validator) {
      return validator(draggedItemId, sourceColumnId)
    }
    return true // Allow by default if no validator
  }, [draggedItemId, sourceColumnId])

  // Handle drag start from card
  const handleDragStart = React.useCallback((itemId: string, colId: string) => {
    setIsDragging(true)
    setDraggedItemId(itemId)
    setSourceColumnId(colId)
    onDragStart?.(itemId, colId)
  }, [onDragStart])

  // Handle drop on column
  const handleDrop = React.useCallback((destinationColumnId: string) => {
    if (draggedItemId && sourceColumnId && destinationColumnId !== sourceColumnId) {
      if (canDropInColumn(destinationColumnId)) {
        const result: KanbanDragResult = {
          itemId: draggedItemId,
          sourceColumnId,
          destinationColumnId,
        }
        onDragEnd?.(result)
      }
    }
    // Reset state
    setIsDragging(false)
    setDraggedItemId(null)
    setSourceColumnId(null)
    setHoveredColumnId(null)
  }, [draggedItemId, sourceColumnId, canDropInColumn, onDragEnd])

  // Handle drag end (cancelled or dropped outside)
  const handleDragEnd = React.useCallback(() => {
    setIsDragging(false)
    setDraggedItemId(null)
    setSourceColumnId(null)
    setHoveredColumnId(null)
  }, [])

  const contextValue = React.useMemo<KanbanContextValue>(() => ({
    isDragging,
    draggedItemId,
    sourceColumnId,
    hoveredColumnId,
    setHoveredColumnId,
    canDropInColumn,
    registerDropValidator,
    unregisterDropValidator,
  }), [isDragging, draggedItemId, sourceColumnId, hoveredColumnId, canDropInColumn, registerDropValidator, unregisterDropValidator])

  return (
    <KanbanProvider value={contextValue}>
      <div
        className={cn(
          'flex gap-4 overflow-x-auto pb-4',
          className
        )}
        onDragEnd={handleDragEnd}
        data-kanban-board
        data-onstart={handleDragStart.toString()}
        data-ondrop={handleDrop.toString()}
      >
        <KanbanBoardInternalContext.Provider value={{ handleDragStart, handleDrop }}>
          {children}
        </KanbanBoardInternalContext.Provider>
      </div>
    </KanbanProvider>
  )
}

// Internal context for drag handlers (not exposed to consumers)
interface KanbanBoardInternalContextValue {
  handleDragStart: (itemId: string, columnId: string) => void
  handleDrop: (columnId: string) => void
}

const KanbanBoardInternalContext = React.createContext<KanbanBoardInternalContextValue | null>(null)

export function useKanbanBoard(): KanbanBoardInternalContextValue {
  const context = React.useContext(KanbanBoardInternalContext)
  if (!context) {
    throw new Error('useKanbanBoard must be used within a Kanban.Board component')
  }
  return context
}

KanbanBoard.displayName = 'KanbanBoard'
