import * as React from 'react'
import { cn } from '../../utils/cn'
import type { DataTableToolbarProps } from './types'

// ============================================================================
// TOOLBAR COMPONENT - Container para filtros e ações
// ============================================================================

export const DataTableToolbar = React.memo(function DataTableToolbar({
  className,
  children,
}: DataTableToolbarProps) {
  return (
    <div className={cn('flex items-center justify-between gap-2 bg-accent/50 p-4 rounded-t-lg', className)}>
      {children}
    </div>
  )
})
