import * as React from 'react'
import { cn } from '../../utils/cn'
import { useDataTable } from './DataTableContext'
import type { DataTableExportProps, DataTableExportFormat } from './types'
import { Button } from '../Button'
import { Download, FileSpreadsheet, FileText } from 'lucide-react'

// ============================================================================
// EXPORT COMPONENT - Exportar dados para CSV/XLSX
// ============================================================================
//
// Uso:
// <DataTable.Toolbar>
//   <DataTable.Export formats={['csv']} filename="relatorio" />
// </DataTable.Toolbar>
//
// ============================================================================

const formatConfig: Record<DataTableExportFormat, {
  label: string
  icon: React.ElementType
  mimeType: string
  extension: string
}> = {
  csv: {
    label: 'CSV',
    icon: FileText,
    mimeType: 'text/csv',
    extension: 'csv',
  },
  xlsx: {
    label: 'Excel',
    icon: FileSpreadsheet,
    mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
    extension: 'xlsx',
  },
  pdf: {
    label: 'PDF',
    icon: FileText,
    mimeType: 'application/pdf',
    extension: 'pdf',
  },
}

/**
 * Converte valor para string segura para CSV
 */
function escapeCSV(value: unknown): string {
  if (value === null || value === undefined) return ''
  const str = String(value)
  // Escapa aspas e envolve com aspas se necessário
  if (str.includes(',') || str.includes('"') || str.includes('\n')) {
    return `"${str.replace(/"/g, '""')}"`
  }
  return str
}

/**
 * Acessa propriedade aninhada (ex: "user.name")
 */
function getNestedValue(obj: Record<string, unknown>, path: string): unknown {
  return path.split('.').reduce<unknown>((current, key) => {
    if (current && typeof current === 'object' && key in (current as Record<string, unknown>)) {
      return (current as Record<string, unknown>)[key]
    }
    return undefined
  }, obj)
}

/**
 * Gera CSV a partir dos dados da tabela
 */
function generateCSV(
  headers: string[],
  rows: Record<string, unknown>[],
  accessors: string[]
): string {
  const headerLine = headers.map(escapeCSV).join(',')
  const dataLines = rows.map((row) =>
    accessors.map((accessor) => {
      const value = getNestedValue(row, accessor)
      return escapeCSV(value)
    }).join(',')
  )
  return [headerLine, ...dataLines].join('\n')
}

/**
 * Download arquivo
 */
function downloadFile(content: string, filename: string, mimeType: string) {
  const blob = new Blob(['\ufeff' + content], { type: `${mimeType};charset=utf-8` }) // BOM para Excel
  const url = URL.createObjectURL(blob)
  const link = document.createElement('a')
  link.href = url
  link.download = filename
  document.body.appendChild(link)
  link.click()
  document.body.removeChild(link)
  URL.revokeObjectURL(url)
}

export function DataTableExport({
  formats = ['csv'],
  filename = 'export',
  className,
}: DataTableExportProps) {
  const table = useDataTable()
  const [open, setOpen] = React.useState(false)
  const dropdownRef = React.useRef<HTMLDivElement>(null)

  // Fecha dropdown ao clicar fora
  React.useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setOpen(false)
      }
    }

    if (open) {
      document.addEventListener('mousedown', handleClickOutside)
      return () => document.removeEventListener('mousedown', handleClickOutside)
    }
  }, [open])

  const handleExport = React.useCallback((format: DataTableExportFormat) => {
    const visibleColumns = table.getVisibleLeafColumns()
    const rows = table.getFilteredRowModel().rows

    // Extrai headers e accessors
    const headers: string[] = []
    const accessors: string[] = []

    visibleColumns.forEach((column) => {
      const header = column.columnDef.header
      const headerText = typeof header === 'string' ? header : column.id

      // Pula colunas sem accessor (como select, actions)
      // Usa type assertion via unknown para acessar propriedades dinâmicas
      const columnDef = column.columnDef as unknown as Record<string, unknown>
      if (column.accessorFn || columnDef.accessorKey) {
        headers.push(headerText)
        accessors.push((columnDef.accessorKey as string) || column.id)
      }
    })

    // Extrai dados como Record<string, unknown>[]
    const data = rows.map((row) => row.original as Record<string, unknown>)

    if (format === 'csv') {
      const csv = generateCSV(headers, data, accessors)
      const config = formatConfig[format]
      downloadFile(csv, `${filename}.${config.extension}`, config.mimeType)
    } else if (format === 'xlsx') {
      // Para XLSX, seria necessário uma lib como xlsx
      console.warn('XLSX export requires xlsx library. Falling back to CSV.')
      const csv = generateCSV(headers, data, accessors)
      downloadFile(csv, `${filename}.csv`, 'text/csv')
    } else if (format === 'pdf') {
      console.warn('PDF export not implemented yet.')
    }

    setOpen(false)
  }, [table, filename])

  // Se só tem um formato, renderiza botão direto
  if (formats.length === 1) {
    const format = formats[0]
    const config = formatConfig[format]
    const Icon = config.icon

    return (
      <Button
        variant="outline"
        size="sm"
        className={cn('h-8', className)}
        onClick={() => handleExport(format)}
      >
        <Icon className="mr-2 h-4 w-4" />
        Exportar {config.label}
      </Button>
    )
  }

  // Múltiplos formatos: dropdown
  return (
    <div className={cn('relative', className)} ref={dropdownRef}>
      <Button
        variant="outline"
        size="sm"
        className="h-8"
        onClick={() => setOpen(!open)}
        aria-expanded={open}
        aria-haspopup="true"
      >
        <Download className="mr-2 h-4 w-4" />
        Exportar
      </Button>

      {open && (
        <div
          className={cn(
            'absolute right-0 top-full z-50 mt-1 w-36',
            'rounded-md border bg-popover p-1 shadow-md',
            'animate-in fade-in-0 zoom-in-95'
          )}
        >
          {formats.map((format) => {
            const config = formatConfig[format]
            const Icon = config.icon

            return (
              <button
                key={format}
                className={cn(
                  'flex w-full items-center gap-2 px-2 py-1.5 rounded-sm cursor-pointer',
                  'hover:bg-accent hover:text-accent-foreground',
                  'text-sm text-left'
                )}
                onClick={() => handleExport(format)}
              >
                <Icon className="h-4 w-4" />
                <span>{config.label}</span>
              </button>
            )
          })}
        </div>
      )}
    </div>
  )
}

DataTableExport.displayName = 'DataTable.Export'
