'use client';

import { useCallback, type MouseEvent } from 'react';
import { cn } from '../../utils/cn';
import { Button } from '../Button/Button';
import { Loader } from '../Loader/Loader';
import { useWizardContext } from './WizardContext';
import type { WizardNavigationProps } from './types';

/**
 * Navigation buttons for the wizard
 *
 * Provides:
 * - Cancel button (first step only by default)
 * - Previous button
 * - Next button (type="button" - does NOT submit)
 * - Submit button (last step only, type="submit")
 *
 * @example
 * ```tsx
 * <Wizard.Navigation
 *   cancelLabel="Cancelar"
 *   prevLabel="Voltar"
 *   nextLabel="Continuar"
 *   submitLabel="Finalizar"
 *   onCancel={() => dialog.close()}
 * />
 * ```
 */
export function WizardNavigation({
  cancelLabel = 'Cancelar',
  prevLabel = 'Voltar',
  nextLabel = 'Continuar',
  submitLabel = 'Finalizar',
  loadingLabel = 'Processando...',
  onCancel,
  showCancel,
  submitDisabled = false,
  className,
}: WizardNavigationProps) {
  const {
    isFirstStep,
    isLastStep,
    currentStep,
    goToNextStep,
    goToPrevStep,
    form,
  } = useWizardContext();

  const isSubmitting = form.formState.isSubmitting;

  // Determine if cancel should be shown
  const shouldShowCancel = showCancel ?? isFirstStep;

  /**
   * Handle next button click
   * IMPORTANT:
   * - Uses type="button" to prevent form submission
   * - Explicitly prevents default and stops propagation
   * - Only advances step, never submits
   */
  const handleNext = useCallback(async (e: MouseEvent<HTMLButtonElement>) => {
    // Prevent any form submission behavior
    e.preventDefault();
    e.stopPropagation();

    await goToNextStep();
  }, [goToNextStep]);

  /**
   * Handle previous button click
   */
  const handlePrev = useCallback((e: MouseEvent<HTMLButtonElement>) => {
    e.preventDefault();
    e.stopPropagation();
    goToPrevStep();
  }, [goToPrevStep]);

  /**
   * Handle cancel button click
   */
  const handleCancel = useCallback((e: MouseEvent<HTMLButtonElement>) => {
    e.preventDefault();
    e.stopPropagation();
    onCancel?.();
  }, [onCancel]);

  return (
    <div
      className={cn(
        'grid grid-cols-2 gap-3 pt-4 border-t border-border',
        className
      )}
    >
      {/* Left button: Cancel or Previous */}
      {shouldShowCancel && onCancel ? (
        <Button
          key="cancel"
          type="button"
          variant="outline"
          onClick={handleCancel}
          disabled={isSubmitting}
          className="w-full"
        >
          {cancelLabel}
        </Button>
      ) : !isFirstStep ? (
        <Button
          key="prev"
          type="button"
          variant="outline"
          onClick={handlePrev}
          disabled={isSubmitting}
          className="w-full"
        >
          {prevLabel}
        </Button>
      ) : (
        <div /> // Spacer for first step without cancel
      )}

      {/* Right button: Next or Submit */}
      {isLastStep ? (
        <Button
          key={`submit-step-${currentStep}`}
          type="submit"
          disabled={submitDisabled || isSubmitting}
          className="w-full"
        >
          {isSubmitting ? (
            <span className="flex items-center justify-center gap-2">
              <Loader variant="spinner" />
              {loadingLabel}
            </span>
          ) : (
            submitLabel
          )}
        </Button>
      ) : (
        <Button
          key={`next-step-${currentStep}`}
          type="button"
          onClick={handleNext}
          disabled={isSubmitting}
          className="w-full"
        >
          {nextLabel}
        </Button>
      )}
    </div>
  );
}
