'use client';

import { Check, AlertCircle } from 'lucide-react';
import { cn } from '../../utils/cn';
import type { WizardStepIndicatorProps } from './types';

/**
 * Size configurations for step indicator
 */
const sizeConfig = {
  sm: {
    circle: 'h-7 w-7 text-xs',
    icon: 'h-3.5 w-3.5',
    label: 'text-xs',
    description: 'text-xs',
    gap: 'gap-1.5',
  },
  md: {
    circle: 'h-9 w-9 text-sm',
    icon: 'h-4 w-4',
    label: 'text-sm',
    description: 'text-xs',
    gap: 'gap-2',
  },
  lg: {
    circle: 'h-11 w-11 text-base',
    icon: 'h-5 w-5',
    label: 'text-base',
    description: 'text-sm',
    gap: 'gap-2.5',
  },
};

/**
 * State-based styling for step indicator
 */
const stateStyles = {
  completed: {
    circle: 'bg-green-500 text-white border-green-500',
    label: 'text-green-600 dark:text-green-400',
    description: 'text-muted-foreground',
  },
  current: {
    circle: 'bg-primary text-primary-foreground border-primary ring-4 ring-primary/20',
    label: 'text-primary font-semibold',
    description: 'text-muted-foreground',
  },
  pending: {
    circle: 'bg-background text-muted-foreground border-muted-foreground/30',
    label: 'text-muted-foreground',
    description: 'text-muted-foreground/60',
  },
  error: {
    circle: 'bg-destructive text-destructive-foreground border-destructive',
    label: 'text-destructive',
    description: 'text-destructive/60',
  },
  disabled: {
    circle: 'bg-muted text-muted-foreground/50 border-muted cursor-not-allowed',
    label: 'text-muted-foreground/50',
    description: 'text-muted-foreground/30',
  },
};

/**
 * Individual step indicator component
 *
 * Displays a step with:
 * - Circle with number/icon/checkmark
 * - Optional label
 * - Optional description
 */
export function WizardStepIndicator({
  step,
  index,
  state,
  showNumber = false,
  showDescription = false,
  size = 'md',
  isClickable = false,
  onClick,
}: WizardStepIndicatorProps) {
  const config = sizeConfig[size];
  const styles = stateStyles[state];
  const Icon = step.icon;

  /**
   * Render the content inside the circle
   */
  const renderCircleContent = () => {
    // Completed state shows checkmark
    if (state === 'completed') {
      return <Check className={config.icon} strokeWidth={3} />;
    }

    // Error state shows alert icon
    if (state === 'error') {
      return <AlertCircle className={config.icon} />;
    }

    // Show icon if provided and not showing numbers
    if (Icon && !showNumber) {
      return <Icon className={config.icon} />;
    }

    // Show step number (1-indexed)
    return <span>{index + 1}</span>;
  };

  return (
    <div
      className={cn(
        'flex flex-col items-center',
        config.gap,
        isClickable && 'cursor-pointer group'
      )}
      onClick={isClickable ? onClick : undefined}
      role={isClickable ? 'button' : undefined}
      tabIndex={isClickable ? 0 : undefined}
      onKeyDown={
        isClickable
          ? (e) => {
              if (e.key === 'Enter' || e.key === ' ') {
                e.preventDefault();
                onClick?.();
              }
            }
          : undefined
      }
      aria-current={state === 'current' ? 'step' : undefined}
    >
      {/* Circle indicator */}
      <div
        className={cn(
          'flex items-center justify-center rounded-full border-2 transition-all duration-200',
          config.circle,
          styles.circle,
          isClickable && 'group-hover:ring-4 group-hover:ring-primary/10'
        )}
      >
        {renderCircleContent()}
      </div>

      {/* Label and description */}
      {(step.label || showDescription) && (
        <div className="flex flex-col items-center text-center max-w-[120px]">
          {step.label && (
            <span
              className={cn(
                'leading-tight transition-colors duration-200',
                config.label,
                styles.label
              )}
            >
              {step.label}
            </span>
          )}
          {showDescription && step.description && (
            <span
              className={cn(
                'leading-tight mt-0.5',
                config.description,
                styles.description
              )}
            >
              {step.description}
            </span>
          )}
        </div>
      )}
    </div>
  );
}
