'use client'

import * as React from 'react'
import { cva, type VariantProps } from 'class-variance-authority'
import { cn } from '../../utils/cn'
import { RippleEffect } from '../RippleEffect'

// ============================================================================
// Header Container
// ============================================================================

export interface ItemCardHeaderProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Alignment of content */
  align?: 'left' | 'right' | 'between'
}

const ItemCardHeader = React.forwardRef<HTMLDivElement, ItemCardHeaderProps>(
  ({ className, align = 'between', children, ...props }, ref) => {
    const alignmentClasses = {
      left: 'justify-start',
      right: 'justify-end',
      between: 'justify-between',
    }

    return (
      <div
        ref={ref}
        className={cn(
          'flex items-center gap-4 px-6 pt-6 pb-4',
          alignmentClasses[align],
          className
        )}
        {...props}
      >
        {children}
      </div>
    )
  }
)

ItemCardHeader.displayName = 'ItemCardHeader'

// ============================================================================
// Icon Container Variants
// ============================================================================

const itemCardIconVariants = cva(
  'flex items-center justify-center rounded-2xl shadow-lg transition-transform',
  {
    variants: {
      size: {
        sm: 'p-2 w-10 h-10',
        md: 'p-3 w-12 h-12',
        lg: 'p-4 w-14 h-14',
      },
      variant: {
        primary: 'bg-primary text-primary-foreground shadow-primary/25',
        secondary: 'bg-secondary text-secondary-foreground shadow-secondary/25',
        success: 'bg-green-500 text-white shadow-green-500/25',
        warning: 'bg-yellow-500 text-white shadow-yellow-500/25',
        destructive: 'bg-red-500 text-white shadow-red-500/25',
        info: 'bg-blue-500 text-white shadow-blue-500/25',
        muted: 'bg-muted text-muted-foreground shadow-muted/25',
        outline: 'bg-background border-2 border-primary text-primary shadow-none',
      },
    },
    defaultVariants: {
      size: 'md',
      variant: 'primary',
    },
  }
)

// ============================================================================
// Icon Component
// ============================================================================

export interface ItemCardIconProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof itemCardIconVariants> {
  /** Whether to show ripple effect */
  ripple?: boolean
}

const ItemCardIcon = React.forwardRef<HTMLDivElement, ItemCardIconProps>(
  ({ className, size, variant, ripple = false, children, ...props }, ref) => {
    // Size classes for wrapper to match icon dimensions
    const wrapperSizeClasses: Record<string, string> = {
      sm: 'w-10 h-10',
      md: 'w-12 h-12',
      lg: 'w-14 h-14',
    }
    const actualSize = size || 'md'

    if (ripple) {
      return (
        <div className={cn('relative', wrapperSizeClasses[actualSize])}>
          <RippleEffect
            color="primary"
            size="md"
            rings={3}
            intensity="light"
          />
          <div
            ref={ref}
            className={cn(itemCardIconVariants({ size, variant }), 'relative z-10', className)}
            {...props}
          >
            {children}
          </div>
        </div>
      )
    }

    return (
      <div
        ref={ref}
        className={cn(itemCardIconVariants({ size, variant }), className)}
        {...props}
      >
        {children}
      </div>
    )
  }
)

ItemCardIcon.displayName = 'ItemCardIcon'

// ============================================================================
// Title Group
// ============================================================================

export interface ItemCardTitleGroupProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Alignment of text */
  align?: 'left' | 'right' | 'center'
}

const ItemCardTitleGroup = React.forwardRef<HTMLDivElement, ItemCardTitleGroupProps>(
  ({ className, align = 'right', children, ...props }, ref) => {
    const alignmentClasses = {
      left: 'text-left',
      right: 'text-right',
      center: 'text-center',
    }

    return (
      <div
        ref={ref}
        className={cn('flex-1 min-w-0', alignmentClasses[align], className)}
        {...props}
      >
        {children}
      </div>
    )
  }
)

ItemCardTitleGroup.displayName = 'ItemCardTitleGroup'

// ============================================================================
// Title
// ============================================================================

export interface ItemCardTitleProps extends React.HTMLAttributes<HTMLHeadingElement> {}

const ItemCardTitle = React.forwardRef<HTMLHeadingElement, ItemCardTitleProps>(
  ({ className, children, ...props }, ref) => {
    return (
      <h3
        ref={ref}
        className={cn('text-lg font-semibold text-foreground truncate', className)}
        {...props}
      >
        {children}
      </h3>
    )
  }
)

ItemCardTitle.displayName = 'ItemCardTitle'

// ============================================================================
// Subtitle
// ============================================================================

export interface ItemCardSubtitleProps extends React.HTMLAttributes<HTMLParagraphElement> {}

const ItemCardSubtitle = React.forwardRef<HTMLParagraphElement, ItemCardSubtitleProps>(
  ({ className, children, ...props }, ref) => {
    return (
      <p
        ref={ref}
        className={cn('text-sm text-muted-foreground', className)}
        {...props}
      >
        {children}
      </p>
    )
  }
)

ItemCardSubtitle.displayName = 'ItemCardSubtitle'

export {
  ItemCardHeader,
  ItemCardIcon,
  ItemCardTitleGroup,
  ItemCardTitle,
  ItemCardSubtitle,
  itemCardIconVariants,
}
