import * as React from 'react'
import { cva } from 'class-variance-authority'
import { TrendingUp, TrendingDown } from 'lucide-react'
import { cn } from '../../utils/cn'
import { Sparkline } from './Sparkline'
import type {
  BigNumberCardRootProps,
  BigNumberCardHeaderProps,
  BigNumberCardTitleProps,
  BigNumberCardLinkProps,
  BigNumberCardContentProps,
  BigNumberCardValueProps,
  BigNumberCardTrendProps,
} from './types'

// ============================================================================
// Root - Card container
// ============================================================================

const rootVariants = cva(
  'relative overflow-hidden rounded-xl border border-border bg-card shadow-sm min-h-[140px]',
  {
    variants: {
      size: {
        default: 'p-5 pb-14',
        sm: 'p-4 pb-12',
        lg: 'p-6 pb-16',
      },
    },
    defaultVariants: {
      size: 'default',
    },
  }
)

function BigNumberCardRoot({ children, className, size }: BigNumberCardRootProps) {
  return (
    <div className={cn(rootVariants({ size }), className)}>
      {children}
    </div>
  )
}

BigNumberCardRoot.displayName = 'BigNumberCard.Root'

// ============================================================================
// Header - Flex container for title + action
// ============================================================================

function BigNumberCardHeader({ children, className }: BigNumberCardHeaderProps) {
  return (
    <div className={cn('flex items-center justify-between', className)}>
      {children}
    </div>
  )
}

BigNumberCardHeader.displayName = 'BigNumberCard.Header'

// ============================================================================
// Title - Muted text
// ============================================================================

function BigNumberCardTitle({ children, className }: BigNumberCardTitleProps) {
  return (
    <span className={cn('text-sm font-medium text-muted-foreground', className)}>
      {children}
    </span>
  )
}

BigNumberCardTitle.displayName = 'BigNumberCard.Title'

// ============================================================================
// Link - Action link
// ============================================================================

function BigNumberCardLink({ children, href, onClick, className }: BigNumberCardLinkProps) {
  const handleClick = (e: React.MouseEvent) => {
    if (onClick) {
      e.preventDefault()
      onClick()
    }
  }

  return (
    <a
      href={href ?? '#'}
      onClick={handleClick}
      className={cn(
        'text-xs font-medium text-primary hover:text-primary/80 hover:underline transition-colors',
        className
      )}
    >
      {children}
    </a>
  )
}

BigNumberCardLink.displayName = 'BigNumberCard.Link'

// ============================================================================
// Content - Optional wrapper for value area
// ============================================================================

function BigNumberCardContent({ children, className }: BigNumberCardContentProps) {
  return (
    <div className={cn('mt-3 space-y-1', className)}>
      {children}
    </div>
  )
}

BigNumberCardContent.displayName = 'BigNumberCard.Content'

// ============================================================================
// Value - Big number with prefix/suffix
// ============================================================================

function BigNumberCardValue({ children, prefix, suffix, className }: BigNumberCardValueProps) {
  return (
    <div className={cn('mt-3 text-3xl font-bold tracking-tight text-foreground', className)}>
      {prefix && <span className="text-2xl">{prefix}</span>}
      {children}
      {suffix && <span className="text-2xl ml-0.5">{suffix}</span>}
    </div>
  )
}

BigNumberCardValue.displayName = 'BigNumberCard.Value'

// ============================================================================
// Trend - Percentage change indicator
// ============================================================================

function BigNumberCardTrend({ value, direction, children, className, show = true }: BigNumberCardTrendProps) {
  if (!show) {
    return null
  }

  const isUp = direction === 'up'
  const Icon = isUp ? TrendingUp : TrendingDown

  return (
    <div
      className={cn(
        'mt-2 flex items-center gap-1.5 text-sm',
        isUp ? 'text-emerald-600 dark:text-emerald-400' : 'text-red-600 dark:text-red-400',
        className
      )}
    >
      <Icon className="h-4 w-4 flex-shrink-0" />
      <span className="font-semibold">
        {isUp ? '+' : ''}{value.toFixed(1)}%
      </span>
      {children && (
        <span className="text-muted-foreground font-normal">{children}</span>
      )}
    </div>
  )
}

BigNumberCardTrend.displayName = 'BigNumberCard.Trend'

// ============================================================================
// Description - Muted description text
// ============================================================================

interface BigNumberCardDescriptionProps {
  children: React.ReactNode
  className?: string
  show?: boolean
}

function BigNumberCardDescription({ children, className, show = true }: BigNumberCardDescriptionProps) {
  if (!show) {
    return null
  }

  return (
    <p className={cn('mt-1 text-xs text-muted-foreground', className)}>
      {children}
    </p>
  )
}

BigNumberCardDescription.displayName = 'BigNumberCard.Description'

// ============================================================================
// Sparkline wrapper for positioning
// ============================================================================

function BigNumberCardSparklineWrapper(props: React.ComponentProps<typeof Sparkline>) {
  const { show = true, ...rest } = props

  if (!show) {
    return null
  }

  return (
    <div className="absolute bottom-0 left-0 right-0 h-16 opacity-80">
      <Sparkline {...rest} show={show} />
    </div>
  )
}

BigNumberCardSparklineWrapper.displayName = 'BigNumberCard.Sparkline'

// ============================================================================
// Compound export
// ============================================================================

export const BigNumberCard = {
  Root: BigNumberCardRoot,
  Header: BigNumberCardHeader,
  Title: BigNumberCardTitle,
  Link: BigNumberCardLink,
  Content: BigNumberCardContent,
  Value: BigNumberCardValue,
  Trend: BigNumberCardTrend,
  Description: BigNumberCardDescription,
  Sparkline: BigNumberCardSparklineWrapper,
}
