import * as React from 'react'
import { motion } from 'framer-motion'
import { cn } from '../../utils/cn'
import type { MobileNavItemProps } from './types'

// Helper to render icon - handles Lucide icons, forwardRef, memo, and React elements
function renderIcon(icon: unknown, className: string): React.ReactNode {
  if (!icon) return null

  // If it's a valid React element, render it directly
  if (React.isValidElement(icon)) {
    return React.cloneElement(icon as React.ReactElement<{ className?: string }>, { className })
  }

  // If it's a component (function, forwardRef, memo), render it
  if (
    typeof icon === 'function' ||
    (typeof icon === 'object' && icon !== null && '$$typeof' in icon)
  ) {
    const IconComponent = icon as React.ComponentType<{ className?: string }>
    return <IconComponent className={className} />
  }

  return null
}

export const MobileNavItem = React.memo<MobileNavItemProps>(function MobileNavItem({
  icon,
  label,
  isActive = false,
  onClick,
}) {
  return (
    <button onClick={onClick} className="group flex flex-col items-center">
      <div
        className={cn(
          'flex items-center justify-center rounded-full p-1.5 transition-colors',
          isActive ? 'text-primary' : 'text-muted-foreground group-hover:text-foreground'
        )}
      >
        {renderIcon(icon, 'h-5 w-5')}
      </div>
      <span
        className={cn(
          'mt-0.5 text-[10px] font-medium',
          isActive ? 'text-primary' : 'text-muted-foreground group-hover:text-foreground'
        )}
      >
        {label}
      </span>
      {isActive && (
        <motion.div
          layoutId="mobileNavActiveIndicator"
          className="mt-1 h-1 w-8 rounded-full bg-primary"
          transition={{ type: 'spring', stiffness: 500, damping: 30 }}
        />
      )}
    </button>
  )
})

MobileNavItem.displayName = 'MobileNavItem'
