import * as React from 'react'
import * as DialogPrimitive from '@radix-ui/react-dialog'
import { X } from 'lucide-react'
import { cn } from '../../utils/cn'
import { cva, type VariantProps } from 'class-variance-authority'

// ============================================================================
// DIALOG MESH EFFECT - Gradient + Grid pattern (default on all dialogs)
// ============================================================================

function DialogMeshEffect() {
  return (
    <div className="absolute top-0 left-0 right-0 h-[48px] overflow-hidden rounded-t-lg pointer-events-none z-[1]">
      {/* Mesh Gradient */}
      <div
        className="absolute inset-0"
        style={{
          background: `
            radial-gradient(ellipse at 30% -30%, hsl(var(--primary) / 0.2) 0%, transparent 70%),
            radial-gradient(ellipse at 80% -20%, hsl(var(--primary) / 0.14) 0%, transparent 65%),
            linear-gradient(to bottom, hsl(var(--primary) / 0.06), transparent 80%)
          `,
        }}
      />
      {/* Grid Pattern */}
      <div
        className="absolute inset-0"
        style={{
          backgroundImage: `
            linear-gradient(hsl(var(--primary) / 0.07) 1px, transparent 1px),
            linear-gradient(90deg, hsl(var(--primary) / 0.07) 1px, transparent 1px)
          `,
          backgroundSize: '28px 28px',
          mask: 'linear-gradient(to bottom, black 0%, transparent 90%)',
          WebkitMask: 'linear-gradient(to bottom, black 0%, transparent 90%)',
        }}
      />
    </div>
  )
}

// ============================================================================
// PRIMITIVES
// ============================================================================

const Dialog = DialogPrimitive.Root
const DialogTrigger = DialogPrimitive.Trigger
const DialogPortal = DialogPrimitive.Portal
const DialogClose = DialogPrimitive.Close

// DialogOverlay
const DialogOverlay = React.memo(
  React.forwardRef<
    React.ElementRef<typeof DialogPrimitive.Overlay>,
    React.ComponentPropsWithoutRef<typeof DialogPrimitive.Overlay>
  >(({ className, ...props }, ref) => (
    <DialogPrimitive.Overlay
      ref={ref}
      className={cn(
        'fixed inset-0 z-50 bg-black/80 data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0',
        className
      )}
      {...props}
    />
  ))
)
DialogOverlay.displayName = DialogPrimitive.Overlay.displayName

// DialogContent
const dialogContentVariants = cva(
  [
    'fixed left-[50%] top-[50%] z-50',
    'translate-x-[-50%] translate-y-[-50%]',
    'grid w-full gap-4',
    'border bg-background p-6 shadow-lg',
    'duration-200',
    'data-[state=open]:animate-in data-[state=closed]:animate-out',
    'data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0',
    'data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95',
    'data-[state=closed]:slide-out-to-left-1/2 data-[state=closed]:slide-out-to-top-[48%]',
    'data-[state=open]:slide-in-from-left-1/2 data-[state=open]:slide-in-from-top-[48%]',
    'sm:rounded-lg',
  ],
  {
    variants: {
      size: {
        sm: 'max-w-sm',
        md: 'max-w-md',
        lg: 'max-w-lg',
        xl: 'max-w-xl',
        '2xl': 'max-w-2xl',
        '3xl': 'max-w-3xl',
        '4xl': 'max-w-4xl',
        full: 'max-w-[95vw] max-h-[95vh]',
      },
    },
    defaultVariants: {
      size: 'lg',
    },
  }
)

export interface DialogContentProps
  extends React.ComponentPropsWithoutRef<typeof DialogPrimitive.Content>,
    VariantProps<typeof dialogContentVariants> {
  showCloseButton?: boolean
  /** Disable the mesh gradient + grid pattern effect (default: false) */
  disableMeshEffect?: boolean
}

const DialogContent = React.memo(
  React.forwardRef<
    React.ElementRef<typeof DialogPrimitive.Content>,
    DialogContentProps
  >(({ className, children, showCloseButton = true, disableMeshEffect = false, size, ...props }, ref) => (
    <DialogPortal>
      <DialogOverlay />
      <DialogPrimitive.Content
        ref={ref}
        className={cn(dialogContentVariants({ size, className }), 'overflow-hidden')}
        {...props}
      >
        {!disableMeshEffect && <DialogMeshEffect />}
        {children}
        {showCloseButton && (
          <DialogPrimitive.Close className="absolute right-4 top-4 z-50 rounded-sm opacity-70 ring-offset-background transition-opacity hover:opacity-100 focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 disabled:pointer-events-none data-[state=open]:bg-accent data-[state=open]:text-muted-foreground">
            <X className="h-4 w-4" />
            <span className="sr-only">Fechar</span>
          </DialogPrimitive.Close>
        )}
      </DialogPrimitive.Content>
    </DialogPortal>
  ))
)
DialogContent.displayName = DialogPrimitive.Content.displayName

// DialogHeader
const DialogHeader = React.memo<React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }) => (
    <div
      className={cn(
        'flex flex-col space-y-1.5 text-center sm:text-left',
        className
      )}
      {...props}
    />
  )
)
DialogHeader.displayName = 'DialogHeader'

// DialogFooter
const DialogFooter = React.memo<React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }) => (
    <div
      className={cn(
        'flex flex-col-reverse sm:flex-row sm:justify-end sm:space-x-2',
        className
      )}
      {...props}
    />
  )
)
DialogFooter.displayName = 'DialogFooter'

// DialogTitle
const DialogTitle = React.memo(
  React.forwardRef<
    React.ElementRef<typeof DialogPrimitive.Title>,
    React.ComponentPropsWithoutRef<typeof DialogPrimitive.Title>
  >(({ className, ...props }, ref) => (
    <DialogPrimitive.Title
      ref={ref}
      className={cn(
        'text-2xl font-semibold leading-none tracking-tight font-heading',
        className
      )}
      {...props}
    />
  ))
)
DialogTitle.displayName = DialogPrimitive.Title.displayName

// DialogDescription
const DialogDescription = React.memo(
  React.forwardRef<
    React.ElementRef<typeof DialogPrimitive.Description>,
    React.ComponentPropsWithoutRef<typeof DialogPrimitive.Description>
  >(({ className, ...props }, ref) => (
    <DialogPrimitive.Description
      ref={ref}
      className={cn('text-sm text-muted-foreground', className)}
      {...props}
    />
  ))
)
DialogDescription.displayName = DialogPrimitive.Description.displayName

// DialogBody
const DialogBody = React.memo<React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }) => (
    <div className={cn('flex-1 overflow-y-auto py-2', className)} {...props} />
  )
)
DialogBody.displayName = 'DialogBody'

export {
  Dialog,
  DialogPortal,
  DialogOverlay,
  DialogClose,
  DialogTrigger,
  DialogContent,
  DialogHeader,
  DialogFooter,
  DialogTitle,
  DialogDescription,
  DialogBody,
}
