import * as React from 'react'
import { ChevronDown, CheckCircle2 } from 'lucide-react'
import { Button } from '../Button'
import { Popover, PopoverContent, PopoverTrigger } from '../Popover'
import { ScrollArea } from '../ScrollArea'
import { Avatar, AvatarFallback } from '../Avatar'
import { Separator } from '../Separator'
import { Loader } from '../Loader'

export interface Company {
  id: string
  name: string
  cnpj?: string
}

export interface NavbarCompanyProfileProps {
  /** Lista de empresas vinculadas */
  companies: Company[]
  /** ID da empresa ativa */
  activeCompanyId?: string
  /** Callback quando uma empresa é selecionada */
  onCompanySelect?: (companyId: string) => void
  /** Se está carregando as empresas */
  isLoading?: boolean
  /** Função para formatar CNPJ (opcional) */
  formatCnpj?: (cnpj: string) => string
}

function getInitials(name: string): string {
  return name.slice(0, 2).toUpperCase()
}

function defaultFormatCnpj(cnpj: string): string {
  // Format: 00.000.000/0000-00
  return cnpj
    .replace(/\D/g, '')
    .replace(/^(\d{2})(\d)/, '$1.$2')
    .replace(/^(\d{2})\.(\d{3})(\d)/, '$1.$2.$3')
    .replace(/\.(\d{3})(\d)/, '.$1/$2')
    .replace(/(\d{4})(\d)/, '$1-$2')
    .slice(0, 18)
}

export function NavbarCompanyProfile({
  companies,
  activeCompanyId,
  onCompanySelect,
  isLoading = false,
  formatCnpj = defaultFormatCnpj,
}: NavbarCompanyProfileProps) {
  const currentCompany = companies.find(
    (company) => company.id === activeCompanyId
  )

  if (!currentCompany) {
    return isLoading ? <Loader variant="dots" /> : null
  }

  const handleCompanyClick = (companyId: string) => {
    if (onCompanySelect) {
      onCompanySelect(companyId)
    }
  }

  return (
    <div className="relative">
      <div className="flex items-center space-x-3 bg-primary/5 text-primary px-2 py-1 rounded-md">
        <Avatar className="h-10 w-10 bg-primary/20">
          <AvatarFallback className="font-semibold">
            {getInitials(currentCompany.name)}
          </AvatarFallback>
        </Avatar>
        <div className="hidden sm:flex sm:flex-col sm:flex-grow">
          <h3 className="font-semibold text-sm">{currentCompany.name}</h3>
          {currentCompany.cnpj && (
            <p className="text-xs text-primary/70">
              {formatCnpj(currentCompany.cnpj)}
            </p>
          )}
        </div>
        <Popover>
          <PopoverTrigger asChild>
            <Button
              variant="ghost"
              size="sm"
              className="h-8 px-2 text-primary hover:bg-primary/20"
            >
              <span className="sr-only">Abrir menu de empresas</span>
              <ChevronDown className="h-4 w-4" />
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-80 p-0" align="end">
            <div className="bg-primary/5 p-4 rounded-t-lg">
              <h4 className="font-semibold text-sm mb-1">
                Empresas Vinculadas
              </h4>
              <p className="text-xs text-muted-foreground">
                Selecione para mudar de empresa
              </p>
            </div>
            <ScrollArea className="h-64">
              <div className="p-4">
                {isLoading && (
                  <div className="flex justify-center py-4">
                    <Loader variant="spinner" />
                  </div>
                )}
                {!isLoading && companies.length === 0 && (
                  <p className="text-center text-muted-foreground">
                    Nenhuma empresa encontrada.
                  </p>
                )}
                {companies.map((company, index) => (
                  <React.Fragment key={company.id}>
                    <Button
                      variant="ghost"
                      className="w-full justify-start text-sm mb-1 hover:bg-primary/10"
                      onClick={() => handleCompanyClick(company.id)}
                    >
                      <div className="flex items-center w-full">
                        <Avatar className="h-8 w-8 mr-3">
                          <AvatarFallback className="bg-primary/20 text-primary text-xs">
                            {getInitials(company.name)}
                          </AvatarFallback>
                        </Avatar>
                        <div className="flex-grow text-left">
                          <div className="font-medium">{company.name}</div>
                          {company.cnpj && (
                            <div className="text-xs text-muted-foreground">
                              {formatCnpj(company.cnpj)}
                            </div>
                          )}
                        </div>
                        {company.id === activeCompanyId && (
                          <CheckCircle2 className="h-4 w-4 text-primary ml-2" />
                        )}
                      </div>
                    </Button>
                    {index < companies.length - 1 && (
                      <Separator className="my-2" />
                    )}
                  </React.Fragment>
                ))}
              </div>
            </ScrollArea>
          </PopoverContent>
        </Popover>
      </div>
    </div>
  )
}

NavbarCompanyProfile.displayName = 'NavbarCompanyProfile'
