import * as React from 'react'
import { Toaster as Sonner, toast as sonnerToast } from 'sonner'
import { AlertTriangle, CheckCircle2, Info, X, XCircle } from 'lucide-react'
import { cn } from '../../utils/cn'

export type ToasterProps = React.ComponentProps<typeof Sonner>

const toastVariants = {
  default: {
    bg: 'bg-card',
    border: 'border-border',
    barColor: 'bg-muted-foreground',
    icon: <Info className="h-5 w-5 text-muted-foreground" />,
    textColor: 'text-foreground',
  },
  success: {
    bg: 'bg-card',
    border: 'border-green-300 dark:border-green-700',
    barColor: 'bg-green-500',
    icon: <CheckCircle2 className="h-5 w-5 text-green-600 dark:text-green-500" />,
    textColor: 'text-foreground',
  },
  error: {
    bg: 'bg-card',
    border: 'border-red-300 dark:border-red-700',
    barColor: 'bg-red-500',
    icon: <XCircle className="h-5 w-5 text-red-600 dark:text-red-500" />,
    textColor: 'text-foreground',
  },
  warning: {
    bg: 'bg-card',
    border: 'border-yellow-400 dark:border-yellow-700',
    barColor: 'bg-yellow-500',
    icon: <AlertTriangle className="h-5 w-5 text-yellow-600 dark:text-yellow-500" />,
    textColor: 'text-foreground',
  },
  info: {
    bg: 'bg-card',
    border: 'border-blue-300 dark:border-blue-700',
    barColor: 'bg-blue-500',
    icon: <Info className="h-5 w-5 text-blue-600 dark:text-blue-500" />,
    textColor: 'text-foreground',
  },
}

export const Toaster = ({ ...props }: ToasterProps) => {
  return (
    <Sonner
      position="top-right"
      expand={false}
      closeButton={false}
      toastOptions={{
        unstyled: true,
        classNames: {
          toast: 'w-full',
        },
      }}
      {...props}
    />
  )
}

interface ToastProps {
  title: string
  description?: string
  variant?: keyof typeof toastVariants
  action?: {
    label: string
    onClick: () => void
  }
  onClose?: () => void
}

const CustomToast = React.memo<ToastProps>(
  ({ title, description, variant = 'default', action, onClose }) => {
    const variantStyles = toastVariants[variant]

    return (
      <div
        className={cn(
          'flex items-start gap-3 p-4 pr-3 rounded-lg shadow-lg border min-w-[350px] max-w-[450px] relative overflow-hidden',
          variantStyles.bg,
          variantStyles.border
        )}
      >
        {/* Barra lateral colorida */}
        <div
          className={cn(
            'absolute left-0 top-0 bottom-0 w-1.5',
            variantStyles.barColor
          )}
        />

        {/* Ícone */}
        <div className="flex-shrink-0 ml-2">{variantStyles.icon}</div>

        {/* Conteúdo */}
        <div className="flex-1 min-w-0">
          <p className={cn('text-sm font-medium', variantStyles.textColor)}>
            {title}
          </p>
          {description && (
            <p className="text-sm text-muted-foreground mt-0.5">{description}</p>
          )}
        </div>

        {/* Ações */}
        <div className="flex items-center gap-1 flex-shrink-0">
          {action && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                action.onClick()
              }}
              className={cn(
                'text-sm font-medium px-2 py-1 rounded hover:bg-accent transition-colors',
                variant === 'error' || variant === 'warning'
                  ? 'text-red-700 dark:text-red-400'
                  : variant === 'success'
                    ? 'text-green-700 dark:text-green-400'
                    : variant === 'info'
                      ? 'text-blue-700 dark:text-blue-400'
                      : 'text-foreground'
              )}
            >
              {action.label}
            </button>
          )}
          <button
            onClick={(e) => {
              e.stopPropagation()
              onClose?.()
            }}
            className="p-1 rounded hover:bg-accent transition-colors"
          >
            <X className="h-4 w-4 text-muted-foreground" />
          </button>
        </div>
      </div>
    )
  }
)

CustomToast.displayName = 'CustomToast'

// Helper functions para criar toasts
const createToast = (
  message: string | ToastProps,
  variant: keyof typeof toastVariants = 'default'
) => {
  const props: ToastProps =
    typeof message === 'string' ? { title: message, variant } : message

  return sonnerToast.custom(
    (t) => <CustomToast {...props} onClose={() => sonnerToast.dismiss(t)} />,
    {
      duration: props.action ? 10000 : 4000,
    }
  )
}

export const toast = Object.assign(
  (message: string) => createToast(message, 'default'),
  {
    success: (message: string | ToastProps) =>
      createToast(
        typeof message === 'string' ? { title: message } : message,
        'success'
      ),
    error: (message: string | ToastProps) =>
      createToast(
        typeof message === 'string' ? { title: message } : message,
        'error'
      ),
    warning: (message: string | ToastProps) =>
      createToast(
        typeof message === 'string' ? { title: message } : message,
        'warning'
      ),
    info: (message: string | ToastProps) =>
      createToast(
        typeof message === 'string' ? { title: message } : message,
        'info'
      ),
    custom: (component: Parameters<typeof sonnerToast.custom>[0], options?: Parameters<typeof sonnerToast.custom>[1]) =>
      sonnerToast.custom(component, options),
    dismiss: (id?: string | number) => sonnerToast.dismiss(id),
    promise: <T,>(
      promise: Promise<T> | (() => Promise<T>),
      options: {
        loading: string
        success: string | ((data: T) => string)
        error: string | ((error: any) => string)
      }
    ) => sonnerToast.promise(promise, options),
  }
)
